async def create_notification(
    title: str,
    message: str,
    notification_type: str = "info",
    link: Optional[str] = None,
    target_roles: Optional[List[str]] = None,
    target_user_ids: Optional[List[str]] = None,
    priority: str = "normal",
    created_by: Optional[str] = None,
    created_by_name: Optional[str] = None
):
    """Create a notification for users"""
    now = datetime.now(timezone.utc).isoformat()
    notification_id = str(uuid.uuid4())
    
    notification_doc = {
        "id": notification_id,
        "title": title,
        "message": message,
        "type": notification_type,
        "link": link,
        "target_roles": target_roles,  # None means all
        "target_user_ids": target_user_ids,  # Specific users
        "priority": priority,
        "read_by": [],  # List of user IDs who have read this
        "created_by": created_by,
        "created_by_name": created_by_name,
        "created_at": now
    }
    
    await db.notifications.insert_one(notification_doc)
    return notification_id

def calculate_sla_due(support_type: str, created_at: datetime) -> datetime:
    """Calculate SLA due date based on support type"""
    if support_type == "hardware":
        hours = SLA_CONFIG["hardware"]["total"]
    else:
        hours = SLA_CONFIG["phone"]["resolution"]
    return created_at + timedelta(hours=hours)

def is_sla_breached(sla_due: datetime, status: str) -> bool:
    """Check if ticket has breached SLA"""
    if status in ["closed", "closed_by_agent", "resolved_on_call", "delivered"]:
        return False
    return datetime.now(timezone.utc) > sla_due

def hash_password(password: str) -> str:
    return bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

def verify_password(plain_password: str, hashed_password: str) -> bool:
    # PHP bcrypt uses $2y$ prefix, Python bcrypt uses $2b$
    # Convert $2y$ to $2b$ for compatibility
    if hashed_password.startswith('$2y$'):
        hashed_password = '$2b$' + hashed_password[4:]
    return bcrypt.checkpw(plain_password.encode('utf-8'), hashed_password.encode('utf-8'))

def create_token(user_id: str, role: str) -> str:
    payload = {
        "user_id": user_id,
        "role": role,
        "exp": datetime.now(timezone.utc) + timedelta(hours=JWT_EXPIRATION_HOURS)
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)

async def get_current_user(credentials: HTTPAuthorizationCredentials = Depends(security)):
    try:
        payload = jwt.decode(credentials.credentials, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        user = await db.users.find_one({"id": payload["user_id"]}, {"_id": 0})
        if not user:
            raise HTTPException(status_code=401, detail="User not found")
        return user
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail="Token expired")
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail="Invalid token")

# Optional version that returns None instead of raising exception (for endpoints with fallback auth)
security_optional = HTTPBearer(auto_error=False)

async def get_current_user_optional(credentials: HTTPAuthorizationCredentials = Depends(security_optional)):
    """Get current user if token provided, otherwise return None"""
    if not credentials:
        return None
    try:
        payload = jwt.decode(credentials.credentials, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        user = await db.users.find_one({"id": payload["user_id"]}, {"_id": 0})
        return user
    except:
        return None

def require_roles(allowed_roles: List[str]):
    async def role_checker(user: dict = Depends(get_current_user)):
        if user["role"] not in allowed_roles:
            raise HTTPException(status_code=403, detail="Insufficient permissions")
        return user
    return role_checker

async def add_ticket_history(ticket_id: str, action: str, by_user: dict, details: dict = None):
    """Add entry to ticket history"""
    history_entry = {
        "action": action,
        "by": f"{by_user['first_name']} {by_user['last_name']}",
        "by_id": by_user["id"],
        "by_role": by_user["role"],
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "details": details or {}
    }
    await db.tickets.update_one(
        {"id": ticket_id},
        {"$push": {"history": history_entry}}
    )

async def log_activity(action: str, entity_type: str, entity_id: str, user: dict, details: dict = None):
    """Log activity to audit_logs collection"""
    now = datetime.now(timezone.utc)
    log_entry = {
        "id": str(uuid.uuid4()),
        "action": action,
        "entity_type": entity_type,
        "entity_id": entity_id,
        "user_id": user["id"],
        "user_name": f"{user['first_name']} {user['last_name']}",
        "user_role": user["role"],
        "details": details or {},
        "created_at": now.isoformat()
    }
    await db.audit_logs.insert_one(log_entry)


# ==================== DUPLICATE VALIDATION UTILITIES ====================

async def check_tracking_id_duplicate(tracking_id: str, exclude_id: str = None) -> dict:
    """
    Check if tracking ID already exists across all relevant collections.
    Returns: {"exists": bool, "source": str, "details": dict} 
    """
    if not tracking_id or tracking_id.strip() == "":
        return {"exists": False}
    
    tracking_id = tracking_id.strip()
    
    # Check pending_fulfillment
    query = {"tracking_id": tracking_id}
    if exclude_id:
        query["id"] = {"$ne": exclude_id}
    
    pf = await db.pending_fulfillment.find_one(query, {"_id": 0, "id": 1, "order_id": 1, "status": 1})
    if pf:
        return {
            "exists": True, 
            "source": "pending_fulfillment",
            "details": {"order_id": pf.get("order_id"), "status": pf.get("status")},
            "message": f"Tracking ID already used in Pending Fulfillment (Order: {pf.get('order_id')})"
        }
    
    # Check dispatches
    dispatch = await db.dispatches.find_one(
        {"tracking_id": tracking_id, "status": {"$ne": "cancelled"}},
        {"_id": 0, "dispatch_number": 1, "order_id": 1, "status": 1}
    )
    if dispatch:
        return {
            "exists": True,
            "source": "dispatches", 
            "details": {"dispatch_number": dispatch.get("dispatch_number"), "status": dispatch.get("status")},
            "message": f"Tracking ID already used in Dispatch #{dispatch.get('dispatch_number')}"
        }
    
    # Check tickets (return tracking)
    ticket = await db.tickets.find_one(
        {"$or": [{"pickup_tracking": tracking_id}, {"return_tracking": tracking_id}]},
        {"_id": 0, "ticket_number": 1, "status": 1}
    )
    if ticket:
        return {
            "exists": True,
            "source": "tickets",
            "details": {"ticket_number": ticket.get("ticket_number")},
            "message": f"Tracking ID already used in Ticket #{ticket.get('ticket_number')}"
        }
    
    return {"exists": False}


async def check_order_id_duplicate(order_id: str, exclude_id: str = None, source_type: str = None) -> dict:
    """
    Check if Order ID already exists across all relevant collections.
    source_type: 'pending_fulfillment', 'dispatch', 'amazon', 'sales' - to exclude self
    Returns: {"exists": bool, "source": str, "details": dict}
    """
    if not order_id or order_id.strip() == "":
        return {"exists": False}
    
    order_id = order_id.strip()
    
    # Check pending_fulfillment
    if source_type != "pending_fulfillment":
        pf = await db.pending_fulfillment.find_one(
            {"$or": [{"order_id": order_id}, {"amazon_order_id": order_id}]},
            {"_id": 0, "id": 1, "status": 1}
        )
        if pf and pf.get("id") != exclude_id:
            return {
                "exists": True,
                "source": "pending_fulfillment",
                "details": {"status": pf.get("status")},
                "message": "Order ID already exists in Pending Fulfillment"
            }
    
    # Check dispatches
    if source_type != "dispatch":
        dispatch = await db.dispatches.find_one(
            {"$or": [{"order_id": order_id}, {"marketplace_order_id": order_id}], "status": {"$ne": "cancelled"}},
            {"_id": 0, "dispatch_number": 1, "status": 1}
        )
        if dispatch:
            return {
                "exists": True,
                "source": "dispatches",
                "details": {"dispatch_number": dispatch.get("dispatch_number")},
                "message": f"Order ID already exists in Dispatch #{dispatch.get('dispatch_number')}"
            }
    
    # Check amazon_orders (if not already tracked)
    if source_type not in ["amazon", "pending_fulfillment"]:
        amazon = await db.amazon_orders.find_one(
            {"amazon_order_id": order_id, "crm_status": {"$in": ["dispatched", "in_pending_fulfillment"]}},
            {"_id": 0, "crm_status": 1}
        )
        if amazon:
            return {
                "exists": True,
                "source": "amazon_orders",
                "details": {"crm_status": amazon.get("crm_status")},
                "message": f"Amazon Order already processed (Status: {amazon.get('crm_status')})"
            }
    
    # Check sales_orders
    if source_type != "sales":
        sales = await db.sales_orders.find_one(
            {"$or": [{"order_number": order_id}, {"external_invoice_number": order_id}]},
            {"_id": 0, "order_number": 1, "status": 1}
        )
        if sales and sales.get("id") != exclude_id:
            return {
                "exists": True,
                "source": "sales_orders",
                "details": {"order_number": sales.get("order_number")},
                "message": f"Order ID already exists in Sales Order #{sales.get('order_number')}"
            }
    
    return {"exists": False}


async def check_invoice_number_duplicate(invoice_number: str, exclude_id: str = None) -> dict:
    """
    Check if Invoice Number already exists across all relevant collections.
    Returns: {"exists": bool, "source": str, "details": dict}
    """
    if not invoice_number or invoice_number.strip() == "":
        return {"exists": False}
    
    invoice_number = invoice_number.strip()
    
    # Check dispatches
    dispatch = await db.dispatches.find_one(
        {"invoice_number": invoice_number, "status": {"$ne": "cancelled"}},
        {"_id": 0, "id": 1, "dispatch_number": 1, "status": 1}
    )
    if dispatch and dispatch.get("id") != exclude_id:
        return {
            "exists": True,
            "source": "dispatches",
            "details": {"dispatch_number": dispatch.get("dispatch_number")},
            "message": f"Invoice Number already used in Dispatch #{dispatch.get('dispatch_number')}"
        }
    
    # Check sales_invoices
    sales_inv = await db.sales_invoices.find_one(
        {"invoice_number": invoice_number},
        {"_id": 0, "id": 1, "invoice_number": 1}
    )
    if sales_inv and sales_inv.get("id") != exclude_id:
        return {
            "exists": True,
            "source": "sales_invoices",
            "details": {},
            "message": "Invoice Number already exists in Sales Invoices"
        }
    
    # Check service_invoices
    service_inv = await db.service_invoices.find_one(
        {"invoice_number": invoice_number},
        {"_id": 0, "id": 1}
    )
    if service_inv and service_inv.get("id") != exclude_id:
        return {
            "exists": True,
            "source": "service_invoices", 
            "details": {},
            "message": "Invoice Number already exists in Service Invoices"
        }
    
    # Check pending_fulfillment (external invoice numbers)
    pf = await db.pending_fulfillment.find_one(
        {"$or": [{"invoice_number": invoice_number}, {"external_invoice_number": invoice_number}]},
        {"_id": 0, "id": 1, "order_id": 1}
    )
    if pf and pf.get("id") != exclude_id:
        return {
            "exists": True,
            "source": "pending_fulfillment",
            "details": {"order_id": pf.get("order_id")},
            "message": f"Invoice Number already used in Pending Fulfillment (Order: {pf.get('order_id')})"
        }
    
    return {"exists": False}


async def validate_no_duplicates(
    tracking_id: str = None, 
    order_id: str = None, 
    invoice_number: str = None,
    exclude_id: str = None,
    source_type: str = None
) -> list:
    """
    Validate multiple fields at once. Returns list of error messages.
    """
    errors = []
    
    if tracking_id:
        result = await check_tracking_id_duplicate(tracking_id, exclude_id)
        if result["exists"]:
            errors.append(result["message"])
    
    if order_id:
        result = await check_order_id_duplicate(order_id, exclude_id, source_type)
        if result["exists"]:
            errors.append(result["message"])
    
    if invoice_number:
        result = await check_invoice_number_duplicate(invoice_number, exclude_id)
        if result["exists"]:
            errors.append(result["message"])
    
    return errors


async def get_stock_info_for_pending_fulfillment(master_sku_id: str, pf_entry: dict) -> dict:
    """Get stock info for a pending fulfillment entry"""
    if not master_sku_id:
        return {
            "product_name": pf_entry.get("master_sku_name"),
            "sku_code": pf_entry.get("sku_code"),
            "current_stock": 0,
            "in_stock": False,
            "is_manufactured": False
        }
    
    master_sku = await db.master_skus.find_one({"id": master_sku_id}, {"_id": 0})
    if not master_sku:
        return {
            "product_name": pf_entry.get("master_sku_name"),
            "sku_code": pf_entry.get("sku_code"),
            "current_stock": 0,
            "in_stock": False,
            "is_manufactured": False
        }
    
    is_manufactured = master_sku.get("is_manufactured", False) or master_sku.get("product_type") == "manufactured"
    firm_id = pf_entry.get("firm_id")
    
    if is_manufactured:
        # Check finished_good_serials for manufactured items
        # Bug 4 Fix: Don't filter by firm_id if not set - check all stock
        query = {"master_sku_id": master_sku_id, "status": "in_stock"}
        if firm_id:
            query["firm_id"] = firm_id
        stock_count = await db.finished_good_serials.count_documents(query)
        current_stock = stock_count
    else:
        # Check inventory_ledger for traded items
        # Bug 4 Fix: Use master_sku as item_type and handle missing firm_id
        if firm_id:
            current_stock = await get_current_stock("master_sku", master_sku_id, firm_id)
        else:
            # No firm_id - sum across all firms
            pipeline = [
                {"$match": {"item_id": master_sku_id, "item_type": "master_sku"}},
                {"$sort": {"created_at": -1}},
                {"$group": {"_id": "$firm_id", "latest_balance": {"$first": "$running_balance"}}},
                {"$group": {"_id": None, "total": {"$sum": "$latest_balance"}}}
            ]
            result = await db.inventory_ledger.aggregate(pipeline).to_list(1)
            current_stock = result[0]["total"] if result else 0
    
    return {
        "product_name": master_sku.get("name"),
        "sku_code": master_sku.get("sku_code"),
        "current_stock": current_stock,
        "in_stock": current_stock > 0,
        "is_manufactured": is_manufactured
    }


# ==================== AUTH ENDPOINTS ====================

@api_router.post("/auth/register", response_model=TokenResponse)
async def register(user_data: UserCreate):
    existing = await db.users.find_one({"email": user_data.email.lower()})
    if existing:
        raise HTTPException(status_code=400, detail="Email already registered")
    
    # Only allow customer registration via public endpoint
    if user_data.role != "customer":
        raise HTTPException(status_code=400, detail="Invalid registration")
    
    user_id = str(uuid.uuid4())
    now = datetime.now(timezone.utc).isoformat()
    
    user_doc = {
        "id": user_id,
        "email": user_data.email.lower(),
        "first_name": user_data.first_name,
        "last_name": user_data.last_name,
        "phone": user_data.phone,
        "role": "customer",
        "password_hash": hash_password(user_data.password),
        "address": user_data.address,
        "city": user_data.city,
        "state": user_data.state,
        "pincode": user_data.pincode,
        "created_at": now,
        "updated_at": now
    }
    
    await db.users.insert_one(user_doc)
    token = create_token(user_id, "customer")
    
    return TokenResponse(
        access_token=token,
        user=UserResponse(**{k: v for k, v in user_doc.items() if k != "password_hash" and k != "_id"})
    )

@api_router.post("/auth/login", response_model=TokenResponse)
async def login(credentials: UserLogin):
    # Support login by email OR phone number
    email_or_phone = credentials.email.lower().strip()
    
    # Check if it looks like a phone number (all digits, 10+ chars)
    is_phone = email_or_phone.replace('+', '').replace(' ', '').isdigit() and len(email_or_phone.replace('+', '').replace(' ', '')) >= 10
    
    user = None
    
    if is_phone:
        # Clean phone number
        phone = email_or_phone.replace('+', '').replace(' ', '').replace('-', '')
        if phone.startswith('91') and len(phone) > 10:
            phone = phone[2:]  # Remove country code
        
        # Find user by phone - first check users table
        user = await db.users.find_one({"phone": phone})
        
        # If not found in users, check dealers table and get linked user
        if not user:
            dealer = await db.dealers.find_one({"phone": phone})
            if dealer:
                user_id = dealer.get("user_id")
                if user_id:
                    # Try as ObjectId first
                    if ObjectId.is_valid(user_id):
                        user = await db.users.find_one({"_id": ObjectId(user_id)})
                    if not user:
                        user = await db.users.find_one({"id": user_id})
    else:
        # Email login
        user = await db.users.find_one({"email": email_or_phone})
    
    if not user or not verify_password(credentials.password, user["password_hash"]):
        raise HTTPException(status_code=401, detail="Invalid credentials")
    
    # Ensure user has an id field
    if "_id" in user and "id" not in user:
        user["id"] = str(user["_id"])
    
    # Convert datetime to string if needed
    if "created_at" in user and not isinstance(user["created_at"], str):
        user["created_at"] = user["created_at"].isoformat() if user["created_at"] else None
    
    # Remove _id for response
    user_response = {k: v for k, v in user.items() if k not in ["_id", "password_hash"]}
    
    token = create_token(user["id"], user["role"])
    
    return TokenResponse(
        access_token=token,
        user=UserResponse(**user_response)
    )

@api_router.get("/auth/me", response_model=UserResponse)
async def get_me(user: dict = Depends(get_current_user)):
    # Convert datetime fields to string if needed
    user_data = {k: v for k, v in user.items() if k != "password_hash"}
    if "created_at" in user_data and isinstance(user_data["created_at"], datetime):
        user_data["created_at"] = user_data["created_at"].isoformat()
    return UserResponse(**user_data)

@api_router.patch("/auth/me", response_model=UserResponse)
async def update_me(update_data: UserUpdate, user: dict = Depends(get_current_user)):
    update_dict = {k: v for k, v in update_data.dict().items() if v is not None}
    if update_dict:
        update_dict["updated_at"] = datetime.now(timezone.utc).isoformat()
        await db.users.update_one({"id": user["id"]}, {"$set": update_dict})
    
    updated_user = await db.users.find_one({"id": user["id"]}, {"_id": 0})
    # Convert datetime fields to string if needed
    user_data = {k: v for k, v in updated_user.items() if k != "password_hash"}
    if "created_at" in user_data and isinstance(user_data["created_at"], datetime):
        user_data["created_at"] = user_data["created_at"].isoformat()
    return UserResponse(**user_data)

# ==================== OTP AUTHENTICATION ====================

# Fast2SMS Configuration
FAST2SMS_API_KEY = os.environ.get("FAST2SMS_API_KEY", "")
FAST2SMS_SENDER_ID = os.environ.get("FAST2SMS_SENDER_ID", "MUSGRD")
FAST2SMS_TEMPLATE_ID = os.environ.get("FAST2SMS_TEMPLATE_ID", "203700")
OTP_EXPIRY_MINUTES = 5

# In-memory OTP storage (use Redis in production)
otp_store = {}

def generate_otp() -> str:
    """Generate a 6-digit OTP"""
    return str(random.randint(100000, 999999))

async def send_otp_via_fast2sms(phone: str, otp: str) -> bool:
    """Send OTP via Fast2SMS DLT route"""
    if not FAST2SMS_API_KEY:
        logger.error("Fast2SMS API key not configured")
        return False
    
    try:
        # Clean phone number (remove +91, spaces, etc.)
        clean_phone = phone.replace('+', '').replace(' ', '').replace('-', '')
        if clean_phone.startswith('91') and len(clean_phone) > 10:
            clean_phone = clean_phone[2:]
        
        # Fast2SMS DLT API
        url = "https://www.fast2sms.com/dev/bulkV2"
        params = {
            "authorization": FAST2SMS_API_KEY,
            "route": "dlt",
            "sender_id": FAST2SMS_SENDER_ID,
            "message": FAST2SMS_TEMPLATE_ID,
            "variables_values": otp,
            "flash": "0",
            "numbers": clean_phone
        }
        
        response = requests.get(url, params=params, timeout=30)
        result = response.json()
        
        if result.get("return") == True:
            logger.info(f"OTP sent successfully to {clean_phone[-4:].rjust(10, '*')}")
            return True
        else:
            logger.error(f"Fast2SMS error: {result}")
            return False
            
    except Exception as e:
        logger.error(f"Failed to send OTP: {str(e)}")
        return False

class OTPRequest(BaseModel):
    phone: str

class OTPVerify(BaseModel):
    phone: str
    otp: str

class ProfileUpdate(BaseModel):
    first_name: Optional[str] = None
    last_name: Optional[str] = None
    email: Optional[str] = None
    address: Optional[str] = None
    city: Optional[str] = None
    state: Optional[str] = None
    pincode: Optional[str] = None

@api_router.post("/auth/otp/send")
async def send_otp(request: OTPRequest):
    """Send OTP to phone number for login"""
    # Clean phone number
    phone = request.phone.replace('+', '').replace(' ', '').replace('-', '')
    if phone.startswith('91') and len(phone) > 10:
        phone = phone[2:]
    
    if len(phone) != 10 or not phone.isdigit():
        raise HTTPException(status_code=400, detail="Invalid phone number. Please enter 10-digit mobile number.")
    
    # Check if user exists (in users table or has a ticket)
    user = await db.users.find_one({"phone": phone})
    
    # If not found in users, check if they have any tickets
    if not user:
        ticket = await db.tickets.find_one({"customer_phone": phone})
        if ticket:
            # Create a user account for this customer
            user_id = str(uuid.uuid4())
            now = datetime.now(timezone.utc).isoformat()
            user = {
                "id": user_id,
                "email": f"{phone}@temp.musclegrid.in",  # Temporary email
                "first_name": ticket.get("customer_name", "").split()[0] if ticket.get("customer_name") else "Customer",
                "last_name": " ".join(ticket.get("customer_name", "").split()[1:]) if ticket.get("customer_name") and len(ticket.get("customer_name", "").split()) > 1 else "",
                "phone": phone,
                "role": "customer",
                "password_hash": "",  # No password for OTP users
                "address": ticket.get("customer_address"),
                "city": ticket.get("customer_city"),
                "state": ticket.get("state"),
                "pincode": ticket.get("pincode"),
                "created_at": now,
                "updated_at": now,
                "otp_user": True,  # Flag for OTP-created users
                "profile_incomplete": True  # Flag to prompt profile completion
            }
            await db.users.insert_one(user)
            logger.info(f"Created user account for existing ticket customer: {phone}")
        else:
            raise HTTPException(
                status_code=404, 
                detail="No account found with this phone number. Please register first or contact support."
            )
    
    # Generate and store OTP
    otp = generate_otp()
    expiry = datetime.now(timezone.utc) + timedelta(minutes=OTP_EXPIRY_MINUTES)
    
    otp_store[phone] = {
        "otp": otp,
        "expiry": expiry,
        "attempts": 0
    }
    
    logger.info(f"OTP stored for phone ******{phone[-4:]}: {otp}")
    
    # Send OTP via Fast2SMS
    sent = await send_otp_via_fast2sms(phone, otp)
    
    if not sent:
        raise HTTPException(status_code=500, detail="Failed to send OTP. Please try again.")
    
    return {
        "message": "OTP sent successfully",
        "phone": f"******{phone[-4:]}",
        "expires_in": OTP_EXPIRY_MINUTES * 60
    }

@api_router.post("/auth/otp/verify", response_model=TokenResponse)
async def verify_otp(request: OTPVerify):
    """Verify OTP and login user"""
    # Clean phone number
    phone = request.phone.replace('+', '').replace(' ', '').replace('-', '')
    if phone.startswith('91') and len(phone) > 10:
        phone = phone[2:]
    
    # Clean OTP input
    otp_input = request.otp.strip()
    
    logger.info(f"OTP verification attempt for phone: ******{phone[-4:]}")
    
    # Check OTP store
    stored = otp_store.get(phone)
    
    if not stored:
        logger.warning(f"No OTP found in store for phone: ******{phone[-4:]}")
        raise HTTPException(status_code=400, detail="OTP expired or not requested. Please request a new OTP.")
    
    # Check expiry
    if datetime.now(timezone.utc) > stored["expiry"]:
        del otp_store[phone]
        logger.warning(f"OTP expired for phone: ******{phone[-4:]}")
        raise HTTPException(status_code=400, detail="OTP has expired. Please request a new OTP.")
    
    # Check attempts
    if stored["attempts"] >= 3:
        del otp_store[phone]
        logger.warning(f"Too many attempts for phone: ******{phone[-4:]}")
        raise HTTPException(status_code=400, detail="Too many incorrect attempts. Please request a new OTP.")
    
    # Verify OTP
    logger.info(f"Comparing OTP: stored={stored['otp']}, received={otp_input}")
    if str(stored["otp"]).strip() != str(otp_input).strip():
        stored["attempts"] += 1
        remaining = 3 - stored["attempts"]
        logger.warning(f"Invalid OTP for phone: ******{phone[-4:]}, attempts: {stored['attempts']}")
        raise HTTPException(status_code=400, detail=f"Invalid OTP. {remaining} attempts remaining.")
    
    # OTP verified - clean up and login
    logger.info(f"OTP verified successfully for phone: ******{phone[-4:]}")
    del otp_store[phone]
    
    # Get user
    user = await db.users.find_one({"phone": phone})
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    
    # Check if profile is incomplete
    profile_incomplete = False
    missing_fields = []
    
    # Check mandatory fields
    if not user.get("email") or user.get("email", "").endswith("@temp.musclegrid.in"):
        missing_fields.append("email")
        profile_incomplete = True
    if not user.get("first_name") or user.get("first_name") == "Customer":
        missing_fields.append("first_name")
        profile_incomplete = True
    if not user.get("address"):
        missing_fields.append("address")
        profile_incomplete = True
    if not user.get("city"):
        missing_fields.append("city")
        profile_incomplete = True
    if not user.get("pincode"):
        missing_fields.append("pincode")
        profile_incomplete = True
    
    # Update profile_incomplete flag in database
    if profile_incomplete != user.get("profile_incomplete", False):
        await db.users.update_one(
            {"id": user["id"]},
            {"$set": {"profile_incomplete": profile_incomplete}}
        )
    
    # Create token
    token = create_token(user["id"], user["role"])
    
    # Prepare user response (exclude sensitive fields)
    user_data = {k: v for k, v in user.items() if k not in ["password_hash", "_id"]}
    user_data["profile_incomplete"] = profile_incomplete
    user_data["missing_fields"] = missing_fields
    
    return TokenResponse(
        access_token=token,
        user=UserResponse(**{k: v for k, v in user_data.items() if k in UserResponse.__fields__})
    )

@api_router.post("/auth/otp/resend")
async def resend_otp(request: OTPRequest):
    """Resend OTP to phone number"""
    # Clean phone number
    phone = request.phone.replace('+', '').replace(' ', '').replace('-', '')
    if phone.startswith('91') and len(phone) > 10:
        phone = phone[2:]
    
    # Check if user exists
    user = await db.users.find_one({"phone": phone})
    if not user:
        raise HTTPException(status_code=404, detail="No account found with this phone number.")
    
    # Check rate limiting (only allow resend after 30 seconds)
    existing = otp_store.get(phone)
    if existing:
        time_since_sent = datetime.now(timezone.utc) - (existing["expiry"] - timedelta(minutes=OTP_EXPIRY_MINUTES))
        if time_since_sent.total_seconds() < 30:
            wait_time = int(30 - time_since_sent.total_seconds())
            raise HTTPException(status_code=429, detail=f"Please wait {wait_time} seconds before requesting a new OTP.")
    
    # Generate and store new OTP
    otp = generate_otp()
    expiry = datetime.now(timezone.utc) + timedelta(minutes=OTP_EXPIRY_MINUTES)
    
    otp_store[phone] = {
        "otp": otp,
        "expiry": expiry,
        "attempts": 0
    }
    
    # Send OTP
    sent = await send_otp_via_fast2sms(phone, otp)
    
    if not sent:
        raise HTTPException(status_code=500, detail="Failed to send OTP. Please try again.")
    
    return {
        "message": "OTP resent successfully",
        "phone": f"******{phone[-4:]}",
        "expires_in": OTP_EXPIRY_MINUTES * 60
    }

@api_router.post("/auth/complete-profile")
async def complete_profile(
    profile: ProfileUpdate,
    user: dict = Depends(get_current_user)
):
    """Complete user profile after OTP login"""
    update_data = {}
    
    if profile.first_name:
        update_data["first_name"] = profile.first_name
    if profile.last_name:
        update_data["last_name"] = profile.last_name
    if profile.email and not profile.email.endswith("@temp.musclegrid.in"):
        # Check if email already exists
        existing = await db.users.find_one({"email": profile.email.lower(), "id": {"$ne": user["id"]}})
        if existing:
            raise HTTPException(status_code=400, detail="This email is already registered to another account.")
        update_data["email"] = profile.email.lower()
    if profile.address:
        update_data["address"] = profile.address
    if profile.city:
        update_data["city"] = profile.city
    if profile.state:
        update_data["state"] = profile.state
    if profile.pincode:
        update_data["pincode"] = profile.pincode
    
    if update_data:
        update_data["updated_at"] = datetime.now(timezone.utc).isoformat()
        update_data["profile_incomplete"] = False
        
        await db.users.update_one(
            {"id": user["id"]},
            {"$set": update_data}
        )
    
    # Return updated user
    updated_user = await db.users.find_one({"id": user["id"]}, {"_id": 0, "password_hash": 0})
    
    return {
        "message": "Profile updated successfully",
        "user": updated_user
    }


