class DispatchUpdate(BaseModel):
    customer_name: Optional[str] = None
    phone: Optional[str] = None
    address: Optional[str] = None
    city: Optional[str] = None
    state: Optional[str] = None
    pincode: Optional[str] = None
    reason: Optional[str] = None
    order_id: Optional[str] = None
    payment_reference: Optional[str] = None
    status: Optional[str] = None
    courier: Optional[str] = None
    tracking_id: Optional[str] = None
    master_sku_id: Optional[str] = None
    selling_price: Optional[float] = None
    invoice_value: Optional[float] = None
    taxable_value: Optional[float] = None

@api_router.patch("/admin/dispatches/{dispatch_id}")
async def admin_update_dispatch(
    dispatch_id: str,
    update_data: DispatchUpdate,
    user: dict = Depends(require_roles(["admin"]))
):
    """Admin updates dispatch/order information"""
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    if not dispatch:
        raise HTTPException(status_code=404, detail="Dispatch not found")
    
    update_dict = {"updated_at": datetime.now(timezone.utc).isoformat()}
    
    for field in ["customer_name", "phone", "address", "city", "state", "pincode",
                  "reason", "order_id", "payment_reference", "status", "courier", "tracking_id",
                  "master_sku_id", "selling_price", "invoice_value", "taxable_value"]:
        value = getattr(update_data, field, None)
        if value is not None:
            update_dict[field] = value
    
    await db.dispatches.update_one({"id": dispatch_id}, {"$set": update_dict})
    
    updated = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    return updated

@api_router.delete("/admin/dispatches/{dispatch_id}")
async def admin_delete_dispatch(
    dispatch_id: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """Admin deletes a dispatch/order"""
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    if not dispatch:
        raise HTTPException(status_code=404, detail="Dispatch not found")
    
    await db.dispatches.delete_one({"id": dispatch_id})
    return {"message": "Dispatch deleted successfully"}


async def ensure_customer_party(
    customer_name: str,
    phone: str,
    address: Optional[str] = None,
    city: Optional[str] = None,
    state: str = "Unknown",
    pincode: Optional[str] = None,
    gstin: Optional[str] = None
):
    """Ensure a customer party exists in the parties collection. Creates if not exists."""
    if not customer_name or not phone:
        return None
    
    # Normalize phone (last 10 digits)
    phone_normalized = phone[-10:] if phone else ""
    
    # Check if party already exists by phone
    existing = await db.parties.find_one({
        "$or": [
            {"phone": phone},
            {"phone": phone_normalized},
            {"phone": {"$regex": phone_normalized + "$"}}
        ]
    })
    
    if existing:
        # Update with any new info
        update_fields = {}
        if address and not existing.get("address"):
            update_fields["address"] = address
        if city and not existing.get("city"):
            update_fields["city"] = city
        if state and state != "Unknown" and existing.get("state") in [None, "", "Unknown"]:
            update_fields["state"] = state
        if pincode and not existing.get("pincode"):
            update_fields["pincode"] = pincode
        
        if update_fields:
            update_fields["updated_at"] = datetime.now(timezone.utc).isoformat()
            await db.parties.update_one({"_id": existing["_id"]}, {"$set": update_fields})
        
        return existing.get("id")
    
    # Create new customer party
    now = datetime.now(timezone.utc).isoformat()
    party_id = str(uuid.uuid4())
    
    party_doc = {
        "id": party_id,
        "name": customer_name,
        "party_types": ["customer"],
        "phone": phone,
        "address": address or "",
        "city": city or "",
        "state": state,
        "pincode": pincode or "",
        "gstin": gstin,
        "opening_balance": 0,
        "credit_limit": 0,
        "is_active": True,
        "created_at": now,
        "updated_at": now,
        "source": "auto_from_dispatch"
    }
    
    await db.parties.insert_one(party_doc)
    return party_id


async def create_sales_order_from_dispatch(dispatch_doc: dict, db):
    """
    Create a sales order entry when a dispatch is created or scanned out.
    Order types:
    - new_order, amazon_order -> Sales > Orders > New Orders
    - spare_dispatch (repair) -> Sales > Orders > Repairs
    - walkin -> Sales > Orders > Walk-in
    """
    now = datetime.now(timezone.utc).isoformat()
    
    # Determine order category based on dispatch type and order source
    dispatch_type = dispatch_doc.get("dispatch_type", "new_order")
    order_source = dispatch_doc.get("order_source", "direct")
    
    if dispatch_type == "spare_dispatch":
        order_category = "repair"
    elif order_source == "walkin":
        order_category = "walkin"
    else:
        order_category = "new_order"
    
    # Determine payment status - marketplace orders start as unpaid until reconciled
    if order_source in ["amazon", "flipkart"]:
        payment_status = "unpaid"
        payment_mode = "marketplace"
    else:
        payment_status = "pending"
        payment_mode = "direct"
    
    # Generate sales order number
    count = await db.sales_orders.count_documents({}) + 1
    order_number = f"SO-{datetime.now(timezone.utc).strftime('%Y%m%d')}-{count:04d}"
    
    # Get SKU details for amount calculation
    sku_code = dispatch_doc.get("sku")
    master_sku = await db.master_skus.find_one({"id": dispatch_doc.get("master_sku_id")}, {"_id": 0}) if dispatch_doc.get("master_sku_id") else None
    
    # Try to get amount from invoice or estimate
    unit_price = 0
    if master_sku:
        unit_price = master_sku.get("mrp", 0) or master_sku.get("selling_price", 0) or 0
    
    sales_order = {
        "id": str(uuid.uuid4()),
        "order_number": order_number,
        "dispatch_id": dispatch_doc.get("id"),
        "dispatch_number": dispatch_doc.get("dispatch_number"),
        "firm_id": dispatch_doc.get("firm_id"),
        "firm_name": dispatch_doc.get("firm_name"),
        "order_category": order_category,  # new_order, repair, walkin
        "order_source": order_source,  # amazon, flipkart, website, walkin, direct, other
        "marketplace_order_id": dispatch_doc.get("marketplace_order_id"),
        "order_id": dispatch_doc.get("order_id"),
        "customer_name": dispatch_doc.get("customer_name"),
        "phone": dispatch_doc.get("phone"),
        "address": dispatch_doc.get("address"),
        "city": dispatch_doc.get("city"),
        "state": dispatch_doc.get("state"),
        "pincode": dispatch_doc.get("pincode"),
        "sku": sku_code,
        "master_sku_id": dispatch_doc.get("master_sku_id"),
        "master_sku_name": dispatch_doc.get("master_sku_name"),
        "serial_number": dispatch_doc.get("serial_number"),
        "quantity": 1,
        "unit_price": unit_price,
        "total_amount": unit_price,
        "payment_status": payment_status,  # unpaid, pending, partial, paid
        "payment_mode": payment_mode,  # marketplace, direct, cod, prepaid
        "marketplace_payment_status": "pending" if order_source in ["amazon", "flipkart"] else None,
        "ecommerce_statement_id": None,  # Will be set when reconciled
        "tracking_id": dispatch_doc.get("tracking_id"),
        "courier": dispatch_doc.get("courier"),
        "dispatch_status": dispatch_doc.get("status"),
        "invoice_url": dispatch_doc.get("invoice_url"),
        "note": dispatch_doc.get("note"),
        "ticket_id": dispatch_doc.get("ticket_id"),
        "ticket_number": dispatch_doc.get("ticket_number"),
        "created_by": dispatch_doc.get("created_by"),
        "created_by_name": dispatch_doc.get("created_by_name"),
        "created_at": now,
        "updated_at": now,
        "dispatched_at": dispatch_doc.get("scanned_out_at"),
        "delivered_at": None
    }
    
    await db.sales_orders.insert_one(sales_order)
    sales_order.pop("_id", None)
    return sales_order


async def create_sales_invoice_from_dispatch(dispatch_doc: dict, db):
    """
    Auto-create a sales invoice when a dispatch is created.
    This ensures every dispatch has a corresponding GST-compliant invoice.
    Uses the dispatch's invoice_value/taxable_value if available (since dispatch already knows the price).
    """
    from datetime import datetime, timezone
    
    now = datetime.now(timezone.utc)
    
    # Check if invoice already exists for this dispatch
    existing_invoice = await db.sales_invoices.find_one({"dispatch_id": dispatch_doc.get("id")})
    if existing_invoice:
        return existing_invoice  # Already has invoice
    
    # Get firm details
    firm = await db.firms.find_one({"id": dispatch_doc.get("firm_id")}, {"_id": 0})
    if not firm:
        return None  # Can't create invoice without firm
    
    # Get or create party from dispatch customer info
    customer_name = dispatch_doc.get("customer_name", "")
    customer_phone = dispatch_doc.get("phone", "")
    customer_state = dispatch_doc.get("state", "")
    
    # Try to find existing party by phone
    party = None
    if customer_phone:
        party = await db.parties.find_one({"phone": customer_phone, "is_active": True}, {"_id": 0})
    
    # If no party found, create one
    if not party:
        party_id = str(uuid.uuid4())
        party = {
            "id": party_id,
            "name": customer_name or "Walk-in Customer",
            "phone": customer_phone,
            "email": "",
            "gstin": "",  # End consumer - no GSTIN
            "party_types": ["customer"],
            "address": dispatch_doc.get("address", ""),
            "city": dispatch_doc.get("city", ""),
            "state": customer_state,
            "state_code": get_state_code(customer_state) if customer_state else "",
            "pincode": dispatch_doc.get("pincode", ""),
            "credit_limit": 0,
            "credit_days": 0,
            "opening_balance": 0,
            "current_balance": 0,
            "is_active": True,
            "created_at": now.isoformat(),
            "updated_at": now.isoformat()
        }
        await db.parties.insert_one(party)
        party.pop("_id", None)
    
    # Get SKU details
    master_sku = None
    if dispatch_doc.get("master_sku_id"):
        master_sku = await db.master_skus.find_one({"id": dispatch_doc.get("master_sku_id")}, {"_id": 0})
    
    if not master_sku:
        # Try to find by SKU code
        sku_code = dispatch_doc.get("sku", "")
        if sku_code:
            master_sku = await db.master_skus.find_one({"sku_code": sku_code}, {"_id": 0})
    
    if not master_sku:
        return None  # Can't create invoice without SKU
    
    # Determine pricing - PRIORITIZE dispatch's taxable_value/invoice_value
    # For marketplace orders, invoice_value is GST-inclusive, taxable_value is pre-calculated
    quantity = dispatch_doc.get("quantity", 1) or 1
    gst_rate = dispatch_doc.get("gst_rate") or master_sku.get("gst_rate", 18) or 18
    hsn_code = master_sku.get("hsn_code", "")
    
    # Check if dispatch has pre-calculated taxable_value (marketplace orders)
    dispatch_invoice_value = dispatch_doc.get("invoice_value") or 0
    dispatch_taxable_value = dispatch_doc.get("taxable_value") or 0
    dispatch_gst_amount = dispatch_doc.get("gst_amount") or 0
    dispatch_selling_price = dispatch_doc.get("selling_price") or 0
    is_gst_inclusive = dispatch_doc.get("price_is_gst_inclusive", False) or dispatch_doc.get("is_marketplace_order", False)
    
    if dispatch_taxable_value > 0:
        # Use dispatch's pre-calculated taxable value directly
        taxable_value = dispatch_taxable_value
        if dispatch_gst_amount > 0:
            gst_amount = dispatch_gst_amount
        else:
            gst_amount = taxable_value * (gst_rate / 100)
    elif dispatch_invoice_value > 0 and is_gst_inclusive:
        # Marketplace order: invoice_value is GST-inclusive, reverse-calculate
        taxable_value = dispatch_invoice_value / (1 + gst_rate / 100)
        gst_amount = dispatch_invoice_value - taxable_value
    elif dispatch_invoice_value > 0:
        # Direct order: invoice_value might be taxable (GST added separately)
        # Check if this looks like a GST-inclusive value by comparing with SKU price
        sku_selling_price = master_sku.get("selling_price") or master_sku.get("mrp") or 0
        if sku_selling_price > 0 and abs(dispatch_invoice_value - (sku_selling_price * quantity * (1 + gst_rate/100))) < 10:
            # Likely GST-inclusive
            taxable_value = dispatch_invoice_value / (1 + gst_rate / 100)
        else:
            taxable_value = dispatch_invoice_value
        gst_amount = taxable_value * (gst_rate / 100)
    elif dispatch_selling_price > 0:
        # Use selling price from dispatch
        taxable_value = dispatch_selling_price * quantity
        gst_amount = taxable_value * (gst_rate / 100)
    else:
        # Fall back to SKU pricing (selling_price > mrp > cost_price)
        unit_price = master_sku.get("selling_price") or master_sku.get("mrp") or master_sku.get("cost_price", 0) or 0
        taxable_value = unit_price * quantity
        gst_amount = taxable_value * (gst_rate / 100)
    
    # Round values
    taxable_value = round(taxable_value, 2)
    gst_amount = round(gst_amount, 2)
    
    # Determine IGST vs CGST/SGST based on state codes
    firm_state_code = firm.get("gstin", "")[:2] if firm.get("gstin") else get_state_code(firm.get("state", ""))
    party_state_code = party.get("state_code") or get_state_code(party.get("state", ""))
    is_igst = firm_state_code != party_state_code
    
    if is_igst:
        igst = gst_amount
        cgst = 0
        sgst = 0
    else:
        igst = 0
        cgst = gst_amount / 2
        sgst = gst_amount / 2
    
    total_gst = igst + cgst + sgst
    grand_total = round(taxable_value + total_gst, 2)
    
    # Generate invoice number
    invoice_number = await get_next_invoice_number(dispatch_doc.get("firm_id"))
    
    invoice = {
        "id": str(uuid.uuid4()),
        "invoice_number": invoice_number,
        "firm_id": dispatch_doc.get("firm_id"),
        "firm_name": firm.get("name"),
        "party_id": party.get("id"),
        "party_name": party.get("name"),
        "party_gstin": party.get("gstin", ""),
        "party_state": party.get("state", ""),
        "dispatch_id": dispatch_doc.get("id"),
        "dispatch_number": dispatch_doc.get("dispatch_number"),
        "invoice_date": now.strftime("%Y-%m-%d"),
        "items": [{
            "master_sku_id": master_sku.get("id"),
            "sku_code": master_sku.get("sku_code"),
            "name": master_sku.get("name"),
            "hsn_code": hsn_code,
            "quantity": quantity,
            "rate": unit_price,
            "gst_rate": gst_rate,
            "discount": 0,
            "taxable_value": taxable_value,
            "gst_amount": gst_amount,
            "igst": igst if is_igst else 0,
            "cgst": cgst if not is_igst else 0,
            "sgst": sgst if not is_igst else 0
        }],
        "subtotal": taxable_value,
        "shipping_charges": 0,
        "other_charges": 0,
        "discount": 0,
        "taxable_value": round(taxable_value, 2),
        "is_igst": is_igst,
        "is_inter_state": is_igst,
        "igst": round(igst, 2),
        "cgst": round(cgst, 2),
        "sgst": round(sgst, 2),
        "total_gst": round(total_gst, 2),
        "grand_total": grand_total,
        "payment_status": "unpaid",
        "amount_paid": 0,
        "balance_due": grand_total,
        "gst_override": False,
        "notes": f"Auto-generated from dispatch {dispatch_doc.get('dispatch_number')}",
        "order_source": dispatch_doc.get("order_source", "direct"),
        "marketplace_order_id": dispatch_doc.get("marketplace_order_id"),
        "created_by": dispatch_doc.get("created_by"),
        "created_by_name": dispatch_doc.get("created_by_name"),
        "created_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    
    await db.sales_invoices.insert_one(invoice)
    invoice.pop("_id", None)
    return invoice


# ==================== DISPATCH ENDPOINTS ====================

@api_router.post("/dispatches", response_model=DispatchResponse)
async def create_dispatch(
    dispatch_type: str = Form(...),
    sku: str = Form(...),
    customer_name: str = Form(...),
    phone: str = Form(...),
    address: str = Form(...),
    reason: str = Form(...),
    order_id: str = Form(...),
    payment_reference: str = Form(...),
    invoice_file: UploadFile = File(...),
    firm_id: Optional[str] = Form(None),
    city: Optional[str] = Form(None),
    state: Optional[str] = Form(None),
    pincode: Optional[str] = Form(None),
    note: Optional[str] = Form(None),
    ticket_id: Optional[str] = Form(None),
    serial_number: Optional[str] = Form(None),  # For manufactured items
    pending_fulfillment_id: Optional[str] = Form(None),  # For pending fulfillment dispatch
    tracking_id: Optional[str] = Form(None),  # Pre-set tracking ID from pending fulfillment
    order_source: Optional[str] = Form(None),  # amazon, flipkart, website, walkin, other
    marketplace_order_id: Optional[str] = Form(None),  # External marketplace order ID
    item_serials: Optional[str] = Form(None),  # JSON array of {item_index, master_sku_id, serial_number} for multi-item orders
    invoice_number: Optional[str] = Form(None),  # Custom invoice number
    user: dict = Depends(require_roles(["accountant", "admin"]))
):
    """Create dispatch with mandatory invoice/challan upload and firm selection"""
    # Validate required fields for invoice generation
    if not state:
        raise HTTPException(status_code=400, detail="State is required for GST invoice generation. Please provide customer's state.")
    
    if not firm_id:
        raise HTTPException(status_code=400, detail="Firm is required for invoice generation. Please select a firm.")
    
    # DUPLICATE VALIDATION
    dup_errors = await validate_no_duplicates(
        tracking_id=tracking_id,
        order_id=order_id,
        invoice_number=invoice_number
    )
    if dup_errors:
        raise HTTPException(status_code=400, detail=dup_errors[0])
    
    dispatch_id = str(uuid.uuid4())
    dispatch_number = generate_dispatch_number()
    now = datetime.now(timezone.utc).isoformat()
    
    # Validate firm if provided
    firm_name = None
    master_sku_info = None
    is_manufactured_item = False
    
    if firm_id:
        firm = await db.firms.find_one({"id": firm_id, "is_active": True})
        if not firm:
            raise HTTPException(status_code=400, detail="Invalid or inactive firm")
        firm_name = firm.get("name")
        
        # Check if this is a manufactured Master SKU
        master_sku = await db.master_skus.find_one({
            "$or": [
                {"sku_code": sku},
                {"aliases.alias_code": sku}
            ],
            "is_active": True
        })
        
        if master_sku and master_sku.get("product_type") == "manufactured":
            is_manufactured_item = True
            master_sku_info = {
                "id": master_sku["id"],
                "name": master_sku["name"],
                "sku_code": master_sku["sku_code"]
            }
            
            # For manufactured items, serial number is REQUIRED
            # Check if serial number is provided directly OR via item_serials (for multi-item/multi-qty orders)
            has_serial_in_item_serials = False
            if item_serials:
                try:
                    import json
                    item_serials_preview = json.loads(item_serials)
                    # Check if any serial in item_serials matches this SKU
                    has_serial_in_item_serials = any(
                        s.get("master_sku_id") == master_sku["id"] 
                        for s in item_serials_preview
                    )
                except:
                    pass
            
            if not serial_number and not has_serial_in_item_serials:
                raise HTTPException(status_code=400, detail="Serial number is required for manufactured items")
            
            # Only validate single serial_number if provided (item_serials handled separately below)
            if serial_number:
                # Verify serial number exists and is in_stock for this firm/SKU
                serial_record = await db.finished_good_serials.find_one({
                    "serial_number": serial_number,
                    "master_sku_id": master_sku["id"],
                    "firm_id": firm_id,
                    "status": "in_stock"
                })
                
                if not serial_record:
                    raise HTTPException(status_code=400, detail=f"Serial number {serial_number} not found or not available in stock")
                
                # Reserve the serial number (mark as dispatched)
                await db.finished_good_serials.update_one(
                    {"serial_number": serial_number},
                    {"$set": {
                        "status": "dispatched",
                        "dispatch_date": now,
                        "updated_at": now
                    }}
                )
        else:
            # For non-manufactured items, check regular SKU stock
            sku_item = await db.skus.find_one({"sku_code": sku, "firm_id": firm_id, "active": True})
            if not sku_item:
                # Check if SKU exists at all
                sku_exists = await db.skus.find_one({"sku_code": sku, "active": True})
                if not sku_exists:
                    # Also check Master SKUs inventory
                    if not master_sku:
                        raise HTTPException(status_code=400, detail=f"SKU {sku} not found")
                
                if not master_sku:
                    raise HTTPException(status_code=400, detail=f"SKU {sku} not available in selected firm")
            
            if sku_item and sku_item.get("stock_quantity", 0) <= 0:
                raise HTTPException(status_code=400, detail=f"SKU {sku} is out of stock in selected firm")
    
    # Process item_serials for multi-item orders with manufactured items
    processed_item_serials = []
    if item_serials:
        try:
            import json
            item_serials_data = json.loads(item_serials)
            
            for item_serial in item_serials_data:
                item_master_sku_id = item_serial.get("master_sku_id")
                item_serial_number = item_serial.get("serial_number")
                item_index = item_serial.get("item_index")
                
                if item_master_sku_id and item_serial_number:
                    # Verify serial number exists and is in_stock
                    serial_record = await db.finished_good_serials.find_one({
                        "serial_number": item_serial_number,
                        "master_sku_id": item_master_sku_id,
                        "firm_id": firm_id,
                        "status": "in_stock"
                    })
                    
                    if not serial_record:
                        raise HTTPException(
                            status_code=400, 
                            detail=f"Serial number {item_serial_number} not found or not available in stock"
                        )
                    
                    # Mark serial as dispatched
                    await db.finished_good_serials.update_one(
                        {"serial_number": item_serial_number},
                        {"$set": {
                            "status": "dispatched",
                            "dispatch_date": now,
                            "updated_at": now
                        }}
                    )
                    
                    # Get SKU info for record
                    item_sku = await db.master_skus.find_one({"id": item_master_sku_id}, {"_id": 0, "name": 1, "sku_code": 1})
                    
                    processed_item_serials.append({
                        "item_index": item_index,
                        "master_sku_id": item_master_sku_id,
                        "master_sku_name": item_sku.get("name") if item_sku else None,
                        "sku_code": item_sku.get("sku_code") if item_sku else None,
                        "serial_number": item_serial_number
                    })
        except json.JSONDecodeError:
            logger.warning(f"Failed to parse item_serials JSON: {item_serials}")
    
    # Upload invoice file using storage utility
    try:
        content = await invoice_file.read()
        relative_path, storage_type = await storage_upload(
            file_data=content,
            folder="invoices",
            original_filename=invoice_file.filename,
            filename_prefix=f"invoice_{dispatch_id}"
        )
        invoice_url = f"/api/files/{relative_path}"
    except StorageError as e:
        logger.error(f"Failed to upload dispatch invoice: {str(e)}")
        raise HTTPException(status_code=500, detail=f"File upload failed: {str(e)}")
    
    # Get ticket number if linked
    ticket_number = None
    if ticket_id:
        ticket = await db.tickets.find_one({"id": ticket_id}, {"_id": 0})
        if ticket:
            ticket_number = ticket["ticket_number"]
    
    # ====== COMPLIANCE VALIDATION FOR DISPATCH ======
    compliance_data = {
        "dispatch_type": dispatch_type,
        "customer_name": customer_name,
        "phone": phone,
        "address": address,
        "order_id": order_id,
        "firm_id": firm_id,
        "sku": sku,
        "tracking_id": tracking_id
    }
    
    files_present = {"invoice_file": invoice_url if invoice_file else None}
    
    compliance_result = validate_document_compliance(
        "dispatch",
        compliance_data,
        files_present,
        0  # No monetary value for dispatch compliance
    )
    
    doc_status = compliance_result["status"]
    
    dispatch_doc = {
        "id": dispatch_id,
        "dispatch_number": dispatch_number,
        "dispatch_type": dispatch_type,
        "ticket_id": ticket_id,
        "ticket_number": ticket_number,
        "sku": sku,
        "firm_id": firm_id,
        "firm_name": firm_name,
        "is_manufactured_item": is_manufactured_item,
        "master_sku_id": master_sku_info["id"] if master_sku_info else None,
        "master_sku_name": master_sku_info["name"] if master_sku_info else None,
        "serial_number": serial_number if is_manufactured_item else None,
        "item_serials": processed_item_serials if processed_item_serials else None,  # For multi-item orders
        "customer_name": customer_name,
        "phone": phone,
        "address": address,
        "city": city,
        "state": state,
        "pincode": pincode,
        "reason": reason,
        "note": note,
        "order_id": order_id,
        "payment_reference": payment_reference,
        "invoice_url": invoice_url,
        "courier": None,
        "tracking_id": tracking_id,  # Pre-filled if from pending fulfillment
        "label_file": None,
        "status": "pending_label",
        "doc_status": doc_status,
        "compliance_score": compliance_result["compliance_score"],
        "compliance_issues": compliance_result.get("soft_blocks", []) + compliance_result.get("warnings", []),
        "pending_fulfillment_id": pending_fulfillment_id,  # Link to pending fulfillment entry
        "order_source": order_source.lower() if order_source else None,  # amazon, flipkart, website, walkin, other
        "marketplace_order_id": marketplace_order_id or order_id,  # Use marketplace ID or fallback to order_id
        "service_charges": None,
        "service_invoice": None,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now,
        "updated_at": now,
        "scanned_in_at": None,
        "scanned_out_at": None
    }
    
    await db.dispatches.insert_one(dispatch_doc)
    dispatch_doc.pop("_id", None)
    
    # Create compliance exception if there are issues
    if doc_status == "pending" and (compliance_result["soft_blocks"] or compliance_result["missing_important"]):
        severity = "important" if compliance_result["missing_important"] else "minor"
        await create_compliance_exception(
            transaction_type="dispatch",
            transaction_id=dispatch_id,
            transaction_ref=dispatch_number,
            firm_id=firm_id or "default",
            issues=compliance_result["soft_blocks"] + [f"Missing: {m['label']}" for m in compliance_result.get("missing_important", [])],
            severity=severity,
            user=user
        )
    
    # Mark pending fulfillment entry as dispatched if applicable
    if pending_fulfillment_id:
        await db.pending_fulfillment.update_one(
            {"id": pending_fulfillment_id},
            {"$set": {
                "status": "dispatched",
                "dispatch_id": dispatch_id,
                "dispatched_at": now,
                "updated_at": now
            }}
        )
        
        # Create audit log for pending fulfillment dispatch
        await db.audit_logs.insert_one({
            "id": str(uuid.uuid4()),
            "action": "pending_fulfillment_dispatched",
            "entity_type": "pending_fulfillment",
            "entity_id": pending_fulfillment_id,
            "entity_name": order_id,
            "performed_by": user["id"],
            "performed_by_name": f"{user['first_name']} {user['last_name']}",
            "details": {"dispatch_id": dispatch_id, "tracking_id": tracking_id, "serial_number": serial_number},
            "timestamp": now
        })
    
    # Create notification for new dispatch
    await create_notification(
        title="New Dispatch Created",
        message=f"Dispatch {dispatch_number} created for {customer_name} - {dispatch_type.replace('_', ' ')}",
        notification_type="info",
        link="/accountant",
        target_roles=["accountant", "dispatcher", "admin"],
        priority="normal"
    )
    
    # Auto-create customer party if not exists (for sales invoice linking)
    await ensure_customer_party(
        customer_name=customer_name,
        phone=phone,
        address=address,
        city=city,
        state=state or "Unknown",
        pincode=pincode
    )
    
    # Create sales order entry from dispatch
    await create_sales_order_from_dispatch(dispatch_doc, db)
    
    # Auto-create sales invoice for GST compliance
    await create_sales_invoice_from_dispatch(dispatch_doc, db)
    
    return DispatchResponse(**dispatch_doc)

@api_router.post("/dispatches/from-ticket/{ticket_id}", response_model=DispatchResponse)
async def create_dispatch_from_ticket(
    ticket_id: str,
    dispatch_type: str = Form(...),
    sku: Optional[str] = Form(None),
    firm_id: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["accountant", "admin"]))
):
    """Create dispatch from a hardware ticket"""
    ticket = await db.tickets.find_one({"id": ticket_id}, {"_id": 0})
    if not ticket:
        raise HTTPException(status_code=404, detail="Ticket not found")
    
    # Get firm name if firm_id provided
    firm_name = None
    if firm_id:
        firm = await db.firms.find_one({"id": firm_id}, {"_id": 0})
        firm_name = firm.get("name") if firm else None
    
    dispatch_id = str(uuid.uuid4())
    dispatch_number = generate_dispatch_number()
    now = datetime.now(timezone.utc).isoformat()
    
    dispatch_doc = {
        "id": dispatch_id,
        "dispatch_number": dispatch_number,
        "dispatch_type": dispatch_type,
        "ticket_id": ticket_id,
        "ticket_number": ticket["ticket_number"],
        "sku": sku,
        "firm_id": firm_id,
        "firm_name": firm_name,
        "customer_name": ticket["customer_name"],
        "phone": ticket["customer_phone"],
        "address": ticket.get("customer_address") or "",
        "city": ticket.get("customer_city"),
        "state": None,
        "pincode": None,
        "reason": f"Hardware service - {dispatch_type.replace('_', ' ')}",
        "note": ticket.get("agent_notes"),
        "courier": None,
        "tracking_id": None,
        "label_file": None,
        "status": "pending_label",
        "service_charges": None,
        "service_invoice": None,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now,
        "updated_at": now,
        "scanned_in_at": None,
        "scanned_out_at": None
    }
    
    await db.dispatches.insert_one(dispatch_doc)
    
    # Update ticket status
    await db.tickets.update_one(
        {"id": ticket_id},
        {"$set": {"status": "awaiting_label", "updated_at": now}}
    )
    await add_ticket_history(ticket_id, f"Dispatch created ({dispatch_type})", user, {"dispatch_number": dispatch_number})
    
    dispatch_doc.pop("_id", None)
    return DispatchResponse(**dispatch_doc)

@api_router.get("/dispatches", response_model=List[DispatchResponse])
async def list_dispatches(
    status: Optional[str] = None,
    dispatch_type: Optional[str] = None,
    search: Optional[str] = None,
    user: dict = Depends(require_roles(["accountant", "dispatcher", "gate", "admin"]))
):
    """List dispatches"""
    query = {}
    
    if status:
        query["status"] = status
    if dispatch_type:
        query["dispatch_type"] = dispatch_type
    if search:
        query["$or"] = [
            {"dispatch_number": {"$regex": search, "$options": "i"}},
            {"customer_name": {"$regex": search, "$options": "i"}},
            {"tracking_id": {"$regex": search, "$options": "i"}},
            {"order_id": {"$regex": search, "$options": "i"}},
            {"marketplace_order_id": {"$regex": search, "$options": "i"}}
        ]
    
    dispatches = await db.dispatches.find(query, {"_id": 0}).sort("created_at", -1).to_list(10000)
    return [DispatchResponse(**d) for d in dispatches]

@api_router.patch("/dispatches/{dispatch_id}/label")
async def upload_dispatch_label(
    dispatch_id: str,
    courier: str = Form(...),
    tracking_id: str = Form(...),
    label_file: UploadFile = File(...),
    user: dict = Depends(require_roles(["accountant", "admin"]))
):
    """Upload shipping label for dispatch"""
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    if not dispatch:
        raise HTTPException(status_code=404, detail="Dispatch not found")
    
    # Upload file using storage utility
    try:
        content = await label_file.read()
        relative_path, storage_type = await storage_upload(
            file_data=content,
            folder="labels",
            original_filename=label_file.filename,
            filename_prefix=dispatch_id
        )
        label_url = f"/api/files/{relative_path}"
    except StorageError as e:
        logger.error(f"Failed to upload dispatch label: {str(e)}")
        raise HTTPException(status_code=500, detail=f"File upload failed: {str(e)}")
    
    now = datetime.now(timezone.utc).isoformat()
    
    await db.dispatches.update_one(
        {"id": dispatch_id},
        {"$set": {
            "courier": courier,
            "tracking_id": tracking_id,
            "label_file": label_url,
            "status": "ready_for_dispatch",
            "updated_at": now
        }}
    )
    
    return {"message": "Label uploaded", "label_url": label_url}

@api_router.patch("/dispatches/{dispatch_id}/status")
async def update_dispatch_status(
    dispatch_id: str,
    status: str = Form(...),
    user: dict = Depends(require_roles(["dispatcher", "gate", "admin"]))
):
    """Update dispatch status - handles both dispatches and tickets"""
    now = datetime.now(timezone.utc).isoformat()
    
    # Try to find in dispatches first
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    
    if dispatch:
        # It's a regular dispatch
        update = {"status": status, "updated_at": now}
        if status == "dispatched":
            update["scanned_out_at"] = now
            
            # ============ STOCK DEDUCTION ON DISPATCH ============
            # Only deduct stock if dispatch has firm_id and sku
            firm_id = dispatch.get("firm_id")
            sku_code = dispatch.get("sku")
            
            if firm_id and sku_code:
                # Find the SKU with this firm_id
                sku_item = await db.skus.find_one({
                    "sku_code": sku_code,
                    "firm_id": firm_id,
                    "active": True
                })
                
                if sku_item:
                    # Check if stock is available
                    current_stock = sku_item.get("stock_quantity", 0)
                    if current_stock < 1:
                        raise HTTPException(
                            status_code=400,
                            detail=f"Insufficient stock for {sku_code} in this firm. Available: {current_stock}"
                        )
                    
                    # Create dispatch_out ledger entry
                    ledger_entry_id = str(uuid.uuid4())
                    running_balance = current_stock - 1
                    
                    ledger_entry = {
                        "id": ledger_entry_id,
                        "entry_number": generate_ledger_entry_number(),
                        "entry_type": "dispatch_out",
                        "item_type": "finished_good",
                        "item_id": sku_item["id"],
                        "item_name": sku_item.get("model_name"),
                        "item_sku": sku_code,
                        "firm_id": firm_id,
                        "firm_name": dispatch.get("firm_name"),
                        "quantity": 1,
                        "running_balance": running_balance,
                        "unit_price": None,
                        "total_value": None,
                        "invoice_number": dispatch.get("invoice_url"),  # Link to invoice if available
                        "reason": f"Dispatch #{dispatch.get('dispatch_number')} - {dispatch.get('dispatch_type', 'sale')}",
                        "reference_id": dispatch_id,
                        "notes": f"Customer: {dispatch.get('customer_name')}, Order: {dispatch.get('order_id')}",
                        "created_by": user["id"],
                        "created_by_name": f"{user['first_name']} {user['last_name']}",
                        "created_at": now,
                        # Additional dispatch-specific fields
                        "dispatch_id": dispatch_id,
                        "dispatch_number": dispatch.get("dispatch_number")
                    }
                    
                    await db.inventory_ledger.insert_one(ledger_entry)
                    
                    # Update SKU stock
                    await db.skus.update_one(
                        {"id": sku_item["id"]},
                        {"$set": {"stock_quantity": running_balance, "updated_at": now}}
                    )
                    
                    # Create audit log for stock deduction
                    await db.audit_logs.insert_one({
                        "id": str(uuid.uuid4()),
                        "action": "dispatch_stock_deducted",
                        "entity_type": "dispatch",
                        "entity_id": dispatch_id,
                        "entity_name": dispatch.get("dispatch_number"),
                        "performed_by": user["id"],
                        "performed_by_name": f"{user['first_name']} {user['last_name']}",
                        "details": {
                            "sku": sku_code,
                            "firm_id": firm_id,
                            "quantity_deducted": 1,
                            "previous_stock": current_stock,
                            "new_stock": running_balance,
                            "ledger_entry_id": ledger_entry_id
                        },
                        "timestamp": now
                    })
                    
                    # Mark dispatch as stock_deducted
                    update["stock_deducted"] = True
                    update["ledger_entry_id"] = ledger_entry_id
            # ============ END STOCK DEDUCTION ============
            
            # Create sales order if not already exists
            existing_sales_order = await db.sales_orders.find_one({"dispatch_id": dispatch_id})
            if not existing_sales_order:
                dispatch["scanned_out_at"] = now  # Set for sales order creation
                await create_sales_order_from_dispatch(dispatch, db)
            else:
                # Update existing sales order with dispatch status
                await db.sales_orders.update_one(
                    {"dispatch_id": dispatch_id},
                    {"$set": {"dispatch_status": "dispatched", "dispatched_at": now, "updated_at": now}}
                )
            
            # Auto-create sales invoice for GST compliance
            await create_sales_invoice_from_dispatch(dispatch, db)
            
            # Auto-register warranty for serialized items
            try:
                warranties = await auto_register_warranty_on_dispatch(dispatch, db)
                if warranties:
                    update["warranties_created"] = warranties
                    logger.info(f"Auto-registered {len(warranties)} warranties for dispatch {dispatch_id}")
            except Exception as e:
                logger.error(f"Failed to auto-register warranty: {str(e)}")
            
            # If this is an amazon_order, create a feedback call task for call support
            if dispatch.get("dispatch_type") == "amazon_order":
                feedback_call_id = str(uuid.uuid4())
                feedback_call = {
                    "id": feedback_call_id,
                    "dispatch_id": dispatch_id,
                    "dispatch_number": dispatch.get("dispatch_number"),
                    "order_id": dispatch.get("order_id"),
                    "customer_name": dispatch.get("customer_name"),
                    "phone": dispatch.get("phone"),
                    "sku": dispatch.get("sku"),
                    "status": "pending",  # pending, completed, no_answer
                    "call_attempts": 0,
                    "feedback_screenshot": None,
                    "notes": None,
                    "assigned_to": None,
                    "completed_by": None,
                    "completed_at": None,
                    "created_at": now,
                    "updated_at": now
                }
                await db.feedback_calls.insert_one(feedback_call)
        
        await db.dispatches.update_one({"id": dispatch_id}, {"$set": update})
        return {"message": f"Dispatch status updated to {status}"}
    
    # Not found in dispatches, check tickets (for return dispatches)
    ticket = await db.tickets.find_one({"id": dispatch_id}, {"_id": 0})
    
    if ticket:
        # It's a ticket return dispatch
        update = {"status": status, "updated_at": now}
        if status == "dispatched":
            update["dispatched_at"] = now
            update["status"] = "dispatched"
        await db.tickets.update_one({"id": dispatch_id}, {"$set": update})
        
        # Add to ticket history
        history_entry = {
            "action": f"Status changed to {status}",
            "by": f"{user['first_name']} {user['last_name']}",
            "by_id": user["id"],
            "by_role": user["role"],
            "timestamp": now,
            "details": {}
        }
        await db.tickets.update_one({"id": dispatch_id}, {"$push": {"history": history_entry}})
        
        return {"message": f"Ticket return dispatch status updated to {status}"}
    
    raise HTTPException(status_code=404, detail="Dispatch not found")

@api_router.get("/dispatcher/queue", response_model=List[DispatchResponse])
async def get_dispatcher_queue(
    user: dict = Depends(require_roles(["call_support", "supervisor", "technician", "service_agent", "accountant", "dispatcher", "gate", "admin"]))
):
    """Get dispatcher queue - items ready to ship"""
    dispatches = await db.dispatches.find(
        {"status": "ready_for_dispatch"},
        {"_id": 0}
    ).sort("created_at", 1).to_list(100)
    
    # Also get tickets ready for dispatch
    tickets = await db.tickets.find(
        {"status": "ready_for_dispatch"},
        {"_id": 0}
    ).sort("created_at", 1).to_list(100)
    
    # Convert tickets to dispatch-like format
    for ticket in tickets:
        dispatch_item = {
            "id": ticket["id"],
            "dispatch_number": ticket["ticket_number"],
            "dispatch_type": "walkin_return" if ticket.get("is_walkin") else "return_dispatch",
            "ticket_id": ticket["id"],
            "ticket_number": ticket["ticket_number"],
            "sku": None,
            "customer_name": ticket["customer_name"],
            "phone": ticket["customer_phone"],
            "address": ticket.get("address") or ticket.get("customer_address", ""),
            "city": ticket.get("city") or ticket.get("customer_city"),
            "state": ticket.get("state"),
            "pincode": ticket.get("pincode"),
            "reason": "Walk-in repair return" if ticket.get("is_walkin") else "Hardware repair return",
            "note": ticket.get("repair_notes"),
            "courier": ticket.get("return_courier"),
            "tracking_id": ticket.get("return_tracking"),
            "label_file": ticket.get("return_label"),
            "status": "ready_for_dispatch",
            "service_charges": ticket.get("service_charges"),
            "service_invoice": ticket.get("service_invoice"),
            "is_walkin": ticket.get("is_walkin", False),
            "board_serial_number": ticket.get("board_serial_number"),
            "device_serial_number": ticket.get("device_serial_number"),
            "created_by": ticket.get("created_by", ""),
            "created_by_name": None,
            "created_at": ticket["created_at"],
            "updated_at": ticket["updated_at"],
            "scanned_in_at": ticket.get("received_at"),
            "scanned_out_at": None
        }
        dispatches.append(dispatch_item)
    
    return [DispatchResponse(**d) for d in dispatches]

@api_router.patch("/dispatcher/dispatches/{dispatch_id}/update-courier")
async def dispatcher_update_courier(
    dispatch_id: str,
    courier: str = Form(...),
    tracking_id: str = Form(...),
    reason: Optional[str] = Form(None),
    label_file: Optional[UploadFile] = File(None),
    user: dict = Depends(require_roles(["dispatcher", "admin"]))
):
    """Dispatcher updates courier details before dispatch - for when courier didn't arrive"""
    # Check if this is a dispatch or a ticket
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    is_ticket = False
    
    if not dispatch:
        # Check if it's a ticket
        dispatch = await db.tickets.find_one({"id": dispatch_id}, {"_id": 0})
        is_ticket = True
        if not dispatch:
            raise HTTPException(status_code=404, detail="Dispatch not found")
    
    now = datetime.now(timezone.utc)
    collection = db.tickets if is_ticket else db.dispatches
    
    # Store previous courier info in history
    courier_history = dispatch.get("courier_history", [])
    if dispatch.get("courier") or dispatch.get("return_courier"):
        old_courier = dispatch.get("return_courier") if is_ticket else dispatch.get("courier")
        old_tracking = dispatch.get("return_tracking") if is_ticket else dispatch.get("tracking_id")
        if old_courier:
            courier_history.append({
                "courier": old_courier,
                "tracking_id": old_tracking,
                "label_file": dispatch.get("return_label") if is_ticket else dispatch.get("label_file"),
                "updated_at": dispatch.get("updated_at"),
                "failed_reason": reason
            })
    
    # Handle label file upload using storage utility
    label_url = None
    if label_file:
        try:
            content = await label_file.read()
            relative_path, storage_type = await storage_upload(
                file_data=content,
                folder="labels",
                original_filename=label_file.filename,
                filename_prefix=f"dispatch_label_{dispatch_id}"
            )
            label_url = f"/api/files/{relative_path}"
        except StorageError as e:
            logger.error(f"Failed to upload dispatch label: {str(e)}")
            raise HTTPException(status_code=500, detail=f"File upload failed: {str(e)}")
    
    # Update fields based on collection type
    if is_ticket:
        update_data = {
            "return_courier": courier,
            "return_tracking": tracking_id,
            "courier_history": courier_history,
            "courier_update_count": len(courier_history),
            "updated_at": now.isoformat()
        }
        if label_url:
            update_data["return_label"] = label_url
    else:
        update_data = {
            "courier": courier,
            "tracking_id": tracking_id,
            "courier_history": courier_history,
            "courier_update_count": len(courier_history),
            "updated_at": now.isoformat()
        }
        if label_url:
            update_data["label_file"] = label_url
    
    await collection.update_one({"id": dispatch_id}, {"$set": update_data})
    
    # Add to history
    if is_ticket:
        await add_ticket_history(dispatch_id, f"Courier updated by dispatcher: {courier} ({tracking_id})", user, {
            "reason": reason,
            "attempt": len(courier_history) + 1
        })
    
    return {
        "message": "Courier details updated",
        "courier": courier,
        "tracking_id": tracking_id,
        "attempt": len(courier_history) + 1
    }

@api_router.get("/dispatcher/recent")
async def get_recent_dispatches(
    user: dict = Depends(require_roles(["call_support", "supervisor", "technician", "service_agent", "accountant", "dispatcher", "gate", "admin"]))
):
    """Get recently dispatched items"""
    # Get dispatches that have been dispatched (outbound)
    dispatched = await db.dispatches.find(
        {"status": "dispatched"},
        {"_id": 0}
    ).sort("scanned_out_at", -1).to_list(50)
    
    # Also get tickets that have been dispatched
    dispatched_tickets = await db.tickets.find(
        {"status": "dispatched"},
        {"_id": 0}
    ).sort("dispatched_at", -1).to_list(50)
    
    # Convert tickets to dispatch format
    for ticket in dispatched_tickets:
        dispatch_item = {
            "id": ticket["id"],
            "dispatch_number": ticket["ticket_number"],
            "dispatch_type": "walkin_return" if ticket.get("is_walkin") else "return_dispatch",
            "ticket_id": ticket["id"],
            "ticket_number": ticket["ticket_number"],
            "customer_name": ticket["customer_name"],
            "phone": ticket["customer_phone"],
            "courier": ticket.get("return_courier"),
            "tracking_id": ticket.get("return_tracking"),
            "status": "dispatched",
            "is_walkin": ticket.get("is_walkin", False),
            "dispatched_at": ticket.get("dispatched_at"),
            "created_at": ticket["created_at"]
        }
        dispatched.append(dispatch_item)
    
    # Sort by dispatch time
    dispatched.sort(key=lambda x: x.get("scanned_out_at") or x.get("dispatched_at") or x.get("created_at"), reverse=True)
    
    return dispatched[:50]


@api_router.put("/dispatcher/dispatches/{dispatch_id}/cancel")
async def dispatcher_cancel_dispatch(
    dispatch_id: str,
    reason: str = Form(...),
    user: dict = Depends(require_roles(["dispatcher", "admin", "accountant"]))
):
    """
    Cancel a dispatch and return inventory to stock.
    For manufactured items with serial numbers, sets serial status back to 'in_stock'.
    """
    now = datetime.now(timezone.utc)
    
    # Check if this is a dispatch or a ticket
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    is_ticket = False
    
    if not dispatch:
        # Check if it's a ticket
        dispatch = await db.tickets.find_one({"id": dispatch_id}, {"_id": 0})
        is_ticket = True
        if not dispatch:
            raise HTTPException(status_code=404, detail="Dispatch not found")
    
    # Only allow cancellation of ready_for_dispatch status
    if dispatch.get("status") not in ["ready_for_dispatch", "ready_to_dispatch"]:
        raise HTTPException(status_code=400, detail=f"Cannot cancel dispatch with status '{dispatch.get('status')}'. Only ready_for_dispatch items can be cancelled.")
    
    if is_ticket:
        # For tickets, just change status back
        await db.tickets.update_one(
            {"id": dispatch_id},
            {"$set": {
                "status": "repaired",  # Set back to repaired
                "cancellation_reason": reason,
                "cancelled_at": now.isoformat(),
                "cancelled_by": user["id"],
                "cancelled_by_name": f"{user['first_name']} {user['last_name']}",
                "updated_at": now.isoformat()
            }}
        )
        return {"message": "Return dispatch cancelled", "dispatch_id": dispatch_id}
    
    # For regular dispatches
    collection = db.dispatches
    
    # Return serial numbers to stock if any
    serial_numbers_returned = []
    
    # Check for single serial number
    if dispatch.get("serial_number"):
        await db.finished_good_serials.update_one(
            {"serial_number": dispatch["serial_number"]},
            {"$set": {
                "status": "in_stock",
                "dispatch_id": None,
                "dispatch_date": None,
                "customer_name": None,
                "phone": None,
                "order_id": None,
                "updated_at": now.isoformat()
            }}
        )
        serial_numbers_returned.append(dispatch["serial_number"])
    
    # Check for multi-item serial numbers
    if dispatch.get("item_serials"):
        for item_serial in dispatch["item_serials"]:
            if isinstance(item_serial, dict):
                for sn in item_serial.get("serial_numbers", []):
                    await db.finished_good_serials.update_one(
                        {"serial_number": sn},
                        {"$set": {
                            "status": "in_stock",
                            "dispatch_id": None,
                            "dispatch_date": None,
                            "customer_name": None,
                            "phone": None,
                            "order_id": None,
                            "updated_at": now.isoformat()
                        }}
                    )
                    serial_numbers_returned.append(sn)
    
    # Update dispatch status to cancelled
    await collection.update_one(
        {"id": dispatch_id},
        {"$set": {
            "status": "cancelled",
            "cancellation_reason": reason,
            "cancelled_at": now.isoformat(),
            "cancelled_by": user["id"],
            "cancelled_by_name": f"{user['first_name']} {user['last_name']}",
            "updated_at": now.isoformat()
        }}
    )
    
    # If linked to pending_fulfillment, update that too
    if dispatch.get("pending_fulfillment_id"):
        await db.pending_fulfillment.update_one(
            {"id": dispatch["pending_fulfillment_id"]},
            {"$set": {
                "status": "cancelled",
                "cancellation_reason": reason,
                "cancelled_at": now.isoformat(),
                "updated_at": now.isoformat()
            }}
        )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "dispatch_cancelled",
        "entity_type": "dispatch",
        "entity_id": dispatch_id,
        "entity_name": dispatch.get("dispatch_number"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {
            "reason": reason,
            "serial_numbers_returned": serial_numbers_returned,
            "customer_name": dispatch.get("customer_name"),
            "order_id": dispatch.get("order_id")
        },
        "timestamp": now.isoformat()
    })
    
    return {
        "message": "Dispatch cancelled and inventory returned to stock",
        "dispatch_id": dispatch_id,
        "serial_numbers_returned": serial_numbers_returned
    }


# ==================== GATE SCAN ENDPOINTS ====================

@api_router.post("/gate/scan", response_model=GateScanResponse)
async def gate_scan(
    scan_data: GateScanCreate,
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin", "accountant"]))
):
    """Record gate scan (inward or outward)"""
    # Validate scan type
    if scan_data.scan_type not in ["inward", "outward"]:
        raise HTTPException(status_code=400, detail="Invalid scan_type. Must be 'inward' or 'outward'")
    
    now = datetime.now(timezone.utc)
    scan_id = str(uuid.uuid4())
    
    # Try to find associated ticket or dispatch
    ticket = await db.tickets.find_one(
        {"$or": [
            {"pickup_tracking": scan_data.tracking_id},
            {"return_tracking": scan_data.tracking_id}
        ]},
        {"_id": 0}
    )
    
    dispatch = await db.dispatches.find_one(
        {"tracking_id": scan_data.tracking_id},
        {"_id": 0}
    )
    
    gate_log = {
        "id": scan_id,
        "scan_type": scan_data.scan_type,
        "tracking_id": scan_data.tracking_id,
        "courier": scan_data.courier,
        "ticket_id": ticket["id"] if ticket else None,
        "ticket_number": ticket["ticket_number"] if ticket else None,
        "dispatch_id": dispatch["id"] if dispatch else None,
        "dispatch_number": dispatch["dispatch_number"] if dispatch else None,
        "customer_name": ticket["customer_name"] if ticket else (dispatch["customer_name"] if dispatch else None),
        "scanned_by": user["id"],
        "scanned_by_name": f"{user['first_name']} {user['last_name']}",
        "notes": scan_data.notes,
        "scanned_at": now.isoformat(),
        "media_count": 0,
        "images_count": 0,
        "videos_count": 0,
        "status": "pending"
    }
    
    await db.gate_logs.insert_one(gate_log)
    
    # Handle based on scan type
    if scan_data.scan_type == "inward":
        # ============ CREATE INCOMING QUEUE ENTRY ============
        # For INWARD scans, create an entry in incoming_queue for classification
        # NO direct stock impact at this stage
        queue_id = str(uuid.uuid4())
        queue_entry = {
            "id": queue_id,
            "queue_number": generate_queue_number(),
            "tracking_id": scan_data.tracking_id,
            "courier": scan_data.courier,
            "source": "gate_scan",
            "gate_log_id": scan_id,
            # Link to ticket/dispatch if found
            "linked_ticket_id": ticket["id"] if ticket else None,
            "linked_ticket_number": ticket["ticket_number"] if ticket else None,
            "linked_dispatch_id": dispatch["id"] if dispatch else None,
            "linked_dispatch_number": dispatch["dispatch_number"] if dispatch else None,
            "customer_name": ticket["customer_name"] if ticket else (dispatch["customer_name"] if dispatch else None),
            # Status
            "status": "pending",  # pending, classified, processed
            "classification_type": None,
            # Classification details (filled later)
            "classified_firm_id": None,
            "classified_firm_name": None,
            "classified_item_type": None,
            "classified_item_id": None,
            "classified_item_name": None,
            "classified_item_sku": None,
            "classified_quantity": None,
            "classified_ticket_id": None,
            "original_dispatch_id": None,
            "original_dispatch_number": None,
            "reason": None,
            "reference_number": None,
            "scrap_reason": None,
            "remarks": None,
            "ledger_entry_id": None,
            "ledger_entry_number": None,
            # Audit
            "scanned_by": user["id"],
            "scanned_by_name": f"{user['first_name']} {user['last_name']}",
            "scanned_at": now.isoformat(),
            "classified_by": None,
            "classified_by_name": None,
            "classified_at": None,
            "created_at": now.isoformat(),
            "updated_at": now.isoformat()
        }
        await db.incoming_queue.insert_one(queue_entry)
        
        # Update ticket status to indicate gate received (but not inventory added)
        if ticket:
            await db.tickets.update_one(
                {"id": ticket["id"]},
                {"$set": {"status": "received_at_factory", "received_at": now.isoformat(), "updated_at": now.isoformat()}}
            )
            await add_ticket_history(ticket["id"], "Gate scan - Inward (pending classification)", user, {
                "tracking_id": scan_data.tracking_id,
                "queue_id": queue_id,
                "queue_number": queue_entry["queue_number"]
            })
        # ============ END INCOMING QUEUE ENTRY ============
    
    elif scan_data.scan_type == "outward":
        if ticket:
            await db.tickets.update_one(
                {"id": ticket["id"]},
                {"$set": {"status": "dispatched", "dispatched_at": now.isoformat(), "updated_at": now.isoformat()}}
            )
            await add_ticket_history(ticket["id"], "Gate scan - Outward", user, {"tracking_id": scan_data.tracking_id})
        if dispatch:
            await db.dispatches.update_one(
                {"id": dispatch["id"]},
                {"$set": {"status": "dispatched", "scanned_out_at": now.isoformat(), "updated_at": now.isoformat()}}
            )
        # Notification for outward scan
        await create_notification(
            title="Package Dispatched",
            message=f"Package {scan_data.tracking_id} scanned outward - dispatched to customer",
            notification_type="success",
            target_roles=["accountant", "dispatcher", "admin"],
            priority="normal"
        )
    
    del gate_log["_id"]
    return GateScanResponse(**gate_log)

@api_router.get("/gate/logs", response_model=List[GateScanResponse])
async def get_gate_logs(
    scan_type: Optional[str] = None,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    search: Optional[str] = None,
    limit: int = 100,
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin", "accountant"]))
):
    """Get gate scan logs"""
    query = {}
    
    if scan_type:
        query["scan_type"] = scan_type
    if search:
        query["$or"] = [
            {"tracking_id": {"$regex": search, "$options": "i"}},
            {"ticket_number": {"$regex": search, "$options": "i"}},
            {"customer_name": {"$regex": search, "$options": "i"}}
        ]
    if from_date:
        query["scanned_at"] = {"$gte": from_date}
    if to_date:
        if "scanned_at" in query:
            query["scanned_at"]["$lte"] = to_date
        else:
            query["scanned_at"] = {"$lte": to_date}
    
    logs = await db.gate_logs.find(query, {"_id": 0}).sort("scanned_at", -1).limit(limit).to_list(limit)
    return [GateScanResponse(**log) for log in logs]

@api_router.get("/gate/scheduled")
async def get_scheduled_parcels(
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin", "accountant"]))
):
    """Get scheduled incoming and outgoing parcels"""
    # Scheduled incoming - tickets with pickup label but not yet received
    incoming = await db.tickets.find(
        {"status": {"$in": ["label_uploaded", "pickup_scheduled"]}, "pickup_tracking": {"$ne": None}},
        {"_id": 0, "ticket_number": 1, "customer_name": 1, "pickup_courier": 1, "pickup_tracking": 1, "updated_at": 1}
    ).to_list(50)
    
    # Scheduled outgoing - ready for dispatch
    outgoing_tickets = await db.tickets.find(
        {"status": "ready_for_dispatch", "return_tracking": {"$ne": None}},
        {"_id": 0, "ticket_number": 1, "customer_name": 1, "return_courier": 1, "return_tracking": 1, "updated_at": 1}
    ).to_list(50)
    
    outgoing_dispatches = await db.dispatches.find(
        {"status": "ready_for_dispatch", "tracking_id": {"$ne": None}},
        {"_id": 0, "dispatch_number": 1, "customer_name": 1, "courier": 1, "tracking_id": 1, "updated_at": 1}
    ).to_list(50)
    
    return {
        "scheduled_incoming": incoming,
        "scheduled_outgoing": outgoing_tickets + outgoing_dispatches
    }


# ==================== GATE MEDIA UPLOAD ====================

@api_router.post("/gate/media/upload")
async def upload_gate_media(
    gate_log_id: str = Form(...),
    tracking_id: str = Form(...),
    movement_type: str = Form(...),  # inward or outward
    media_type: str = Form(...),  # image or video
    capture_source: str = Form("camera"),  # camera, gallery, file_upload
    file: UploadFile = File(...),
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin"]))
):
    """Upload media for gate scan with proper folder structure"""
    from utils.storage import upload_file, create_folder
    
    # Validate movement type
    if movement_type not in ["inward", "outward"]:
        raise HTTPException(status_code=400, detail="Invalid movement_type. Use 'inward' or 'outward'")
    
    # Validate media type
    if media_type not in ["image", "video"]:
        raise HTTPException(status_code=400, detail="Invalid media_type. Use 'image' or 'video'")
    
    # Verify gate log exists
    gate_log = await db.gate_logs.find_one({"id": gate_log_id}, {"_id": 0})
    if not gate_log:
        raise HTTPException(status_code=404, detail="Gate log not found")
    
    now = datetime.now(timezone.utc)
    date_str = now.strftime("%Y-%m-%d")
    
    # Determine base folder: Returns for inward, Dispatches for outward
    base_folder = "Returns" if movement_type == "inward" else "Dispatches"
    subfolder = "images" if media_type == "image" else "videos"
    
    # Folder path: Returns/2026-04-03-TRK123456/images/
    folder_path = f"{base_folder}/{date_str}-{tracking_id}/{subfolder}"
    
    # Count existing media for sequential naming
    existing_count = await db.gate_media.count_documents({
        "gate_log_id": gate_log_id,
        "media_type": media_type
    })
    sequence_num = existing_count + 1
    
    # Get file extension
    original_filename = file.filename or "media"
    ext = Path(original_filename).suffix.lower()
    if not ext:
        ext = ".jpg" if media_type == "image" else ".mp4"
    
    # Generate filename: TRK123456_01.jpg
    new_filename = f"{tracking_id}_{str(sequence_num).zfill(2)}{ext}"
    
    # Read file data
    file_data = await file.read()
    
    # Upload to NAS
    try:
        # First create the folder structure
        await create_folder(folder_path)
        
        # Upload the file
        relative_path, storage_type = await upload_file(
            file_data=file_data,
            folder=folder_path,
            original_filename=new_filename,
            filename_prefix=""
        )
    except Exception as e:
        logger.error(f"Failed to upload gate media: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Failed to upload media: {str(e)}")
    
    # Create media record
    media_id = str(uuid.uuid4())
    media_doc = {
        "id": media_id,
        "gate_log_id": gate_log_id,
        "tracking_id": tracking_id,
        "movement_type": movement_type,
        "media_type": media_type,
        "relative_path": relative_path,
        "filename": new_filename,
        "original_filename": original_filename,
        "capture_source": capture_source,
        "file_size": len(file_data),
        "uploaded_by": user["id"],
        "uploaded_by_name": f"{user.get('first_name', '')} {user.get('last_name', '')}".strip(),
        "uploaded_at": now.isoformat(),
        "captured_at": now.isoformat()
    }
    
    await db.gate_media.insert_one(media_doc)
    
    # Update gate log media count
    media_counts = await db.gate_media.aggregate([
        {"$match": {"gate_log_id": gate_log_id}},
        {"$group": {
            "_id": "$media_type",
            "count": {"$sum": 1}
        }}
    ]).to_list(10)
    
    images_count = next((m["count"] for m in media_counts if m["_id"] == "image"), 0)
    videos_count = next((m["count"] for m in media_counts if m["_id"] == "video"), 0)
    
    await db.gate_logs.update_one(
        {"id": gate_log_id},
        {"$set": {
            "images_count": images_count,
            "videos_count": videos_count,
            "media_count": images_count + videos_count
        }}
    )
    
    del media_doc["_id"]
    return {
        "success": True,
        "media": media_doc,
        "images_count": images_count,
        "videos_count": videos_count
    }


@api_router.get("/gate/media/{gate_log_id}")
async def get_gate_media(
    gate_log_id: str,
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin", "accountant"]))
):
    """Get all media for a gate log"""
    media = await db.gate_media.find(
        {"gate_log_id": gate_log_id},
        {"_id": 0}
    ).sort("uploaded_at", 1).to_list(50)
    
    return {
        "media": media,
        "images": [m for m in media if m["media_type"] == "image"],
        "videos": [m for m in media if m["media_type"] == "video"],
        "images_count": len([m for m in media if m["media_type"] == "image"]),
        "videos_count": len([m for m in media if m["media_type"] == "video"])
    }


@api_router.delete("/gate/media/{media_id}")
async def delete_gate_media(
    media_id: str,
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin"]))
):
    """Delete a gate media file"""
    from utils.storage import delete_file
    
    media = await db.gate_media.find_one({"id": media_id}, {"_id": 0})
    if not media:
        raise HTTPException(status_code=404, detail="Media not found")
    
    # Delete from NAS
    try:
        await delete_file(media["relative_path"])
    except Exception as e:
        logger.warning(f"Failed to delete file from NAS: {str(e)}")
    
    # Delete from database
    await db.gate_media.delete_one({"id": media_id})
    
    # Update gate log media count
    gate_log_id = media["gate_log_id"]
    media_counts = await db.gate_media.aggregate([
        {"$match": {"gate_log_id": gate_log_id}},
        {"$group": {
            "_id": "$media_type",
            "count": {"$sum": 1}
        }}
    ]).to_list(10)
    
    images_count = next((m["count"] for m in media_counts if m["_id"] == "image"), 0)
    videos_count = next((m["count"] for m in media_counts if m["_id"] == "video"), 0)
    
    await db.gate_logs.update_one(
        {"id": gate_log_id},
        {"$set": {
            "images_count": images_count,
            "videos_count": videos_count,
            "media_count": images_count + videos_count
        }}
    )
    
    return {"success": True, "message": "Media deleted"}


@api_router.post("/gate/{gate_log_id}/complete")
async def complete_gate_scan(
    gate_log_id: str,
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin"]))
):
    """Complete a gate scan after media validation"""
    gate_log = await db.gate_logs.find_one({"id": gate_log_id}, {"_id": 0})
    if not gate_log:
        raise HTTPException(status_code=404, detail="Gate log not found")
    
    # Get media counts
    media = await db.gate_media.find({"gate_log_id": gate_log_id}, {"_id": 0}).to_list(50)
    images_count = len([m for m in media if m["media_type"] == "image"])
    videos_count = len([m for m in media if m["media_type"] == "video"])
    
    scan_type = gate_log.get("scan_type")
    
    # Validate media requirements
    if scan_type == "outward":
        if images_count < 1:
            raise HTTPException(
                status_code=400, 
                detail="Outward scan requires at least 1 image. Please capture/upload images before completing."
            )
    elif scan_type == "inward":
        if images_count < 2:
            raise HTTPException(
                status_code=400, 
                detail=f"Inward scan requires at least 2 images. Currently have {images_count}. Please capture/upload more images."
            )
    
    # Mark gate log as completed
    now = datetime.now(timezone.utc)
    await db.gate_logs.update_one(
        {"id": gate_log_id},
        {"$set": {
            "status": "completed",
            "completed_at": now.isoformat(),
            "completed_by": user["id"],
            "images_count": images_count,
            "videos_count": videos_count,
            "media_count": images_count + videos_count
        }}
    )
    
    # Update incoming queue entry if exists (for inward scans)
    if scan_type == "inward":
        await db.incoming_queue.update_one(
            {"gate_log_id": gate_log_id},
            {"$set": {
                "media_attached": True,
                "images_count": images_count,
                "videos_count": videos_count,
                "updated_at": now.isoformat()
            }}
        )
    
    return {
        "success": True,
        "message": f"Gate scan completed with {images_count} images and {videos_count} videos",
        "images_count": images_count,
        "videos_count": videos_count
    }


@api_router.get("/gate/media/by-tracking/{tracking_id}")
async def get_media_by_tracking(
    tracking_id: str,
    user: dict = Depends(require_roles(["gate", "dispatcher", "admin", "accountant"]))
):
    """Get all media for a tracking ID (for accountant viewing)"""
    media = await db.gate_media.find(
        {"tracking_id": tracking_id},
        {"_id": 0}
    ).sort("uploaded_at", 1).to_list(100)
    
    return {
        "tracking_id": tracking_id,
        "media": media,
        "images": [m for m in media if m["media_type"] == "image"],
        "videos": [m for m in media if m["media_type"] == "video"],
        "total_count": len(media)
    }


@api_router.get("/gate/media/download/{media_id}")
async def download_gate_media(
    media_id: str,
    token: Optional[str] = Query(None, description="Auth token for browser image tags"),
    user: dict = Depends(get_current_user_optional)
):
    """Download/stream a gate media file. Supports token via query param for browser <img> tags."""
    from utils.storage import download_file
    from fastapi.responses import StreamingResponse
    import io
    
    # If no user from header, try query token
    if not user and token:
        try:
            payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
            user_id = payload.get("user_id")  # Our JWT uses "user_id" not "sub"
            if user_id:
                user = await db.users.find_one({"id": user_id}, {"_id": 0})
        except:
            pass
    
    if not user:
        raise HTTPException(status_code=403, detail="Authentication required")
    
    media = await db.gate_media.find_one({"id": media_id}, {"_id": 0})
    if not media:
        raise HTTPException(status_code=404, detail="Media not found")
    
    # Download from NAS
    file_data = await download_file(media["relative_path"])
    if not file_data:
        raise HTTPException(status_code=404, detail="File not found in storage")
    
    # Determine content type
    ext = Path(media["filename"]).suffix.lower()
    content_types = {
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".png": "image/png",
        ".webp": "image/webp",
        ".mp4": "video/mp4",
        ".mov": "video/quicktime",
        ".avi": "video/x-msvideo"
    }
    content_type = content_types.get(ext, "application/octet-stream")
    
    return StreamingResponse(
        io.BytesIO(file_data),
        media_type=content_type,
        headers={"Content-Disposition": f"inline; filename={media['filename']}"}
    )


