@api_router.patch("/admin/users/{user_id}")
async def update_user(
    user_id: str,
    first_name: Optional[str] = None,
    last_name: Optional[str] = None,
    email: Optional[str] = None,
    phone: Optional[str] = None,
    role: Optional[str] = None,
    password: Optional[str] = None,
    user: dict = Depends(require_roles(["admin"]))
):
    """Update user details"""
    target_user = await db.users.find_one({"id": user_id}, {"_id": 0})
    if not target_user:
        raise HTTPException(status_code=404, detail="User not found")
    
    update_data = {"updated_at": datetime.now(timezone.utc).isoformat()}
    
    if first_name:
        update_data["first_name"] = first_name
    if last_name:
        update_data["last_name"] = last_name
    if email:
        # Check if email is already taken by another user
        existing = await db.users.find_one({"email": email.lower(), "id": {"$ne": user_id}})
        if existing:
            raise HTTPException(status_code=400, detail="Email already in use")
        update_data["email"] = email.lower()
    if phone:
        update_data["phone"] = phone
    if role:
        if role not in ROLES:
            raise HTTPException(status_code=400, detail="Invalid role")
        update_data["role"] = role
    if password:
        if len(password) < 6:
            raise HTTPException(status_code=400, detail="Password must be at least 6 characters")
        update_data["password_hash"] = hash_password(password)
    
    await db.users.update_one({"id": user_id}, {"$set": update_data})
    
    updated_user = await db.users.find_one({"id": user_id}, {"_id": 0, "password_hash": 0})
    return updated_user


@api_router.delete("/admin/users/{user_id}")
async def delete_user(
    user_id: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """Delete a user (admin only)"""
    # Check if user exists
    existing_user = await db.users.find_one({"id": user_id})
    if not existing_user:
        raise HTTPException(status_code=404, detail="User not found")
    
    # Prevent deleting yourself
    if user_id == user["id"]:
        raise HTTPException(status_code=400, detail="Cannot delete your own account")
    
    # Prevent deleting the last admin
    if existing_user.get("role") == "admin":
        admin_count = await db.users.count_documents({"role": "admin"})
        if admin_count <= 1:
            raise HTTPException(status_code=400, detail="Cannot delete the last admin user")
    
    # Delete the user
    await db.users.delete_one({"id": user_id})
    
    # Log the deletion
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "user_deleted",
        "entity_type": "user",
        "entity_id": user_id,
        "entity_name": f"{existing_user.get('first_name')} {existing_user.get('last_name')}",
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {
            "deleted_user_email": existing_user.get("email"),
            "deleted_user_role": existing_user.get("role")
        },
        "timestamp": datetime.now(timezone.utc).isoformat()
    })
    
    return {"message": "User deleted successfully", "user_id": user_id}


@api_router.get("/admin/agent-performance")
async def get_agent_performance(
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    user: dict = Depends(require_roles(["admin"]))
):
    """Get detailed agent performance analytics for team meetings"""
    # Get all agents (support, supervisor, technicians, accountants)
    agents = await db.users.find(
        {"role": {"$in": ["call_support", "supervisor", "service_agent", "accountant"]}},
        {"_id": 0, "id": 1, "first_name": 1, "last_name": 1, "role": 1, "email": 1}
    ).to_list(50)
    
    performance = []
    now = datetime.now(timezone.utc)
    
    for agent in agents:
        # Build query
        query = {"assigned_to": agent["id"]}
        if from_date:
            query["created_at"] = {"$gte": from_date}
        if to_date:
            if "created_at" in query:
                query["created_at"]["$lte"] = to_date
            else:
                query["created_at"] = {"$lte": to_date}
        
        # Get ticket stats
        total = await db.tickets.count_documents(query)
        closed = await db.tickets.count_documents({**query, "status": {"$in": ["closed", "closed_by_agent", "resolved_on_call"]}})
        hardware = await db.tickets.count_documents({**query, "support_type": "hardware"})
        phone = await db.tickets.count_documents({**query, "support_type": "phone"})
        sla_breached = await db.tickets.count_documents({**query, "sla_due": {"$lt": now.isoformat()}, "status": {"$nin": ["closed", "closed_by_agent", "resolved_on_call"]}})
        
        # Calculate average resolution time
        closed_tickets = await db.tickets.find(
            {**query, "closed_at": {"$ne": None}},
            {"_id": 0, "created_at": 1, "closed_at": 1}
        ).to_list(1000)
        
        avg_hours = 0
        if closed_tickets:
            total_hours = 0
            for t in closed_tickets:
                try:
                    created = datetime.fromisoformat(t["created_at"].replace('Z', '+00:00'))
                    closed_time = datetime.fromisoformat(t["closed_at"].replace('Z', '+00:00'))
                    total_hours += (closed_time - created).total_seconds() / 3600
                except:
                    pass
            avg_hours = total_hours / len(closed_tickets) if closed_tickets else 0
        
        sla_compliance = ((total - sla_breached) / total * 100) if total > 0 else 100
        
        performance.append(AgentPerformance(
            agent_id=agent["id"],
            agent_name=f"{agent['first_name']} {agent['last_name']}",
            total_tickets=total,
            closed_tickets=closed,
            hardware_tickets=hardware,
            phone_tickets=phone,
            sla_breaches=sla_breached,
            avg_resolution_hours=round(avg_hours, 2),
            sla_compliance_rate=round(sla_compliance, 2)
        ))
    
    return performance

@api_router.get("/admin/tickets")
async def get_all_tickets_admin(
    search: Optional[str] = None,
    status: Optional[str] = None,
    support_type: Optional[str] = None,
    sla_breached: Optional[bool] = None,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    page: int = 1,
    limit: int = 50,
    user: dict = Depends(require_roles(["admin"]))
):
    """Get all tickets for admin view with pagination"""
    query = {}
    
    if search:
        query["$or"] = [
            {"ticket_number": {"$regex": search, "$options": "i"}},
            {"customer_name": {"$regex": search, "$options": "i"}},
            {"customer_phone": {"$regex": search, "$options": "i"}},
            {"serial_number": {"$regex": search, "$options": "i"}}
        ]
    if status and status != "all":
        query["status"] = status
    if support_type and support_type != "all":
        query["support_type"] = support_type
    if from_date:
        query["created_at"] = {"$gte": from_date}
    if to_date:
        if "created_at" in query:
            query["created_at"]["$lte"] = to_date
        else:
            query["created_at"] = {"$lte": to_date}
    
    # Get total count first
    total_count = await db.tickets.count_documents(query)
    total_pages = (total_count + limit - 1) // limit
    
    skip = (page - 1) * limit
    tickets = await db.tickets.find(query, {"_id": 0}).sort("created_at", -1).skip(skip).limit(limit).to_list(limit)
    
    # Update SLA status
    now = datetime.now(timezone.utc)
    filtered_tickets = []
    for ticket in tickets:
        if ticket.get("sla_due"):
            try:
                sla_due = datetime.fromisoformat(ticket["sla_due"].replace('Z', '+00:00'))
                ticket["sla_breached"] = is_sla_breached(sla_due, ticket["status"])
            except:
                ticket["sla_breached"] = False
        else:
            ticket["sla_breached"] = False
        
        # Filter by SLA breach if requested
        if sla_breached is not None:
            if sla_breached == ticket.get("sla_breached", False):
                filtered_tickets.append(ticket)
        else:
            filtered_tickets.append(ticket)
    
    # If filtering by SLA breach, adjust total count
    if sla_breached is not None:
        # Need to recount with SLA filter (not efficient but accurate)
        all_for_sla = await db.tickets.find(query, {"_id": 0, "sla_due": 1, "status": 1}).to_list(10000)
        sla_count = 0
        for t in all_for_sla:
            if t.get("sla_due"):
                try:
                    sla_due = datetime.fromisoformat(t["sla_due"].replace('Z', '+00:00'))
                    is_breach = is_sla_breached(sla_due, t["status"])
                    if sla_breached == is_breach:
                        sla_count += 1
                except:
                    if not sla_breached:
                        sla_count += 1
            elif not sla_breached:
                sla_count += 1
        total_count = sla_count
        total_pages = (total_count + limit - 1) // limit
    
    return {
        "tickets": filtered_tickets if sla_breached is not None else tickets,
        "total": total_count,
        "page": page,
        "limit": limit,
        "total_pages": total_pages
    }

