# ==================== STOCK TRANSFER ENDPOINTS ====================

@api_router.post("/inventory/transfer", response_model=StockTransferResponse)
async def create_stock_transfer(
    transfer_data: StockTransferCreate,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Create an inter-firm stock transfer.
    This creates two ledger entries: transfer_out from source firm, transfer_in to destination firm.
    Invoice number is MANDATORY for GST compliance.
    """
    # Validate invoice number (MANDATORY)
    if not transfer_data.invoice_number or not transfer_data.invoice_number.strip():
        raise HTTPException(status_code=400, detail="Invoice number is MANDATORY for inter-firm transfers (GST compliance)")
    
    # Validate item type
    if transfer_data.item_type not in ["raw_material", "finished_good", "master_sku"]:
        raise HTTPException(status_code=400, detail="Item type must be 'raw_material', 'finished_good', or 'master_sku'")
    
    # Verify both firms exist and are active
    from_firm = await db.firms.find_one({"id": transfer_data.from_firm_id, "is_active": True})
    if not from_firm:
        raise HTTPException(status_code=400, detail="Source firm not found or inactive")
    
    to_firm = await db.firms.find_one({"id": transfer_data.to_firm_id, "is_active": True})
    if not to_firm:
        raise HTTPException(status_code=400, detail="Destination firm not found or inactive")
    
    if transfer_data.from_firm_id == transfer_data.to_firm_id:
        raise HTTPException(status_code=400, detail="Source and destination firm cannot be the same")
    
    # Get item details
    if transfer_data.item_type == "raw_material":
        # Raw materials are now global, no firm_id check
        item = await db.raw_materials.find_one({"id": transfer_data.item_id})
        if not item:
            raise HTTPException(status_code=400, detail="Raw material not found")
        item_name = item.get("name")
        item_sku = item.get("sku_code")
        dest_item_id = transfer_data.item_id  # Same item ID since raw materials are global
    elif transfer_data.item_type == "master_sku":
        item = await db.master_skus.find_one({"id": transfer_data.item_id})
        if not item:
            raise HTTPException(status_code=400, detail="Master SKU not found")
        item_name = item.get("name")
        item_sku = item.get("sku_code")
        dest_item_id = transfer_data.item_id
    else:  # finished_good
        item = await db.skus.find_one({"id": transfer_data.item_id})
        if not item:
            raise HTTPException(status_code=400, detail="SKU not found")
        item_name = item.get("model_name")
        item_sku = item.get("sku_code")
        dest_item_id = transfer_data.item_id  # Same SKU ID for finished goods
    
    # Check if source firm has sufficient stock
    current_stock = await get_current_stock(transfer_data.item_type, transfer_data.item_id, transfer_data.from_firm_id)
    if current_stock < transfer_data.quantity:
        raise HTTPException(
            status_code=400,
            detail=f"Insufficient stock in source firm. Available: {current_stock}, Requested: {transfer_data.quantity}"
        )
    
    # For manufactured items (master_sku with product_type='manufactured'), handle serial numbers
    serial_numbers_to_transfer = []
    if transfer_data.item_type == "master_sku" and item.get("product_type") == "manufactured":
        # Serial numbers are required for manufactured items
        if not transfer_data.serial_numbers or len(transfer_data.serial_numbers) == 0:
            raise HTTPException(
                status_code=400,
                detail="Serial numbers are required for manufactured item transfers"
            )
        if len(transfer_data.serial_numbers) != transfer_data.quantity:
            raise HTTPException(
                status_code=400,
                detail=f"Number of serial numbers ({len(transfer_data.serial_numbers)}) must match quantity ({transfer_data.quantity})"
            )
        
        # Verify all serial numbers exist and belong to source firm
        for serial in transfer_data.serial_numbers:
            serial_record = await db.finished_good_serials.find_one({
                "serial_number": serial,
                "master_sku_id": transfer_data.item_id,
                "firm_id": transfer_data.from_firm_id,
                "status": "in_stock"
            })
            if not serial_record:
                raise HTTPException(
                    status_code=400,
                    detail=f"Serial number {serial} not found in stock at source firm or not available"
                )
            serial_numbers_to_transfer.append(serial_record)
    
    transfer_id = str(uuid.uuid4())
    now = datetime.now(timezone.utc).isoformat()
    transfer_number = generate_transfer_number()
    
    # Create transfer_out entry for source firm
    out_entry_id = str(uuid.uuid4())
    out_running_balance = current_stock - transfer_data.quantity
    out_entry = {
        "id": out_entry_id,
        "entry_number": generate_ledger_entry_number(),
        "entry_type": "transfer_out",
        "item_type": transfer_data.item_type,
        "item_id": transfer_data.item_id,
        "item_name": item_name,
        "item_sku": item_sku,
        "firm_id": transfer_data.from_firm_id,
        "firm_name": from_firm.get("name"),
        "quantity": transfer_data.quantity,
        "running_balance": out_running_balance,
        "unit_price": None,
        "total_value": None,
        "invoice_number": transfer_data.invoice_number,
        "reason": f"Transfer to {to_firm.get('name')}",
        "reference_id": transfer_id,
        "notes": transfer_data.notes,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now
    }
    await db.inventory_ledger.insert_one(out_entry)
    
    # Update source firm stock
    await update_stock_from_ledger(transfer_data.item_type, transfer_data.item_id, transfer_data.from_firm_id)
    
    # Create transfer_in entry for destination firm
    dest_current_stock = await get_current_stock(transfer_data.item_type, dest_item_id, transfer_data.to_firm_id)
    in_entry_id = str(uuid.uuid4())
    in_running_balance = dest_current_stock + transfer_data.quantity
    in_entry = {
        "id": in_entry_id,
        "entry_number": generate_ledger_entry_number(),
        "entry_type": "transfer_in",
        "item_type": transfer_data.item_type,
        "item_id": dest_item_id,
        "item_name": item_name,
        "item_sku": item_sku,
        "firm_id": transfer_data.to_firm_id,
        "firm_name": to_firm.get("name"),
        "quantity": transfer_data.quantity,
        "running_balance": in_running_balance,
        "unit_price": None,
        "total_value": None,
        "invoice_number": transfer_data.invoice_number,
        "reason": f"Transfer from {from_firm.get('name')}",
        "reference_id": transfer_id,
        "notes": transfer_data.notes,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now
    }
    await db.inventory_ledger.insert_one(in_entry)
    
    # Update destination firm stock
    await update_stock_from_ledger(transfer_data.item_type, dest_item_id, transfer_data.to_firm_id)
    
    # Update serial numbers for manufactured items
    if serial_numbers_to_transfer:
        for serial_record in serial_numbers_to_transfer:
            await db.finished_good_serials.update_one(
                {"id": serial_record["id"]},
                {"$set": {
                    "firm_id": transfer_data.to_firm_id,
                    "firm_name": to_firm.get("name"),
                    "updated_at": now
                }}
            )
    
    # Determine unit price and total value
    unit_price = transfer_data.unit_price
    if unit_price is None and transfer_data.auto_create_entries:
        # Get cost price or last purchase price
        if transfer_data.item_type == "raw_material":
            unit_price = item.get("cost_price", 0) or 0
        else:
            unit_price = item.get("cost_price", 0) or (item.get("mrp", 0) * 0.5) or 0
        # Apply margin
        if transfer_data.margin_percentage and unit_price > 0:
            unit_price = round(unit_price * (1 + transfer_data.margin_percentage / 100), 2)
    
    total_value = round(unit_price * transfer_data.quantity, 2) if unit_price else None
    gst_rate = float(item.get("gst_rate", 18) or 18)
    hsn_code = item.get("hsn_code", "")
    
    # Create transfer record
    transfer_doc = {
        "id": transfer_id,
        "transfer_number": transfer_number,
        "item_type": transfer_data.item_type,
        "item_id": transfer_data.item_id,
        "item_name": item_name,
        "item_sku": item_sku,
        "hsn_code": hsn_code,
        "from_firm_id": transfer_data.from_firm_id,
        "from_firm_name": from_firm.get("name"),
        "to_firm_id": transfer_data.to_firm_id,
        "to_firm_name": to_firm.get("name"),
        "quantity": transfer_data.quantity,
        "unit_price": unit_price,
        "total_value": total_value,
        "margin_percentage": transfer_data.margin_percentage,
        "gst_rate": gst_rate,
        "serial_numbers": transfer_data.serial_numbers if transfer_data.serial_numbers else [],
        "invoice_number": transfer_data.invoice_number,
        "notes": transfer_data.notes,
        "ledger_out_id": out_entry_id,
        "ledger_in_id": in_entry_id,
        "sales_invoice_id": None,
        "purchase_entry_id": None,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now
    }
    
    # Auto-create Sales Invoice for From Firm and Purchase Entry for To Firm
    if transfer_data.auto_create_entries and unit_price and unit_price > 0:
        # Create Sales Invoice for the selling firm (from_firm)
        sales_invoice_id = str(uuid.uuid4())
        sales_invoice_number = f"INV-TRF-{datetime.now(timezone.utc).strftime('%Y%m%d')}-{str(uuid.uuid4())[:5].upper()}"
        
        gst_amount = round(total_value * gst_rate / 100, 2)
        grand_total = round(total_value + gst_amount, 2)
        
        # Create party record for the receiving firm if it doesn't exist
        to_firm_as_party = await db.parties.find_one({"gstin": to_firm.get("gstin")}, {"_id": 0})
        if not to_firm_as_party:
            to_firm_party_id = str(uuid.uuid4())
            to_firm_as_party = {
                "id": to_firm_party_id,
                "name": to_firm.get("name"),
                "gstin": to_firm.get("gstin"),
                "party_types": ["customer"],
                "address": to_firm.get("address"),
                "city": to_firm.get("city"),
                "state": to_firm.get("state"),
                "pincode": to_firm.get("pincode"),
                "is_inter_company": True,
                "linked_firm_id": to_firm.get("id"),
                "created_at": now
            }
            await db.parties.insert_one(to_firm_as_party)
        
        sales_invoice_doc = {
            "id": sales_invoice_id,
            "invoice_number": sales_invoice_number,
            "invoice_date": now[:10],
            "firm_id": transfer_data.from_firm_id,
            "firm_name": from_firm.get("name"),
            "firm_gstin": from_firm.get("gstin"),
            "party_id": to_firm_as_party.get("id"),
            "party_name": to_firm.get("name"),
            "party_gstin": to_firm.get("gstin"),
            "party_address": to_firm.get("address"),
            "is_inter_company_transfer": True,
            "transfer_id": transfer_id,
            "items": [{
                "item_id": transfer_data.item_id,
                "item_type": transfer_data.item_type,
                "master_sku_id": transfer_data.item_id if transfer_data.item_type == "master_sku" else None,
                "name": item_name,
                "sku_code": item_sku,
                "description": f"{item_name} ({item_sku})",
                "hsn_code": hsn_code,
                "quantity": transfer_data.quantity,
                "rate": unit_price,
                "unit_price": unit_price,
                "gst_rate": gst_rate,
                "discount": 0,
                "taxable_value": total_value,
                "amount": total_value,
                "gst_amount": gst_amount
            }],
            "subtotal": total_value,
            "taxable_value": total_value,
            "is_igst": True,  # Inter-company transfers are typically IGST
            "igst": gst_amount,
            "cgst": 0,
            "sgst": 0,
            "total_gst": gst_amount,
            "gst_amount": gst_amount,
            "grand_total": grand_total,
            "total_amount": grand_total,
            "payment_status": "unpaid",
            "amount_paid": 0,
            "balance_due": grand_total,
            "status": "final",
            "doc_status": "complete",
            "source": "inter_company_transfer",
            "notes": f"Auto-generated from inter-company transfer {transfer_number}",
            "created_by": user["id"],
            "created_by_name": f"{user['first_name']} {user['last_name']}",
            "created_at": now
        }
        await db.sales_invoices.insert_one(sales_invoice_doc)
        transfer_doc["sales_invoice_id"] = sales_invoice_id
        
        # Create Purchase Entry for the receiving firm (to_firm)
        purchase_entry_id = str(uuid.uuid4())
        purchase_number = f"PUR-TRF-{datetime.now(timezone.utc).strftime('%Y%m%d')}-{str(uuid.uuid4())[:5].upper()}"
        
        # Create party record for the selling firm if it doesn't exist
        from_firm_as_party = await db.parties.find_one({"gstin": from_firm.get("gstin")}, {"_id": 0})
        if not from_firm_as_party:
            from_firm_party_id = str(uuid.uuid4())
            from_firm_as_party = {
                "id": from_firm_party_id,
                "name": from_firm.get("name"),
                "gstin": from_firm.get("gstin"),
                "party_types": ["supplier"],
                "address": from_firm.get("address"),
                "city": from_firm.get("city"),
                "state": from_firm.get("state"),
                "pincode": from_firm.get("pincode"),
                "is_inter_company": True,
                "linked_firm_id": from_firm.get("id"),
                "created_at": now
            }
            await db.parties.insert_one(from_firm_as_party)
        
        purchase_doc = {
            "id": purchase_entry_id,
            "purchase_number": purchase_number,
            "invoice_number": transfer_data.invoice_number,
            "invoice_date": now[:10],
            "firm_id": transfer_data.to_firm_id,
            "firm_name": to_firm.get("name"),
            "firm_gstin": to_firm.get("gstin"),
            "supplier_id": from_firm_as_party.get("id"),
            "supplier_name": from_firm.get("name"),
            "supplier_gstin": from_firm.get("gstin"),
            "supplier_state": from_firm.get("state"),
            "supplier_address": from_firm.get("address"),
            "is_inter_company_transfer": True,
            "is_inter_state": True,
            "transfer_id": transfer_id,
            "items": [{
                "item_id": transfer_data.item_id,
                "item_type": transfer_data.item_type,
                "item_name": item_name,
                "name": item_name,
                "sku_code": item_sku,
                "description": f"{item_name} ({item_sku})",
                "hsn_code": hsn_code,
                "quantity": transfer_data.quantity,
                "rate": unit_price,
                "unit_price": unit_price,
                "gst_rate": gst_rate,
                "taxable_value": total_value,
                "igst": gst_amount,
                "cgst": 0,
                "sgst": 0,
                "total": grand_total,
                "amount": total_value
            }],
            "total_taxable": total_value,
            "total_igst": gst_amount,
            "total_cgst": 0,
            "total_sgst": 0,
            "total_gst": gst_amount,
            "total_amount": grand_total,
            "totals": {
                "subtotal": total_value,
                "taxable_value": total_value,
                "gst_amount": gst_amount,
                "total_gst": gst_amount,
                "grand_total": grand_total
            },
            "payment_status": "unpaid",
            "amount_paid": 0,
            "balance_due": grand_total,
            "status": "final",
            "doc_status": "complete",
            "source": "inter_company_transfer",
            "notes": f"Auto-generated from inter-company transfer {transfer_number}",
            "created_by": user["id"],
            "created_by_name": f"{user['first_name']} {user['last_name']}",
            "created_at": now
        }
        await db.purchases.insert_one(purchase_doc)
        transfer_doc["purchase_entry_id"] = purchase_entry_id
    
    await db.stock_transfers.insert_one(transfer_doc)
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "stock_transfer",
        "entity_type": "stock_transfer",
        "entity_id": transfer_id,
        "entity_name": transfer_number,
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "performed_by_role": user.get("role"),
        "details": {
            "item_name": item_name,
            "quantity": transfer_data.quantity,
            "from_firm": from_firm.get("name"),
            "to_firm": to_firm.get("name"),
            "invoice_number": transfer_data.invoice_number,
            "serial_numbers": transfer_data.serial_numbers if transfer_data.serial_numbers else []
        },
        "timestamp": now
    })
    
    return StockTransferResponse(**{k: v for k, v in transfer_doc.items() if k != "_id"})

@api_router.get("/inventory/transfers", response_model=List[StockTransferResponse])
async def list_stock_transfers(
    firm_id: Optional[str] = None,
    limit: int = Query(100, le=500),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """List stock transfers"""
    query = {}
    if firm_id:
        query["$or"] = [{"from_firm_id": firm_id}, {"to_firm_id": firm_id}]
    
    transfers = await db.stock_transfers.find(query, {"_id": 0}).sort("created_at", -1).to_list(limit)
    return transfers

@api_router.get("/inventory/transfer-pricing/{item_type}/{item_id}")
async def get_transfer_pricing_info(
    item_type: str,
    item_id: str,
    from_firm_id: str,
    quantity: int = 1,
    margin_percentage: float = Query(15.0, ge=0, le=100),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Get pricing suggestions for inter-firm transfer.
    Returns cost price, suggested transfer price with margin, and stock availability.
    """
    # Get item details and cost price
    if item_type == "raw_material":
        item = await db.raw_materials.find_one({"id": item_id}, {"_id": 0})
        if not item:
            raise HTTPException(status_code=404, detail="Raw material not found")
        item_name = item.get("name")
        item_sku = item.get("sku_code")
        cost_price = item.get("cost_price", 0) or 0
        gst_rate = float(item.get("gst_rate", 18) or 18)
        hsn_code = item.get("hsn_code", "")
    elif item_type == "master_sku":
        item = await db.master_skus.find_one({"id": item_id}, {"_id": 0})
        if not item:
            raise HTTPException(status_code=404, detail="Master SKU not found")
        item_name = item.get("name")
        item_sku = item.get("sku_code")
        mrp = item.get("mrp", 0) or 0
        cost_price = item.get("cost_price", 0) or (mrp * 0.5 if mrp else 0)  # Fallback to 50% of MRP
        gst_rate = float(item.get("gst_rate", 18) or 18)
        hsn_code = item.get("hsn_code", "")
    else:
        raise HTTPException(status_code=400, detail="Invalid item type. Use 'raw_material' or 'master_sku'")
    
    # Get last purchase price if available
    last_purchase = await db.inventory_ledger.find_one(
        {"item_id": item_id, "firm_id": from_firm_id, "entry_type": "purchase", "unit_price": {"$gt": 0}},
        {"_id": 0},
        sort=[("created_at", -1)]
    )
    last_purchase_price = last_purchase.get("unit_price") if last_purchase else None
    
    # Use best available price for calculations
    base_price = last_purchase_price or cost_price or 0
    
    # Calculate suggested transfer price with margin
    suggested_price = round(base_price * (1 + margin_percentage / 100), 2) if base_price > 0 else 0
    
    # Get current stock at source firm
    current_stock = await get_current_stock(item_type, item_id, from_firm_id)
    
    # Calculate totals
    total_base_value = round(base_price * quantity, 2)
    total_transfer_value = round(suggested_price * quantity, 2)
    margin_amount = round(total_transfer_value - total_base_value, 2)
    
    # Calculate GST
    gst_amount = round(total_transfer_value * gst_rate / 100, 2)
    grand_total = round(total_transfer_value + gst_amount, 2)
    
    return {
        "item_id": item_id,
        "item_type": item_type,
        "item_name": item_name,
        "item_sku": item_sku,
        "hsn_code": hsn_code,
        "gst_rate": gst_rate,
        "current_stock": current_stock,
        "cost_price": cost_price,
        "last_purchase_price": last_purchase_price,
        "base_price": base_price,
        "margin_percentage": margin_percentage,
        "suggested_unit_price": suggested_price,
        "quantity": quantity,
        "total_base_value": total_base_value,
        "total_transfer_value": total_transfer_value,
        "margin_amount": margin_amount,
        "gst_amount": gst_amount,
        "grand_total": grand_total
    }

@api_router.get("/inventory/transfers/{transfer_id}", response_model=StockTransferResponse)
async def get_stock_transfer(
    transfer_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get a specific stock transfer"""
    transfer = await db.stock_transfers.find_one({"id": transfer_id}, {"_id": 0})
    if not transfer:
        raise HTTPException(status_code=404, detail="Stock transfer not found")
    return transfer

