@api_router.get("/inventory/stock")
async def get_inventory_stock(
    firm_id: Optional[str] = None,
    item_type: Optional[str] = None,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get current stock levels across firms - includes all Master SKUs for all firms"""
    result = {
        "raw_materials": [],
        "finished_goods": [],
        "master_skus": [],  # New: Master SKUs with per-firm stock
        "summary": {
            "total_raw_materials": 0,
            "total_finished_goods": 0,
            "total_master_skus": 0,
            "low_stock_alerts": 0,
            "negative_stock_alerts": 0
        }
    }
    
    # Get all active firms
    firm_query = {"is_active": True}
    if firm_id:
        firm_query["id"] = firm_id
    firms = await db.firms.find(firm_query, {"_id": 0}).to_list(100)
    firm_map = {f["id"]: f for f in firms}
    
    # Get raw materials (now firm-agnostic, stock per firm from ledger)
    if not item_type or item_type == "raw_material":
        raw_materials = await db.raw_materials.find({"is_active": True}, {"_id": 0}).to_list(1000)
        
        for rm in raw_materials:
            # For each raw material, show stock per firm
            for firm in firms:
                last_entry = await db.inventory_ledger.find_one(
                    {"item_id": rm["id"], "firm_id": firm["id"], "item_type": "raw_material"},
                    sort=[("created_at", -1)]
                )
                stock = last_entry.get("running_balance", 0) if last_entry else 0
                
                is_low = stock <= rm.get("reorder_level", 0)
                is_negative = stock < 0
                
                result["raw_materials"].append({
                    "id": rm["id"],
                    "item_id": rm["id"],  # For consistency with ledger entries
                    "name": rm.get("name"),
                    "sku_code": rm.get("sku_code"),
                    "unit": rm.get("unit"),
                    "hsn_code": rm.get("hsn_code"),
                    "reorder_level": rm.get("reorder_level", 10),
                    "firm_id": firm["id"],
                    "firm_name": firm.get("name"),
                    "current_stock": stock,
                    "is_low_stock": is_low,
                    "is_negative": is_negative
                })
                
                if is_low:
                    result["summary"]["low_stock_alerts"] += 1
                if is_negative:
                    result["summary"]["negative_stock_alerts"] += 1
        
        result["summary"]["total_raw_materials"] = len(raw_materials)
    
    # Get finished goods (old SKUs - for backward compatibility)
    if not item_type or item_type == "finished_good":
        sku_query = {"active": True}
        if firm_id:
            sku_query["firm_id"] = firm_id
        skus = await db.skus.find(sku_query, {"_id": 0}).to_list(1000)
        
        for sku in skus:
            firm = firm_map.get(sku.get("firm_id"), {})
            sku["firm_name"] = firm.get("name")
            sku["is_low_stock"] = sku.get("stock_quantity", 0) <= sku.get("min_stock_alert", 0)
            sku["is_negative"] = sku.get("stock_quantity", 0) < 0
            result["finished_goods"].append(sku)
            
            if sku["is_low_stock"]:
                result["summary"]["low_stock_alerts"] += 1
            if sku["is_negative"]:
                result["summary"]["negative_stock_alerts"] += 1
        
        result["summary"]["total_finished_goods"] = len(skus)
    
    # Get Master SKUs - show ALL Master SKUs for ALL firms (even with zero stock)
    if not item_type or item_type == "master_sku":
        master_skus = await db.master_skus.find({"is_active": True}, {"_id": 0}).to_list(10000)
        
        for sku in master_skus:
            is_manufactured = sku.get("product_type") == "manufactured"
            
            # For each Master SKU, create an entry for each firm
            for firm in firms:
                if is_manufactured:
                    # For manufactured items, count stock from finished_good_serials
                    in_stock_serials = await db.finished_good_serials.find(
                        {"master_sku_id": sku["id"], "firm_id": firm["id"], "status": "in_stock"},
                        {"_id": 0, "serial_number": 1, "manufactured_at": 1, "notes": 1}
                    ).to_list(10000)
                    stock = len(in_stock_serials)
                    serial_numbers = [s["serial_number"] for s in in_stock_serials]
                else:
                    # For traded items, use ledger balance
                    last_entry = await db.inventory_ledger.find_one(
                        {"item_id": sku["id"], "firm_id": firm["id"], "item_type": "master_sku"},
                        sort=[("created_at", -1)]
                    )
                    stock = last_entry.get("running_balance", 0) if last_entry else 0
                    serial_numbers = []
                
                is_low = stock <= sku.get("reorder_level", 10)
                is_negative = stock < 0
                
                result["master_skus"].append({
                    "id": sku["id"],
                    "item_id": sku["id"],  # For consistency with ledger entries
                    "name": sku.get("name"),
                    "sku_code": sku.get("sku_code"),
                    "category": sku.get("category"),
                    "hsn_code": sku.get("hsn_code"),
                    "unit": sku.get("unit", "pcs"),
                    "is_manufactured": sku.get("is_manufactured", False),
                    "product_type": sku.get("product_type"),
                    "manufacturing_role": sku.get("manufacturing_role"),
                    "has_bom": len(sku.get("bill_of_materials", [])) > 0,
                    "aliases_count": len(sku.get("aliases", [])),
                    "reorder_level": sku.get("reorder_level", 10),
                    "firm_id": firm["id"],
                    "firm_name": firm.get("name"),
                    "current_stock": stock,
                    "serial_numbers": serial_numbers if is_manufactured else [],
                    "is_low_stock": is_low,
                    "is_negative": is_negative
                })
                
                if is_low:
                    result["summary"]["low_stock_alerts"] += 1
                if is_negative:
                    result["summary"]["negative_stock_alerts"] += 1
        
        result["summary"]["total_master_skus"] = len(master_skus)
    
    return result

@api_router.get("/inventory/stock-by-firm")
async def get_stock_by_firm(
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get stock summary grouped by firm"""
    firms = await db.firms.find({"is_active": True}, {"_id": 0}).to_list(100)
    
    result = []
    for firm in firms:
        firm_data = {
            "firm_id": firm["id"],
            "firm_name": firm["name"],
            "gstin": firm["gstin"],
            "raw_materials_count": 0,
            "raw_materials_value": 0,
            "finished_goods_count": 0,
            "finished_goods_value": 0,
            "low_stock_items": 0
        }
        
        # Count raw materials
        rm_count = await db.raw_materials.count_documents({"firm_id": firm["id"], "is_active": True})
        firm_data["raw_materials_count"] = rm_count
        
        # Get raw materials stock
        raw_materials = await db.raw_materials.find(
            {"firm_id": firm["id"], "is_active": True},
            {"_id": 0, "current_stock": 1, "reorder_level": 1}
        ).to_list(1000)
        
        for rm in raw_materials:
            if rm.get("current_stock", 0) <= rm.get("reorder_level", 0):
                firm_data["low_stock_items"] += 1
        
        # Count finished goods for this firm
        fg_count = await db.skus.count_documents({"firm_id": firm["id"], "active": True})
        firm_data["finished_goods_count"] = fg_count
        
        skus = await db.skus.find(
            {"firm_id": firm["id"], "active": True},
            {"_id": 0, "stock_quantity": 1, "min_stock_alert": 1}
        ).to_list(1000)
        
        for sku in skus:
            if sku.get("stock_quantity", 0) <= sku.get("min_stock_alert", 0):
                firm_data["low_stock_items"] += 1
        
        result.append(firm_data)
    
    return result

# ==================== STOCK MOVEMENT REPORTS ====================

@api_router.get("/reports/stock-ledger")
async def get_stock_ledger_report(
    firm_id: Optional[str] = None,
    item_type: Optional[str] = None,
    item_id: Optional[str] = None,
    entry_type: Optional[str] = None,
    created_by: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    limit: int = Query(500, le=2000),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Stock Ledger Report - All inventory movements
    Filters: date range, firm, item/SKU, ledger type, user
    """
    query = {}
    
    if firm_id:
        query["firm_id"] = firm_id
    if item_type:
        query["item_type"] = item_type
    if item_id:
        query["item_id"] = item_id
    if entry_type:
        query["entry_type"] = entry_type
    if created_by:
        query["created_by"] = created_by
    
    # Date range filter
    if date_from or date_to:
        date_query = {}
        if date_from:
            date_query["$gte"] = date_from
        if date_to:
            date_query["$lte"] = date_to + "T23:59:59"
        query["created_at"] = date_query
    
    entries = await db.inventory_ledger.find(query, {"_id": 0}).sort("created_at", -1).to_list(limit)
    
    # Calculate totals
    totals = {
        "total_entries": len(entries),
        "total_in": 0,
        "total_out": 0,
        "by_entry_type": {},
        "by_firm": {}
    }
    
    for entry in entries:
        qty = entry.get("quantity", 0)
        entry_type_val = entry.get("entry_type")
        firm_name = entry.get("firm_name", "Unknown")
        
        # Count by entry type
        if entry_type_val not in totals["by_entry_type"]:
            totals["by_entry_type"][entry_type_val] = {"count": 0, "quantity": 0}
        totals["by_entry_type"][entry_type_val]["count"] += 1
        totals["by_entry_type"][entry_type_val]["quantity"] += qty
        
        # Count by firm
        if firm_name not in totals["by_firm"]:
            totals["by_firm"][firm_name] = {"count": 0, "in_qty": 0, "out_qty": 0}
        totals["by_firm"][firm_name]["count"] += 1
        
        # In/Out totals
        if entry_type_val in ["purchase", "transfer_in", "adjustment_in", "return_in", "repair_yard_in"]:
            totals["total_in"] += qty
            totals["by_firm"][firm_name]["in_qty"] += qty
        else:
            totals["total_out"] += qty
            totals["by_firm"][firm_name]["out_qty"] += qty
    
    return {
        "entries": entries,
        "totals": totals,
        "filters_applied": {
            "firm_id": firm_id,
            "item_type": item_type,
            "item_id": item_id,
            "entry_type": entry_type,
            "created_by": created_by,
            "date_from": date_from,
            "date_to": date_to
        }
    }

@api_router.get("/reports/current-stock")
async def get_current_stock_report(
    firm_id: Optional[str] = None,
    item_type: Optional[str] = None,
    low_stock_only: bool = False,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Current Stock Report - Firm-wise stock levels
    Shows: raw materials and finished goods separately, low stock / reorder alerts
    """
    result = {
        "raw_materials": [],
        "finished_goods": [],
        "firms_summary": [],
        "totals": {
            "total_raw_materials": 0,
            "total_finished_goods": 0,
            "low_stock_count": 0,
            "negative_stock_count": 0
        }
    }
    
    # Get all active firms
    firm_query = {"is_active": True}
    if firm_id:
        firm_query["id"] = firm_id
    firms = await db.firms.find(firm_query, {"_id": 0}).to_list(100)
    firm_map = {f["id"]: f for f in firms}
    
    # Process each firm
    for firm in firms:
        firm_summary = {
            "firm_id": firm["id"],
            "firm_name": firm["name"],
            "gstin": firm["gstin"],
            "raw_materials_count": 0,
            "raw_materials_qty": 0,
            "finished_goods_count": 0,
            "finished_goods_qty": 0,
            "low_stock_items": [],
            "negative_stock_items": []
        }
        
        # Raw materials for this firm
        if not item_type or item_type == "raw_material":
            rm_query = {"firm_id": firm["id"], "is_active": True}
            raw_materials = await db.raw_materials.find(rm_query, {"_id": 0}).to_list(1000)
            
            for rm in raw_materials:
                rm["firm_name"] = firm["name"]
                rm["is_low_stock"] = rm.get("current_stock", 0) <= rm.get("reorder_level", 0)
                rm["is_negative"] = rm.get("current_stock", 0) < 0
                
                if low_stock_only and not (rm["is_low_stock"] or rm["is_negative"]):
                    continue
                
                result["raw_materials"].append(rm)
                firm_summary["raw_materials_count"] += 1
                firm_summary["raw_materials_qty"] += rm.get("current_stock", 0)
                
                if rm["is_low_stock"]:
                    firm_summary["low_stock_items"].append(rm["sku_code"])
                    result["totals"]["low_stock_count"] += 1
                if rm["is_negative"]:
                    firm_summary["negative_stock_items"].append(rm["sku_code"])
                    result["totals"]["negative_stock_count"] += 1
        
        # Finished goods for this firm
        if not item_type or item_type == "finished_good":
            sku_query = {"firm_id": firm["id"], "active": True}
            skus = await db.skus.find(sku_query, {"_id": 0}).to_list(1000)
            
            for sku in skus:
                sku["firm_name"] = firm["name"]
                sku["is_low_stock"] = sku.get("stock_quantity", 0) <= sku.get("min_stock_alert", 0)
                sku["is_negative"] = sku.get("stock_quantity", 0) < 0
                
                if low_stock_only and not (sku["is_low_stock"] or sku["is_negative"]):
                    continue
                
                result["finished_goods"].append(sku)
                firm_summary["finished_goods_count"] += 1
                firm_summary["finished_goods_qty"] += sku.get("stock_quantity", 0)
                
                if sku["is_low_stock"]:
                    firm_summary["low_stock_items"].append(sku["sku_code"])
                    result["totals"]["low_stock_count"] += 1
                if sku["is_negative"]:
                    firm_summary["negative_stock_items"].append(sku["sku_code"])
                    result["totals"]["negative_stock_count"] += 1
        
        result["firms_summary"].append(firm_summary)
    
    result["totals"]["total_raw_materials"] = len(result["raw_materials"])
    result["totals"]["total_finished_goods"] = len(result["finished_goods"])
    
    return result

@api_router.get("/reports/transfers")
async def get_transfer_report(
    from_firm_id: Optional[str] = None,
    to_firm_id: Optional[str] = None,
    item_id: Optional[str] = None,
    invoice_number: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    limit: int = Query(500, le=2000),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Transfer Report - Inter-firm stock transfers
    Filters: source firm, destination firm, invoice number, item, date
    """
    query = {}
    
    if from_firm_id:
        query["from_firm_id"] = from_firm_id
    if to_firm_id:
        query["to_firm_id"] = to_firm_id
    if item_id:
        query["item_id"] = item_id
    if invoice_number:
        query["invoice_number"] = {"$regex": invoice_number, "$options": "i"}
    
    # Date range filter
    if date_from or date_to:
        date_query = {}
        if date_from:
            date_query["$gte"] = date_from
        if date_to:
            date_query["$lte"] = date_to + "T23:59:59"
        query["created_at"] = date_query
    
    transfers = await db.stock_transfers.find(query, {"_id": 0}).sort("created_at", -1).to_list(limit)
    
    # Calculate totals
    totals = {
        "total_transfers": len(transfers),
        "total_quantity": sum(t.get("quantity", 0) for t in transfers),
        "by_source_firm": {},
        "by_dest_firm": {}
    }
    
    for transfer in transfers:
        src = transfer.get("from_firm_name", "Unknown")
        dest = transfer.get("to_firm_name", "Unknown")
        qty = transfer.get("quantity", 0)
        
        if src not in totals["by_source_firm"]:
            totals["by_source_firm"][src] = {"count": 0, "quantity": 0}
        totals["by_source_firm"][src]["count"] += 1
        totals["by_source_firm"][src]["quantity"] += qty
        
        if dest not in totals["by_dest_firm"]:
            totals["by_dest_firm"][dest] = {"count": 0, "quantity": 0}
        totals["by_dest_firm"][dest]["count"] += 1
        totals["by_dest_firm"][dest]["quantity"] += qty
    
    return {
        "transfers": transfers,
        "totals": totals
    }

@api_router.get("/reports/dispatch-return")
async def get_dispatch_return_report(
    firm_id: Optional[str] = None,
    item_id: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    limit: int = Query(500, le=2000),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Dispatch and Return Report
    Shows: dispatch_out and return_in entries with linked references
    """
    query = {"entry_type": {"$in": ["dispatch_out", "return_in"]}}
    
    if firm_id:
        query["firm_id"] = firm_id
    if item_id:
        query["item_id"] = item_id
    
    # Date range filter
    if date_from or date_to:
        date_query = {}
        if date_from:
            date_query["$gte"] = date_from
        if date_to:
            date_query["$lte"] = date_to + "T23:59:59"
        query["created_at"] = date_query
    
    entries = await db.inventory_ledger.find(query, {"_id": 0}).sort("created_at", -1).to_list(limit)
    
    # Separate dispatches and returns
    dispatches = [e for e in entries if e.get("entry_type") == "dispatch_out"]
    returns = [e for e in entries if e.get("entry_type") == "return_in"]
    
    totals = {
        "total_dispatched": sum(e.get("quantity", 0) for e in dispatches),
        "total_returned": sum(e.get("quantity", 0) for e in returns),
        "dispatch_count": len(dispatches),
        "return_count": len(returns),
        "net_out": sum(e.get("quantity", 0) for e in dispatches) - sum(e.get("quantity", 0) for e in returns)
    }
    
    return {
        "dispatches": dispatches,
        "returns": returns,
        "totals": totals
    }

@api_router.get("/reports/adjustments")
async def get_adjustment_report(
    firm_id: Optional[str] = None,
    item_id: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    limit: int = Query(500, le=2000),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Adjustment and Repair-Yard Report
    Shows: adjustment_in, adjustment_out, repair_yard_in with mandatory reasons visible
    """
    query = {"entry_type": {"$in": ["adjustment_in", "adjustment_out", "repair_yard_in"]}}
    
    if firm_id:
        query["firm_id"] = firm_id
    if item_id:
        query["item_id"] = item_id
    
    # Date range filter
    if date_from or date_to:
        date_query = {}
        if date_from:
            date_query["$gte"] = date_from
        if date_to:
            date_query["$lte"] = date_to + "T23:59:59"
        query["created_at"] = date_query
    
    entries = await db.inventory_ledger.find(query, {"_id": 0}).sort("created_at", -1).to_list(limit)
    
    # Separate by type
    adjustments_in = [e for e in entries if e.get("entry_type") == "adjustment_in"]
    adjustments_out = [e for e in entries if e.get("entry_type") == "adjustment_out"]
    repair_yard = [e for e in entries if e.get("entry_type") == "repair_yard_in"]
    
    totals = {
        "adjustment_in_qty": sum(e.get("quantity", 0) for e in adjustments_in),
        "adjustment_out_qty": sum(e.get("quantity", 0) for e in adjustments_out),
        "repair_yard_qty": sum(e.get("quantity", 0) for e in repair_yard),
        "adjustment_in_count": len(adjustments_in),
        "adjustment_out_count": len(adjustments_out),
        "repair_yard_count": len(repair_yard),
        "net_adjustment": (
            sum(e.get("quantity", 0) for e in adjustments_in) + 
            sum(e.get("quantity", 0) for e in repair_yard) - 
            sum(e.get("quantity", 0) for e in adjustments_out)
        )
    }
    
    return {
        "adjustments_in": adjustments_in,
        "adjustments_out": adjustments_out,
        "repair_yard": repair_yard,
        "all_entries": entries,
        "totals": totals
    }

@api_router.get("/reports/export/csv")
async def export_report_csv(
    report_type: str = Query(..., description="ledger, stock, transfers, dispatch_return, adjustments"),
    firm_id: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Export report data as CSV"""
    import io
    import csv
    from fastapi.responses import StreamingResponse
    
    output = io.StringIO()
    writer = csv.writer(output)
    
    if report_type == "ledger":
        # Get ledger data
        query = {}
        if firm_id:
            query["firm_id"] = firm_id
        if date_from or date_to:
            date_query = {}
            if date_from:
                date_query["$gte"] = date_from
            if date_to:
                date_query["$lte"] = date_to + "T23:59:59"
            query["created_at"] = date_query
        
        entries = await db.inventory_ledger.find(query, {"_id": 0}).sort("created_at", -1).to_list(5000)
        
        # Write header
        writer.writerow([
            "Entry Number", "Date", "Type", "Item SKU", "Item Name", "Firm", 
            "Quantity", "Running Balance", "Unit Price", "Total Value",
            "Invoice/Ref", "Reason", "Created By"
        ])
        
        # Write data
        for e in entries:
            writer.writerow([
                e.get("entry_number"),
                e.get("created_at", "")[:10],
                e.get("entry_type"),
                e.get("item_sku"),
                e.get("item_name"),
                e.get("firm_name"),
                e.get("quantity"),
                e.get("running_balance"),
                e.get("unit_price", ""),
                e.get("total_value", ""),
                e.get("invoice_number", ""),
                e.get("reason", ""),
                e.get("created_by_name")
            ])
    
    elif report_type == "stock":
        # Current stock
        firms = await db.firms.find({"is_active": True}, {"_id": 0}).to_list(100)
        
        writer.writerow([
            "Firm", "GSTIN", "Item Type", "SKU Code", "Item Name", 
            "Current Stock", "Reorder Level", "Status"
        ])
        
        for firm in firms:
            # Raw materials
            rms = await db.raw_materials.find({"firm_id": firm["id"], "is_active": True}, {"_id": 0}).to_list(1000)
            for rm in rms:
                status = "OK"
                if rm.get("current_stock", 0) < 0:
                    status = "NEGATIVE"
                elif rm.get("current_stock", 0) <= rm.get("reorder_level", 0):
                    status = "LOW"
                writer.writerow([
                    firm["name"], firm["gstin"], "Raw Material",
                    rm.get("sku_code"), rm.get("name"),
                    rm.get("current_stock", 0), rm.get("reorder_level"),
                    status
                ])
            
            # SKUs
            skus = await db.skus.find({"firm_id": firm["id"], "active": True}, {"_id": 0}).to_list(1000)
            for sku in skus:
                status = "OK"
                if sku.get("stock_quantity", 0) < 0:
                    status = "NEGATIVE"
                elif sku.get("stock_quantity", 0) <= sku.get("min_stock_alert", 0):
                    status = "LOW"
                writer.writerow([
                    firm["name"], firm["gstin"], "Finished Good",
                    sku.get("sku_code"), sku.get("model_name"),
                    sku.get("stock_quantity", 0), sku.get("min_stock_alert"),
                    status
                ])
    
    elif report_type == "transfers":
        query = {}
        if firm_id:
            query["$or"] = [{"from_firm_id": firm_id}, {"to_firm_id": firm_id}]
        if date_from or date_to:
            date_query = {}
            if date_from:
                date_query["$gte"] = date_from
            if date_to:
                date_query["$lte"] = date_to + "T23:59:59"
            query["created_at"] = date_query
        
        transfers = await db.stock_transfers.find(query, {"_id": 0}).to_list(5000)
        
        writer.writerow([
            "Transfer Number", "Date", "Item SKU", "Item Name",
            "From Firm", "To Firm", "Quantity", "Invoice Number", "Created By"
        ])
        
        for t in transfers:
            writer.writerow([
                t.get("transfer_number"),
                t.get("created_at", "")[:10],
                t.get("item_sku"),
                t.get("item_name"),
                t.get("from_firm_name"),
                t.get("to_firm_name"),
                t.get("quantity"),
                t.get("invoice_number"),
                t.get("created_by_name")
            ])
    
    else:
        writer.writerow(["Error", "Invalid report type"])
    
    output.seek(0)
    
    return StreamingResponse(
        iter([output.getvalue()]),
        media_type="text/csv",
        headers={"Content-Disposition": f"attachment; filename={report_type}_report.csv"}
    )

# ==================== PENDING FULFILLMENT QUEUE (AMAZON ORDERS) ====================

@api_router.get("/pending-fulfillment/check-unique")
async def check_pending_fulfillment_unique(
    order_id: Optional[str] = Query(None),
    tracking_id: Optional[str] = Query(None),
    invoice_number: Optional[str] = Query(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Check if order_id, tracking_id, or invoice_number already exists across all relevant tables"""
    
    # Use centralized duplicate validation utilities
    if tracking_id:
        result = await check_tracking_id_duplicate(tracking_id)
        if result["exists"]:
            return {"exists": True, "field": "tracking_id", "source": result["source"], "message": result["message"], "details": result.get("details", {})}
    
    if order_id:
        result = await check_order_id_duplicate(order_id)
        if result["exists"]:
            return {"exists": True, "field": "order_id", "source": result["source"], "message": result["message"], "details": result.get("details", {})}
    
    if invoice_number:
        result = await check_invoice_number_duplicate(invoice_number)
        if result["exists"]:
            return {"exists": True, "field": "invoice_number", "source": result["source"], "message": result["message"], "details": result.get("details", {})}
    
    return {"exists": False}


@api_router.get("/pending-fulfillment/phone-history")
async def get_phone_order_history(
    phone: str = Query(..., min_length=10),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get previous orders for a phone number across all tables"""
    results = []
    phone_regex = phone[-10:]  # Last 10 digits
    
    # Search in pending fulfillment
    pf_cursor = db.pending_fulfillment.find(
        {"customer_phone": {"$regex": phone_regex, "$options": "i"}},
        {"_id": 0, "order_id": 1, "tracking_id": 1, "customer_name": 1, "status": 1, "created_at": 1}
    ).sort("created_at", -1).limit(5)
    pf_results = await pf_cursor.to_list(length=5)
    for r in pf_results:
        r["source"] = "pending_fulfillment"
    results.extend(pf_results)
    
    # Search in dispatches
    dispatch_cursor = db.dispatches.find(
        {"customer_phone": {"$regex": phone_regex, "$options": "i"}},
        {"_id": 0, "dispatch_number": 1, "tracking_id": 1, "customer_name": 1, "status": 1, "created_at": 1}
    ).sort("created_at", -1).limit(5)
    dispatch_results = await dispatch_cursor.to_list(length=5)
    for d in dispatch_results:
        d["order_id"] = d.pop("dispatch_number", "N/A")
        d["source"] = "dispatch"
    results.extend(dispatch_results)
    
    # Search in tickets (sales/service orders)
    ticket_cursor = db.tickets.find(
        {"customer_phone": {"$regex": phone_regex, "$options": "i"}},
        {"_id": 0, "ticket_number": 1, "order_id": 1, "customer_name": 1, "status": 1, "created_at": 1}
    ).sort("created_at", -1).limit(5)
    ticket_results = await ticket_cursor.to_list(length=5)
    for t in ticket_results:
        t["order_id"] = t.get("order_id") or t.pop("ticket_number", "N/A")
        t["source"] = "ticket"
    results.extend(ticket_results)
    
    # Sort by date and return top 10
    results.sort(key=lambda x: x.get("created_at", ""), reverse=True)
    return results[:10]


@api_router.post("/pending-fulfillment")
async def create_pending_fulfillment(
    data: PendingFulfillmentCreate,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Create a pending fulfillment entry for Amazon orders awaiting stock"""
    # Validate firm
    firm = await db.firms.find_one({"id": data.firm_id, "is_active": True})
    if not firm:
        raise HTTPException(status_code=400, detail="Invalid or inactive firm")
    
    # Build items list - support both single item (backward compat) and multiple items
    items_list = []
    if data.items and len(data.items) > 0:
        # Multiple items mode
        for item in data.items:
            master_sku = await db.master_skus.find_one({"id": item.master_sku_id, "is_active": True})
            if not master_sku:
                raise HTTPException(status_code=400, detail=f"Invalid or inactive Master SKU: {item.master_sku_id}")
            items_list.append({
                "master_sku_id": item.master_sku_id,
                "master_sku_name": master_sku.get("name"),
                "sku_code": master_sku.get("sku_code"),
                "hsn_code": master_sku.get("hsn_code"),
                "gst_rate": master_sku.get("gst_rate", 18),
                "quantity": item.quantity
            })
    elif data.master_sku_id:
        # Single item mode (backward compatibility)
        master_sku = await db.master_skus.find_one({"id": data.master_sku_id, "is_active": True})
        if not master_sku:
            raise HTTPException(status_code=400, detail="Invalid or inactive Master SKU")
        items_list.append({
            "master_sku_id": data.master_sku_id,
            "master_sku_name": master_sku.get("name"),
            "sku_code": master_sku.get("sku_code"),
            "hsn_code": master_sku.get("hsn_code"),
            "gst_rate": master_sku.get("gst_rate", 18),
            "quantity": data.quantity
        })
    else:
        raise HTTPException(status_code=400, detail="At least one item is required")
    
    # DUPLICATE VALIDATION using centralized utility
    dup_errors = await validate_no_duplicates(
        tracking_id=data.tracking_id,
        order_id=data.order_id,
        invoice_number=data.invoice_number if hasattr(data, 'invoice_number') else None,
        source_type="pending_fulfillment"
    )
    if dup_errors:
        raise HTTPException(status_code=400, detail=dup_errors[0])
    
    fulfillment_id = str(uuid.uuid4())
    now = datetime.now(timezone.utc)
    expiry_date = now + timedelta(days=data.label_expiry_days)
    
    # Check current stock for all items - check if any item has insufficient stock
    all_items_in_stock = True
    total_quantity = 0
    for item in items_list:
        current_stock = await get_current_stock("master_sku", item["master_sku_id"], data.firm_id)
        item["current_stock"] = current_stock
        total_quantity += item["quantity"]
        if current_stock < item["quantity"]:
            all_items_in_stock = False
    
    initial_status = "ready_to_dispatch" if all_items_in_stock else "awaiting_stock"
    
    # For backward compatibility, also store master_sku_id and quantity for single-item entries
    first_item = items_list[0] if items_list else {}
    
    fulfillment_doc = {
        "id": fulfillment_id,
        "order_id": data.order_id,
        "tracking_id": data.tracking_id,
        "firm_id": data.firm_id,
        "items": items_list,  # New: array of items
        "master_sku_id": first_item.get("master_sku_id"),  # Backward compat
        "quantity": total_quantity,  # Total quantity
        "label_created_at": now.isoformat(),
        "label_expiry_date": expiry_date.isoformat(),
        "status": initial_status,
        "tracking_history": [{
            "tracking_id": data.tracking_id,
            "created_at": now.isoformat(),
            "status": "active"
        }],
        "notes": data.notes,
        "customer_name": data.customer_name,
        "customer_phone": data.customer_phone,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    
    await db.pending_fulfillment.insert_one(fulfillment_doc)
    
    # Remove MongoDB's _id before returning (not JSON serializable)
    fulfillment_doc.pop("_id", None)
    
    # Create audit log
    items_summary = ", ".join([f"{i.get('sku_code')} x{i.get('quantity')}" for i in items_list])
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "pending_fulfillment_created",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": data.order_id,
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"tracking_id": data.tracking_id, "items": items_summary, "status": initial_status},
        "timestamp": now.isoformat()
    })
    
    # Enrich response
    fulfillment_doc["firm_name"] = firm.get("name")
    fulfillment_doc["master_sku_name"] = first_item.get("master_sku_name")
    fulfillment_doc["sku_code"] = first_item.get("sku_code")
    fulfillment_doc["current_stock"] = first_item.get("current_stock", 0)
    fulfillment_doc["is_label_expired"] = False
    fulfillment_doc["is_label_expiring_soon"] = (expiry_date - now).total_seconds() < 86400
    
    return fulfillment_doc

@api_router.get("/pending-fulfillment")
async def list_pending_fulfillment(
    status: Optional[str] = None,
    firm_id: Optional[str] = None,
    include_expired: bool = False,
    user: dict = Depends(require_roles(["call_support", "supervisor", "technician", "service_agent", "accountant", "dispatcher", "gate", "admin"]))
):
    """List all pending fulfillment entries"""
    query = {}
    # Don't filter by status initially if status is ready_to_dispatch
    # We need to check awaiting_stock entries that might now have stock
    filter_for_ready = status == "ready_to_dispatch"
    
    if status and not filter_for_ready:
        query["status"] = status
    elif not include_expired and not filter_for_ready:
        query["status"] = {"$nin": ["expired", "cancelled", "dispatched"]}
    elif not include_expired:
        # For ready_to_dispatch filter, include awaiting_stock as well (they might have stock now)
        query["status"] = {"$in": ["awaiting_stock", "awaiting_procurement", "pending_dispatch", "ready_to_dispatch"]}
    
    if firm_id:
        query["firm_id"] = firm_id
    
    entries = await db.pending_fulfillment.find(query, {"_id": 0}).sort("created_at", -1).to_list(1000)
    
    # Get firms and SKUs for enrichment
    firm_ids = list(set(e.get("firm_id") for e in entries if e.get("firm_id")))
    sku_ids = list(set(e.get("master_sku_id") for e in entries if e.get("master_sku_id")))
    
    firms = await db.firms.find({"id": {"$in": firm_ids}}, {"_id": 0, "id": 1, "name": 1}).to_list(100)
    skus = await db.master_skus.find({"id": {"$in": sku_ids}}, {"_id": 0, "id": 1, "name": 1, "sku_code": 1}).to_list(1000)
    
    firm_map = {f["id"]: f["name"] for f in firms}
    sku_map = {s["id"]: {"name": s["name"], "sku_code": s.get("sku_code")} for s in skus}
    
    now = datetime.now(timezone.utc)
    
    for entry in entries:
        entry["firm_name"] = firm_map.get(entry.get("firm_id"))
        
        # Try to resolve master_sku_id if missing (for Amazon orders)
        master_sku_id = entry.get("master_sku_id")
        if not master_sku_id and entry.get("type") == "amazon_order":
            items = entry.get("items", [])
            if items:
                amazon_sku = items[0].get("amazon_sku") or items[0].get("seller_sku")
                if amazon_sku:
                    # Check SKU mapping
                    mapping = await db.amazon_sku_mappings.find_one({
                        "firm_id": entry.get("firm_id"),
                        "amazon_sku": amazon_sku
                    })
                    if mapping:
                        master_sku_id = mapping.get("master_sku_id")
        
        sku_info = sku_map.get(master_sku_id, {})
        entry["master_sku_name"] = sku_info.get("name") or entry.get("master_sku_name")
        entry["sku_code"] = sku_info.get("sku_code") or entry.get("sku_code")
        entry["master_sku_id_resolved"] = master_sku_id  # For UI reference
        
        # Calculate stock and expiry status
        # For entries with items array, check stock for each item
        items = entry.get("items", [])
        if items and len(items) > 0:
            all_items_in_stock = True
            for item in items:
                item_sku_id = item.get("master_sku_id")
                if item_sku_id:
                    item_stock = await get_current_stock("master_sku", item_sku_id, entry.get("firm_id"))
                    item["current_stock"] = item_stock
                    if item_stock < item.get("quantity", 1):
                        all_items_in_stock = False
                    # Add product_type info for serial number requirement
                    item_sku = await db.master_skus.find_one({"id": item_sku_id}, {"_id": 0, "product_type": 1, "is_manufactured": 1, "name": 1, "sku_code": 1})
                    if item_sku:
                        item["product_type"] = item_sku.get("product_type")
                        item["is_manufactured"] = item_sku.get("product_type") == "manufactured" or item_sku.get("is_manufactured", False)
                        # Populate master_sku_name and sku_code for display
                        item["master_sku_name"] = item_sku.get("name") or item.get("sku_name") or item.get("title")
                        item["sku_code"] = item_sku.get("sku_code") or item.get("amazon_sku") or item.get("seller_sku")
                else:
                    all_items_in_stock = False  # Can't dispatch without SKU mapping
                    # Still try to display product title from Amazon data
                    item["master_sku_name"] = item.get("sku_name") or item.get("title") or item.get("product_title") or "Unknown"
                    item["sku_code"] = item.get("amazon_sku") or item.get("seller_sku") or "No SKU"
            entry["all_items_in_stock"] = all_items_in_stock
            # Use first item's stock for backward compat display
            first_item_sku = items[0].get("master_sku_id")
            entry["current_stock"] = await get_current_stock("master_sku", first_item_sku, entry.get("firm_id")) if first_item_sku else 0
            # Also populate entry-level master_sku_name from first item for table display
            if items[0].get("master_sku_name"):
                entry["master_sku_name"] = items[0].get("master_sku_name")
            if items[0].get("sku_code"):
                entry["sku_code"] = items[0].get("sku_code")
        else:
            current_stock = await get_current_stock("master_sku", master_sku_id, entry.get("firm_id"))
            entry["current_stock"] = current_stock
            entry["all_items_in_stock"] = current_stock >= entry.get("quantity", 1)
        
        expiry_date = datetime.fromisoformat(entry.get("label_expiry_date").replace("Z", "+00:00")) if entry.get("label_expiry_date") else now
        entry["is_label_expired"] = now > expiry_date
        entry["is_label_expiring_soon"] = 0 < (expiry_date - now).total_seconds() < 86400
        
        # Auto-update status if needed (check all items have stock)
        if entry["status"] == "awaiting_stock" and entry.get("all_items_in_stock", False):
            entry["status"] = "ready_to_dispatch"
            await db.pending_fulfillment.update_one(
                {"id": entry["id"]},
                {"$set": {"status": "ready_to_dispatch", "updated_at": now.isoformat()}}
            )
            # Create notification for stock availability
            await create_notification(
                title="Order Ready for Dispatch",
                message=f"Order {entry.get('order_id')} now has stock available and is ready for dispatch",
                notification_type="success",
                link="/accountant/pending-fulfillment",
                target_roles=["accountant", "admin"],
                priority="high"
            )
    
    # Summary stats
    summary = {
        "total": len(entries),
        "awaiting_stock": len([e for e in entries if e.get("status") == "awaiting_stock"]),
        "awaiting_procurement": len([e for e in entries if e.get("status") == "awaiting_procurement"]),
        "pending_dispatch": len([e for e in entries if e.get("status") == "pending_dispatch"]),
        "ready_to_dispatch": len([e for e in entries if e.get("status") == "ready_to_dispatch"]),
        "expired_labels": len([e for e in entries if e.get("is_label_expired")]),
        "expiring_soon": len([e for e in entries if e.get("is_label_expiring_soon")])
    }
    
    # If filtering for ready_to_dispatch, filter out awaiting_stock entries
    if filter_for_ready:
        entries = [e for e in entries if e.get("status") == "ready_to_dispatch" and not e.get("is_label_expired")]
    
    return {"entries": entries, "summary": summary}

@api_router.get("/pending-fulfillment/{fulfillment_id}")
async def get_pending_fulfillment(
    fulfillment_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get a specific pending fulfillment entry"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id}, {"_id": 0})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    # Enrich
    firm = await db.firms.find_one({"id": entry.get("firm_id")}, {"_id": 0, "name": 1})
    sku = await db.master_skus.find_one({"id": entry.get("master_sku_id")}, {"_id": 0, "name": 1, "sku_code": 1})
    
    entry["firm_name"] = firm.get("name") if firm else None
    entry["master_sku_name"] = sku.get("name") if sku else None
    entry["sku_code"] = sku.get("sku_code") if sku else None
    
    current_stock = await get_current_stock("master_sku", entry.get("master_sku_id"), entry.get("firm_id"))
    entry["current_stock"] = current_stock
    
    now = datetime.now(timezone.utc)
    expiry_date = datetime.fromisoformat(entry.get("label_expiry_date").replace("Z", "+00:00")) if entry.get("label_expiry_date") else now
    entry["is_label_expired"] = now > expiry_date
    entry["is_label_expiring_soon"] = 0 < (expiry_date - now).total_seconds() < 86400
    
    return entry


@api_router.put("/pending-fulfillment/{fulfillment_id}")
async def update_pending_fulfillment(
    fulfillment_id: str,
    data: PendingFulfillmentUpdate,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Update a pending fulfillment entry (customer details, items, tracking)"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    # Don't allow editing dispatched/cancelled entries
    if entry.get("status") in ["dispatched", "cancelled"]:
        raise HTTPException(status_code=400, detail="Cannot edit dispatched or cancelled entries")
    
    now = datetime.now(timezone.utc).isoformat()
    update_data = {"updated_at": now}
    
    # Update customer details if provided
    if data.customer_name is not None:
        update_data["customer_name"] = data.customer_name
    if data.customer_phone is not None:
        update_data["customer_phone"] = data.customer_phone
    if data.notes is not None:
        update_data["notes"] = data.notes
    
    # Update tracking_id if provided (with duplicate check)
    if data.tracking_id and data.tracking_id != entry.get("tracking_id"):
        existing = await db.pending_fulfillment.find_one({
            "tracking_id": data.tracking_id,
            "id": {"$ne": fulfillment_id}
        })
        if existing:
            raise HTTPException(status_code=400, detail=f"Tracking ID {data.tracking_id} already exists")
        update_data["tracking_id"] = data.tracking_id
        # Add to tracking history
        tracking_history = entry.get("tracking_history", [])
        tracking_history.append({
            "tracking_id": data.tracking_id,
            "created_at": now,
            "status": "updated",
            "updated_by": user["id"]
        })
        update_data["tracking_history"] = tracking_history
    
    # Update items if provided
    if data.items:
        items_list = []
        total_quantity = 0
        for item in data.items:
            if not item.get("master_sku_id"):
                continue
            master_sku = await db.master_skus.find_one({"id": item["master_sku_id"], "is_active": True})
            if not master_sku:
                raise HTTPException(status_code=400, detail=f"Invalid Master SKU: {item['master_sku_id']}")
            qty = item.get("quantity", 1)
            total_quantity += qty
            items_list.append({
                "master_sku_id": item["master_sku_id"],
                "master_sku_name": master_sku.get("name"),
                "sku_code": master_sku.get("sku_code"),
                "hsn_code": master_sku.get("hsn_code"),
                "gst_rate": master_sku.get("gst_rate", 18),
                "quantity": qty
            })
        
        if items_list:
            update_data["items"] = items_list
            update_data["quantity"] = total_quantity
            # For backward compatibility
            update_data["master_sku_id"] = items_list[0]["master_sku_id"]
    
    await db.pending_fulfillment.update_one(
        {"id": fulfillment_id},
        {"$set": update_data}
    )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "pending_fulfillment_updated",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": entry.get("order_id"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"changes": list(update_data.keys())},
        "timestamp": now
    })
    
    return {"success": True, "message": "Entry updated successfully", "updated_fields": list(update_data.keys())}

@api_router.delete("/pending-fulfillment/{fulfillment_id}/duplicate")
async def delete_duplicate_entry(
    fulfillment_id: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """Delete a duplicate pending fulfillment entry (admin only)"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Entry not found")
    
    # Check if this is actually a duplicate
    order_id = entry.get("order_id")
    tracking_id = entry.get("tracking_id")
    
    duplicates = await db.pending_fulfillment.count_documents({"order_id": order_id})
    if duplicates <= 1:
        raise HTTPException(status_code=400, detail="This entry is not a duplicate. Use cancel instead.")
    
    # Delete the entry
    await db.pending_fulfillment.delete_one({"id": fulfillment_id})
    
    # Create audit log
    now = datetime.now(timezone.utc).isoformat()
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "pending_fulfillment_duplicate_deleted",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": order_id,
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"tracking_id": tracking_id, "reason": "duplicate removal"},
        "timestamp": now
    })
    
    return {"success": True, "message": f"Duplicate entry for order {order_id} deleted"}


@api_router.put("/pending-fulfillment/{fulfillment_id}/regenerate-tracking")
async def regenerate_tracking_id(
    fulfillment_id: str,
    new_tracking_id: str = Form(...),
    expiry_days: int = Form(5),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Regenerate tracking ID for a pending fulfillment (extends expiry)"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    if entry.get("status") == "dispatched":
        raise HTTPException(status_code=400, detail="Cannot regenerate tracking for dispatched orders")
    
    now = datetime.now(timezone.utc)
    new_expiry = now + timedelta(days=expiry_days)
    
    # Mark old tracking as replaced in history
    tracking_history = entry.get("tracking_history", [])
    for th in tracking_history:
        if th.get("status") == "active":
            th["status"] = "replaced"
            th["expired_at"] = now.isoformat()
    
    # Add new tracking to history
    tracking_history.append({
        "tracking_id": new_tracking_id,
        "created_at": now.isoformat(),
        "status": "active"
    })
    
    await db.pending_fulfillment.update_one(
        {"id": fulfillment_id},
        {"$set": {
            "tracking_id": new_tracking_id,
            "label_created_at": now.isoformat(),
            "label_expiry_date": new_expiry.isoformat(),
            "tracking_history": tracking_history,
            "status": "awaiting_stock" if entry.get("status") == "expired" else entry.get("status"),
            "updated_at": now.isoformat()
        }}
    )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "tracking_regenerated",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": entry.get("order_id"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"old_tracking": entry.get("tracking_id"), "new_tracking": new_tracking_id},
        "timestamp": now.isoformat()
    })
    
    return {"message": "Tracking ID regenerated", "new_tracking_id": new_tracking_id, "new_expiry_date": new_expiry.isoformat()}

@api_router.post("/pending-fulfillment/{fulfillment_id}/dispatch")
async def dispatch_pending_fulfillment(
    fulfillment_id: str,
    serial_numbers: Optional[str] = Form(None),  # Comma-separated for multi-item manufactured items
    notes: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Dispatch a pending fulfillment order with multi-item support (deducts stock for all items)"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    if entry.get("status") == "dispatched":
        raise HTTPException(status_code=400, detail="Order already dispatched")
    
    if entry.get("status") == "cancelled":
        raise HTTPException(status_code=400, detail="Cannot dispatch cancelled order")
    
    # Check label expiry (only if label_expiry_date exists)
    now = datetime.now(timezone.utc)
    label_expiry_date = entry.get("label_expiry_date")
    if label_expiry_date:
        try:
            expiry_date = datetime.fromisoformat(label_expiry_date.replace("Z", "+00:00"))
            if now > expiry_date:
                raise HTTPException(status_code=400, detail="Label has expired. Please regenerate tracking ID first.")
        except (ValueError, AttributeError):
            # Invalid date format - skip expiry check
            pass
    
    # Get items list - support both multi-item and single-item entries
    items = entry.get("items", [])
    if not items and entry.get("master_sku_id"):
        # Backward compatibility: single item entry
        items = [{
            "master_sku_id": entry.get("master_sku_id"),
            "master_sku_name": entry.get("master_sku_name"),
            "sku_code": entry.get("sku_code"),
            "quantity": entry.get("quantity", 1)
        }]
    
    if not items:
        raise HTTPException(status_code=400, detail="No items found in this fulfillment entry")
    
    firm = await db.firms.find_one({"id": entry.get("firm_id")})
    dispatch_id = str(uuid.uuid4())
    dispatch_number = f"AMZ-{now.strftime('%Y%m%d')}-{str(uuid.uuid4())[:8].upper()}"
    
    # Parse serial numbers if provided (comma-separated)
    serial_list = [s.strip() for s in (serial_numbers or "").split(",") if s.strip()] if serial_numbers else []
    
    # Process each item - check stock and prepare dispatch items
    dispatch_items = []
    ledger_entries = []
    total_quantity = 0
    
    for idx, item in enumerate(items):
        master_sku = await db.master_skus.find_one({"id": item.get("master_sku_id")})
        if not master_sku:
            raise HTTPException(status_code=400, detail=f"Master SKU not found: {item.get('master_sku_id')}")
        
        is_manufactured = master_sku.get("product_type") == "manufactured"
        item_quantity = item.get("quantity", 1)
        total_quantity += item_quantity
        
        if is_manufactured:
            # For manufactured items, need serial number
            if idx < len(serial_list):
                serial_number = serial_list[idx]
                serial_entry = await db.finished_good_serials.find_one({
                    "serial_number": serial_number,
                    "master_sku_id": item.get("master_sku_id"),
                    "firm_id": entry.get("firm_id"),
                    "status": "in_stock"
                })
                if not serial_entry:
                    raise HTTPException(status_code=400, detail=f"Serial number {serial_number} not found or not in stock for {master_sku.get('name')}")
                
                # Mark serial as dispatched
                await db.finished_good_serials.update_one(
                    {"id": serial_entry["id"]},
                    {"$set": {"status": "dispatched", "dispatched_at": now.isoformat()}}
                )
            else:
                # Manufactured item without serial - skip serial validation if not provided
                serial_number = None
        else:
            # For traded items, check ledger stock
            current_stock = await get_current_stock("master_sku", item.get("master_sku_id"), entry.get("firm_id"))
            if current_stock < item_quantity:
                raise HTTPException(status_code=400, detail=f"Insufficient stock for {master_sku.get('name')}. Available: {current_stock}, Required: {item_quantity}")
            
            # Prepare ledger entry for stock deduction
            ledger_id = str(uuid.uuid4())
            ledger_number = f"LED-{now.strftime('%Y%m%d')}-{str(uuid.uuid4())[:8].upper()}"
            new_balance = current_stock - item_quantity
            
            ledger_entries.append({
                "id": ledger_id,
                "entry_number": ledger_number,
                "entry_type": "dispatch_out",
                "item_type": "master_sku",
                "item_id": item.get("master_sku_id"),
                "item_name": master_sku.get("name"),
                "item_sku": master_sku.get("sku_code"),
                "firm_id": entry.get("firm_id"),
                "firm_name": firm.get("name") if firm else None,
                "quantity": item_quantity,
                "running_balance": new_balance,
                "reference_id": dispatch_id,
                "notes": f"Fulfillment dispatch - Order: {entry.get('order_id')} - Item: {master_sku.get('name')}",
                "created_by": user["id"],
                "created_by_name": f"{user['first_name']} {user['last_name']}",
                "created_at": now.isoformat()
            })
            serial_number = None
        
        dispatch_items.append({
            "master_sku_id": item.get("master_sku_id"),
            "master_sku_name": master_sku.get("name"),
            "sku_code": master_sku.get("sku_code"),
            "hsn_code": master_sku.get("hsn_code"),
            "gst_rate": master_sku.get("gst_rate", 18),
            "quantity": item_quantity,
            "serial_number": serial_number,
            "is_manufactured": is_manufactured
        })
    
    # Determine dispatch type and order source based on entry type
    dispatch_type = "amazon_order" if entry.get("type") == "amazon_order" else "new_order"
    order_source = entry.get("order_source", "amazon" if entry.get("type") == "amazon_order" else "direct")
    
    # For backward compatibility, use first item's details as primary
    first_item = dispatch_items[0] if dispatch_items else {}
    
    dispatch_doc = {
        "id": dispatch_id,
        "dispatch_number": dispatch_number,
        "dispatch_type": dispatch_type,
        "order_source": order_source,
        "firm_id": entry.get("firm_id"),
        "firm_name": firm.get("name") if firm else None,
        "master_sku_id": first_item.get("master_sku_id"),
        "master_sku_name": first_item.get("master_sku_name"),
        "sku": first_item.get("sku_code"),
        "sku_code": first_item.get("sku_code"),
        "quantity": total_quantity,
        "items": dispatch_items,  # Store all items
        "serial_number": first_item.get("serial_number"),
        "order_id": entry.get("order_id"),
        "marketplace_order_id": entry.get("amazon_order_id") or entry.get("order_id"),
        "customer_name": entry.get("customer_name"),
        "phone": entry.get("phone"),
        "address": entry.get("address"),
        "city": entry.get("city"),
        "state": entry.get("state"),
        "pincode": entry.get("pincode"),
        "tracking_id": entry.get("tracking_id") or entry.get("tracking_number"),
        "courier": entry.get("carrier_name") or entry.get("carrier_code"),
        "pending_fulfillment_id": fulfillment_id,
        "status": "dispatched",
        "scanned_out_at": now.isoformat(),
        "notes": notes,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat()
    }
    await db.dispatches.insert_one(dispatch_doc)
    
    # Create sales order entry for this dispatch
    await create_sales_order_from_dispatch(dispatch_doc, db)
    
    # Auto-create sales invoice for GST compliance
    await create_sales_invoice_from_dispatch(dispatch_doc, db)
    
    # Insert all ledger entries for stock deduction
    if ledger_entries:
        await db.inventory_ledger.insert_many(ledger_entries)
    
    # Update pending fulfillment status
    await db.pending_fulfillment.update_one(
        {"id": fulfillment_id},
        {"$set": {
            "status": "dispatched",
            "dispatched_at": now.isoformat(),
            "dispatch_id": dispatch_id,
            "updated_at": now.isoformat()
        }}
    )
    
    # Update amazon_orders status if this is an Amazon order
    if entry.get("type") == "amazon_order" and entry.get("amazon_order_id"):
        await db.amazon_orders.update_one(
            {"amazon_order_id": entry.get("amazon_order_id")},
            {"$set": {
                "crm_status": "dispatched",
                "dispatched_at": now.isoformat(),
                "dispatch_id": dispatch_id,
                "dispatch_number": dispatch_number,
                "updated_at": now.isoformat()
            }}
        )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "pending_fulfillment_dispatched",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": entry.get("order_id"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"dispatch_id": dispatch_id, "tracking_id": entry.get("tracking_id"), "serial_number": serial_number},
        "timestamp": now.isoformat()
    })
    
    return {"message": "Order dispatched successfully", "dispatch_id": dispatch_id, "dispatch_number": dispatch_number}

@api_router.put("/pending-fulfillment/{fulfillment_id}/cancel")
async def cancel_pending_fulfillment(
    fulfillment_id: str,
    reason: str = Form(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Cancel a pending fulfillment entry"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    if entry.get("status") == "dispatched":
        raise HTTPException(status_code=400, detail="Cannot cancel dispatched orders")
    
    now = datetime.now(timezone.utc)
    
    await db.pending_fulfillment.update_one(
        {"id": fulfillment_id},
        {"$set": {
            "status": "cancelled",
            "cancellation_reason": reason,
            "cancelled_at": now.isoformat(),
            "cancelled_by": user["id"],
            "cancelled_by_name": f"{user['first_name']} {user['last_name']}",
            "updated_at": now.isoformat()
        }}
    )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "pending_fulfillment_cancelled",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": entry.get("order_id"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"reason": reason},
        "timestamp": now.isoformat()
    })
    
    return {"message": "Order cancelled", "order_id": entry.get("order_id")}


@api_router.put("/pending-fulfillment/{fulfillment_id}/upload-eway-bill")
async def upload_eway_bill(
    fulfillment_id: str,
    eway_bill_number: str = Form(...),
    eway_bill_file: UploadFile = File(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Upload e-way bill for orders > ₹50,000"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    if entry.get("status") in ["dispatched", "cancelled"]:
        raise HTTPException(status_code=400, detail=f"Cannot upload e-way bill for {entry.get('status')} order")
    
    now = datetime.now(timezone.utc)
    
    # Save the e-way bill file
    file_ext = eway_bill_file.filename.split('.')[-1] if '.' in eway_bill_file.filename else 'pdf'
    file_name = f"eway_bill_{fulfillment_id}_{now.strftime('%Y%m%d%H%M%S')}.{file_ext}"
    file_path = f"/uploads/eway_bills/{file_name}"
    
    os.makedirs("/app/uploads/eway_bills", exist_ok=True)
    
    with open(f"/app{file_path}", "wb") as f:
        content = await eway_bill_file.read()
        f.write(content)
    
    # Update the entry
    await db.pending_fulfillment.update_one(
        {"id": fulfillment_id},
        {"$set": {
            "eway_bill_number": eway_bill_number,
            "eway_bill_url": file_path,
            "eway_bill_uploaded_at": now.isoformat(),
            "eway_bill_uploaded_by": user["id"],
            "updated_at": now.isoformat()
        }}
    )
    
    return {
        "message": "E-way bill uploaded successfully",
        "eway_bill_number": eway_bill_number,
        "eway_bill_url": file_path
    }


@api_router.put("/pending-fulfillment/{fulfillment_id}/mark-ready")
async def mark_pending_fulfillment_ready(
    fulfillment_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Mark a pending fulfillment entry as ready to dispatch (when stock is available)"""
    entry = await db.pending_fulfillment.find_one({"id": fulfillment_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Pending fulfillment entry not found")
    
    if entry.get("status") == "dispatched":
        raise HTTPException(status_code=400, detail="Order already dispatched")
    
    if entry.get("status") == "cancelled":
        raise HTTPException(status_code=400, detail="Order is cancelled")
    
    if entry.get("status") == "ready_to_dispatch":
        raise HTTPException(status_code=400, detail="Order already ready to dispatch")
    
    # Check stock availability
    firm_id = entry.get("firm_id")
    master_sku_id = entry.get("master_sku_id")
    quantity_required = entry.get("quantity", 1)
    
    # If master_sku_id is missing, try to resolve from items or SKU mapping
    if not master_sku_id:
        # Check items array first
        items = entry.get("items", [])
        if items and items[0].get("master_sku_id"):
            master_sku_id = items[0].get("master_sku_id")
        else:
            # Try to find from SKU mapping (for Amazon orders)
            amazon_order_id = entry.get("amazon_order_id")
            if amazon_order_id:
                amazon_order = await db.amazon_orders.find_one({"amazon_order_id": amazon_order_id})
                if amazon_order:
                    for item in amazon_order.get("items", []):
                        amazon_sku = item.get("amazon_sku") or item.get("seller_sku")
                        if amazon_sku:
                            # Check SKU mapping
                            mapping = await db.amazon_sku_mappings.find_one({
                                "firm_id": firm_id,
                                "amazon_sku": amazon_sku
                            })
                            if mapping:
                                master_sku_id = mapping.get("master_sku_id")
                                # Update the entry for future use
                                await db.pending_fulfillment.update_one(
                                    {"id": fulfillment_id},
                                    {"$set": {
                                        "master_sku_id": master_sku_id,
                                        "master_sku_name": mapping.get("master_sku_name"),
                                        "sku_code": mapping.get("sku_code")
                                    }}
                                )
                                break
                            
                            # Also try alias lookup
                            master_sku_doc = await db.master_skus.find_one({
                                "$or": [
                                    {"sku_code": amazon_sku},
                                    {"aliases": {"$elemMatch": {"alias_code": amazon_sku, "platform": {"$regex": "^amazon$", "$options": "i"}}}}
                                ]
                            }, {"_id": 0})
                            if master_sku_doc:
                                master_sku_id = master_sku_doc.get("id")
                                # Create mapping and update entry
                                await db.amazon_sku_mappings.update_one(
                                    {"firm_id": firm_id, "amazon_sku": amazon_sku},
                                    {"$set": {
                                        "id": str(uuid.uuid4()),
                                        "firm_id": firm_id,
                                        "amazon_sku": amazon_sku,
                                        "master_sku_id": master_sku_id,
                                        "master_sku_name": master_sku_doc.get("name"),
                                        "sku_code": master_sku_doc.get("sku_code"),
                                        "auto_mapped": True,
                                        "mapped_via": "mark_ready_lookup",
                                        "created_at": datetime.now(timezone.utc).isoformat()
                                    }},
                                    upsert=True
                                )
                                await db.pending_fulfillment.update_one(
                                    {"id": fulfillment_id},
                                    {"$set": {
                                        "master_sku_id": master_sku_id,
                                        "master_sku_name": master_sku_doc.get("name"),
                                        "sku_code": master_sku_doc.get("sku_code")
                                    }}
                                )
                                break
    
    if not master_sku_id:
        raise HTTPException(
            status_code=400, 
            detail="Cannot check inventory: SKU not mapped. Please map the SKU to a Master SKU first."
        )
    
    # Get current stock using the ledger-based calculation (same as list endpoint)
    current_stock = await get_current_stock("master_sku", master_sku_id, firm_id)
    
    if current_stock < quantity_required:
        raise HTTPException(
            status_code=400, 
            detail=f"Insufficient stock. Required: {quantity_required}, Available: {current_stock}"
        )
    
    now = datetime.now(timezone.utc)
    
    await db.pending_fulfillment.update_one(
        {"id": fulfillment_id},
        {"$set": {
            "status": "ready_to_dispatch",
            "marked_ready_at": now.isoformat(),
            "marked_ready_by": user["id"],
            "marked_ready_by_name": f"{user['first_name']} {user['last_name']}",
            "updated_at": now.isoformat()
        }}
    )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "pending_fulfillment_marked_ready",
        "entity_type": "pending_fulfillment",
        "entity_id": fulfillment_id,
        "entity_name": entry.get("order_id"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {"stock_at_time": current_stock, "quantity_required": quantity_required, "master_sku_id": master_sku_id},
        "timestamp": now.isoformat()
    })
    
    return {"message": "Order marked as ready to dispatch", "order_id": entry.get("order_id")}


@api_router.put("/pending-fulfillment/fix-amazon-status")
async def fix_amazon_pending_fulfillment_status(
    user: dict = Depends(require_roles(["admin"]))
):
    """Fix Amazon orders that have status='pending' instead of 'pending_dispatch'"""
    result = await db.pending_fulfillment.update_many(
        {"type": "amazon_order", "status": "pending"},
        {"$set": {"status": "pending_dispatch"}}
    )
    return {
        "message": f"Fixed {result.modified_count} Amazon orders",
        "modified_count": result.modified_count
    }


@api_router.put("/amazon/sync-dispatched-status")
async def sync_amazon_dispatched_status(
    firm_id: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """Sync Amazon orders that were dispatched but still show as tracking_added"""
    # Find dispatched pending_fulfillment entries for Amazon orders
    dispatched_entries = await db.pending_fulfillment.find({
        "type": "amazon_order",
        "status": "dispatched",
        "firm_id": firm_id
    }).to_list(1000)
    
    updated_count = 0
    for entry in dispatched_entries:
        amazon_order_id = entry.get("amazon_order_id")
        if amazon_order_id:
            # Check if amazon_orders status is not dispatched
            amazon_order = await db.amazon_orders.find_one({
                "amazon_order_id": amazon_order_id,
                "crm_status": {"$ne": "dispatched"}
            })
            
            if amazon_order:
                await db.amazon_orders.update_one(
                    {"amazon_order_id": amazon_order_id},
                    {"$set": {
                        "crm_status": "dispatched",
                        "dispatched_at": entry.get("dispatched_at"),
                        "dispatch_id": entry.get("dispatch_id"),
                        "updated_at": datetime.now(timezone.utc).isoformat()
                    }}
                )
                updated_count += 1
    
    return {
        "message": f"Synced {updated_count} Amazon orders to dispatched status",
        "updated_count": updated_count
    }


@api_router.post("/amazon/sync-from-dispatches")
async def sync_amazon_from_dispatches(
    firm_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Sync Amazon orders from dispatcher queue.
    Finds dispatched orders with Amazon order IDs and updates Amazon orders to mark as dispatched.
    Useful when orders were manually dispatched without going through Amazon Orders workflow.
    """
    # Find dispatches that have marketplace_order_id (Amazon order ID)
    dispatches = await db.dispatches.find({
        "firm_id": firm_id,
        "status": {"$in": ["dispatched", "delivered"]},
        "$or": [
            {"marketplace_order_id": {"$exists": True, "$ne": None, "$ne": ""}},
            {"order_source": "amazon"},
            {"dispatch_type": "amazon_order"}
        ]
    }).to_list(1000)
    
    synced_count = 0
    synced_orders = []
    now = datetime.now(timezone.utc).isoformat()
    
    for dispatch in dispatches:
        # Get the Amazon order ID
        amazon_order_id = dispatch.get("marketplace_order_id") or dispatch.get("order_id")
        tracking_id = dispatch.get("tracking_id") or dispatch.get("tracking_number")
        courier = dispatch.get("courier") or dispatch.get("carrier_code")
        
        if not amazon_order_id:
            continue
        
        # Check if this Amazon order exists and needs updating
        amazon_order = await db.amazon_orders.find_one({
            "amazon_order_id": amazon_order_id,
            "firm_id": firm_id
        })
        
        if amazon_order:
            # Check if order is still pending or tracking_added (not yet synced as dispatched)
            current_status = amazon_order.get("crm_status")
            
            if current_status in ["pending", "tracking_added", None]:
                # Update the Amazon order with tracking and status
                update_data = {
                    "crm_status": "dispatched",
                    "dispatched_at": dispatch.get("created_at") or now,
                    "dispatch_id": dispatch.get("id"),
                    "dispatch_number": dispatch.get("dispatch_number"),
                    "updated_at": now
                }
                
                # Add tracking info if available and not already set
                if tracking_id and not amazon_order.get("tracking_number"):
                    update_data["tracking_number"] = tracking_id
                    update_data["carrier_code"] = courier
                    update_data["tracking_updated_at"] = now
                
                await db.amazon_orders.update_one(
                    {"amazon_order_id": amazon_order_id},
                    {"$set": update_data}
                )
                
                synced_count += 1
                synced_orders.append(amazon_order_id)
    
    return {
        "success": True,
        "message": f"Synced {synced_count} Amazon orders from dispatches",
        "synced_count": synced_count,
        "synced_orders": synced_orders[:10]  # Return first 10 for reference
    }


# ==================== NOTIFICATIONS API ====================

@api_router.get("/notifications")
async def get_notifications(
    unread_only: bool = False,
    limit: int = 50,
    user: dict = Depends(get_current_user)
):
    """Get notifications for the current user"""
    user_role = user.get("role")
    user_id = user.get("id")
    
    # Build query - get notifications targeted to this user's role or specifically to them
    query = {
        "$or": [
            {"target_roles": None},  # Notifications for all
            {"target_roles": user_role},  # Notifications for this role
            {"target_roles": {"$in": [user_role]}},  # Role in list
            {"target_user_ids": user_id},  # Specifically for this user
            {"target_user_ids": {"$in": [user_id]}}  # User in list
        ]
    }
    
    if unread_only:
        query["read_by"] = {"$nin": [user_id]}
    
    notifications = await db.notifications.find(query, {"_id": 0}).sort("created_at", -1).limit(limit).to_list(limit)
    
    # Add is_read flag for each notification
    for n in notifications:
        n["is_read"] = user_id in n.get("read_by", [])
    
    # Get unread count
    unread_count = await db.notifications.count_documents({
        **query,
        "read_by": {"$nin": [user_id]}
    })
    
    return {
        "notifications": notifications,
        "unread_count": unread_count
    }

@api_router.post("/notifications/{notification_id}/read")
async def mark_notification_read(
    notification_id: str,
    user: dict = Depends(get_current_user)
):
    """Mark a notification as read"""
    user_id = user.get("id")
    
    result = await db.notifications.update_one(
        {"id": notification_id},
        {"$addToSet": {"read_by": user_id}}
    )
    
    if result.modified_count == 0:
        # Check if notification exists
        notification = await db.notifications.find_one({"id": notification_id})
        if not notification:
            raise HTTPException(status_code=404, detail="Notification not found")
    
    return {"success": True, "message": "Notification marked as read"}

@api_router.post("/notifications/read-all")
async def mark_all_notifications_read(user: dict = Depends(get_current_user)):
    """Mark all notifications as read for current user"""
    user_id = user.get("id")
    user_role = user.get("role")
    
    # Update all notifications visible to this user
    query = {
        "$or": [
            {"target_roles": None},
            {"target_roles": user_role},
            {"target_roles": {"$in": [user_role]}},
            {"target_user_ids": user_id},
            {"target_user_ids": {"$in": [user_id]}}
        ]
    }
    
    result = await db.notifications.update_many(
        query,
        {"$addToSet": {"read_by": user_id}}
    )
    
    return {"success": True, "marked_count": result.modified_count}

@api_router.post("/notifications", response_model=NotificationResponse)
async def create_notification_endpoint(
    data: NotificationCreate,
    user: dict = Depends(require_roles(["admin"]))
):
    """Create a new notification (admin only)"""
    notification_id = await create_notification(
        title=data.title,
        message=data.message,
        notification_type=data.type,
        link=data.link,
        target_roles=data.target_roles,
        target_user_ids=data.target_user_ids,
        priority=data.priority,
        created_by=user.get("id"),
        created_by_name=f"{user['first_name']} {user['last_name']}"
    )
    
    notification = await db.notifications.find_one({"id": notification_id}, {"_id": 0})
    notification["is_read"] = False
    return notification


# ==================== ACTIVITY LOGS ====================

@api_router.get("/admin/activity-logs")
async def get_activity_logs(
    action_type: Optional[str] = None,
    user_id: Optional[str] = None,
    entity_type: Optional[str] = None,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    search: Optional[str] = None,
    limit: int = 500,
    skip: int = 0,
    user: dict = Depends(require_roles(["admin"]))
):
    """Get comprehensive activity logs for admin"""
    query = {}
    
    if action_type:
        query["action"] = action_type
    if user_id:
        query["performed_by"] = user_id
    if entity_type:
        query["entity_type"] = entity_type
    if date_from:
        try:
            from_date = datetime.fromisoformat(date_from.replace('Z', '+00:00'))
            query["timestamp"] = {"$gte": from_date.isoformat()}
        except:
            pass
    if date_to:
        try:
            to_date = datetime.fromisoformat(date_to.replace('Z', '+00:00'))
            if "timestamp" in query:
                query["timestamp"]["$lte"] = to_date.isoformat()
            else:
                query["timestamp"] = {"$lte": to_date.isoformat()}
        except:
            pass
    if search:
        query["$or"] = [
            {"action": {"$regex": search, "$options": "i"}},
            {"performed_by_name": {"$regex": search, "$options": "i"}},
            {"entity_name": {"$regex": search, "$options": "i"}},
            {"entity_type": {"$regex": search, "$options": "i"}}
        ]
    
    # Get logs from audit_logs collection
    audit_logs = await db.audit_logs.find(query, {"_id": 0}).sort("timestamp", -1).skip(skip).limit(limit).to_list(limit)
    
    # Also collect logs from other sources to create a comprehensive view
    # Get gate scan logs
    gate_query = {}
    if date_from:
        gate_query["timestamp"] = {"$gte": date_from}
    if date_to:
        if "timestamp" in gate_query:
            gate_query["timestamp"]["$lte"] = date_to
        else:
            gate_query["timestamp"] = {"$lte": date_to}
    
    gate_logs = await db.gate_scans.find(gate_query, {"_id": 0}).sort("timestamp", -1).limit(200).to_list(200)
    
    # Transform gate logs to activity format
    for gl in gate_logs:
        gl["action"] = f"gate_scan_{gl.get('direction', 'unknown')}"
        gl["entity_type"] = "gate_scan"
        gl["entity_name"] = gl.get("ticket_number") or gl.get("dispatch_number") or gl.get("tracking_id", "Unknown")
        gl["performed_by_name"] = gl.get("scanned_by_name", "Gate Operator")
    
    # Combine and sort all logs
    all_logs = audit_logs + gate_logs
    all_logs.sort(key=lambda x: x.get("timestamp", ""), reverse=True)
    
    # Limit to requested amount
    all_logs = all_logs[:limit]
    
    # Get total count for pagination
    total_count = await db.audit_logs.count_documents(query)
    
    # Get unique action types for filter
    action_types = await db.audit_logs.distinct("action")
    entity_types = await db.audit_logs.distinct("entity_type")
    
    # Get users who have performed actions
    performers = await db.audit_logs.aggregate([
        {"$group": {"_id": {"id": "$performed_by", "name": "$performed_by_name"}}},
        {"$project": {"_id": 0, "id": "$_id.id", "name": "$_id.name"}}
    ]).to_list(100)
    
    return {
        "logs": all_logs,
        "total": total_count,
        "action_types": action_types,
        "entity_types": entity_types,
        "performers": [p for p in performers if p.get("id")]
    }

@api_router.post("/admin/activity-logs")
async def create_activity_log(
    action: str = Form(...),
    entity_type: str = Form(...),
    entity_id: str = Form(...),
    entity_name: str = Form(""),
    details: str = Form("{}"),
    user: dict = Depends(require_roles(["admin", "accountant", "supervisor", "call_support", "service_agent", "dispatcher", "gate"]))
):
    """Manually create an activity log entry"""
    now = datetime.now(timezone.utc).isoformat()
    
    try:
        details_dict = json.loads(details) if details else {}
    except:
        details_dict = {"raw": details}
    
    log_entry = {
        "id": str(uuid.uuid4()),
        "action": action,
        "entity_type": entity_type,
        "entity_id": entity_id,
        "entity_name": entity_name,
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "performed_by_role": user["role"],
        "details": details_dict,
        "timestamp": now
    }
    
    await db.audit_logs.insert_one(log_entry)
    if "_id" in log_entry:
        del log_entry["_id"]
    
    return log_entry


# ==================== DATA IMPORT/EXPORT ====================

@api_router.post("/admin/bulk-import")
async def bulk_import_data(
    file: UploadFile = File(...),
    clear_existing: bool = Form(False),
    user: dict = Depends(require_roles(["admin"]))
):
    """
    Import data from JSON export file.
    Use clear_existing=true to replace all data, false to merge/skip duplicates.
    """
    import json
    
    try:
        content = await file.read()
        data = json.loads(content.decode('utf-8'))
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid JSON file: {str(e)}")
    
    results = {}
    collections_order = [
        'firms',
        'users', 
        'master_skus',
        'raw_materials',
        'products',
        'skus',
        'warranties',
        'tickets',
        'dispatches',
        'production_requests',
        'productions',
        'supervisor_payables',
        'finished_good_serials',
        'inventory_ledger',
        'incoming_queue',
        'pending_fulfillment',
        'gate_logs',
        'audit_logs',
        'feedback',
        'appointments',
        'notifications',
        'stock_transfers',
        'supervisor_availability',
        # Dealer Portal Collections
        'dealers',
        'dealer_orders',
        'dealer_products',
        'dealer_applications',
        'dealer_promo_requests',
        'parties',
        'party_ledger',
        # Quotation/PI Collections
        'quotations',
        'pi_approvals',
        # HR Collections
        'salary_masters',
        'attendance_logs',
        'shift_logs'
    ]
    
    for coll_name in collections_order:
        if coll_name not in data:
            continue
            
        docs = data[coll_name]
        if not docs:
            continue
        
        collection = db[coll_name]
        
        if clear_existing:
            # Clear and insert all
            await collection.delete_many({})
            if docs:
                await collection.insert_many(docs)
            results[coll_name] = {"imported": len(docs), "mode": "replaced"}
        else:
            # Merge - skip existing by id
            imported = 0
            skipped = 0
            for doc in docs:
                doc_id = doc.get('id')
                if doc_id:
                    existing = await collection.find_one({"id": doc_id})
                    if existing:
                        skipped += 1
                        continue
                await collection.insert_one(doc)
                imported += 1
            results[coll_name] = {"imported": imported, "skipped": skipped, "mode": "merged"}
    
    return {
        "success": True,
        "message": "Data import completed",
        "results": results
    }

