@api_router.get("/admin/excel/export/{data_source}")
async def export_excel_data(
    data_source: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """Export specific data source as Excel file"""
    import pandas as pd
    from io import BytesIO
    
    if data_source not in EXCEL_DATA_SOURCES:
        raise HTTPException(status_code=400, detail=f"Invalid data source. Available: {list(EXCEL_DATA_SOURCES.keys())}")
    
    config = EXCEL_DATA_SOURCES[data_source]
    
    # Fetch data from MongoDB
    docs = await db[config["collection"]].find(config["filter"], {"_id": 0}).to_list(100000)
    
    # Filter only required fields
    filtered_docs = []
    for doc in docs:
        filtered_doc = {}
        for field in config["fields"]:
            value = doc.get(field, "")
            # Convert complex objects to string
            if isinstance(value, (dict, list)):
                value = json.dumps(value, default=str)
            elif isinstance(value, datetime):
                value = value.isoformat()
            filtered_doc[field] = value
        filtered_docs.append(filtered_doc)
    
    # Create DataFrame
    df = pd.DataFrame(filtered_docs)
    
    # Ensure all columns exist even if empty
    for field in config["fields"]:
        if field not in df.columns:
            df[field] = ""
    
    # Reorder columns
    df = df[config["fields"]]
    
    # Create Excel file in memory
    output = BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        # Main data sheet
        sheet_name = "dealers" if data_source == "dealers_full" else data_source
        df.to_excel(writer, sheet_name=sheet_name, index=False)
        
        # For dealers_full, add related collections as separate sheets
        if data_source == "dealers_full" and "related_collections" in config:
            for related_name, related_config in config["related_collections"].items():
                related_docs = await db[related_name].find({}, {"_id": 0}).to_list(100000)
                related_filtered = []
                for rdoc in related_docs:
                    filtered_rdoc = {}
                    for field in related_config["fields"]:
                        value = rdoc.get(field, "")
                        if isinstance(value, (dict, list)):
                            value = json.dumps(value, default=str)
                        elif isinstance(value, datetime):
                            value = value.isoformat()
                        filtered_rdoc[field] = value
                    related_filtered.append(filtered_rdoc)
                
                related_df = pd.DataFrame(related_filtered)
                for field in related_config["fields"]:
                    if field not in related_df.columns:
                        related_df[field] = ""
                related_df = related_df[related_config["fields"]]
                related_df.to_excel(writer, sheet_name=related_name, index=False)
        
        # Add metadata sheet with field descriptions
        meta_data = []
        meta_data.append({"Sheet": sheet_name, "Field": "---", "Required": "---", "Notes": "Main dealer data"})
        for f in config["fields"]:
            meta_data.append({
                "Sheet": sheet_name,
                "Field": f,
                "Required": "Yes" if f in config["required_fields"] else "No",
                "Notes": "Auto-generated, leave empty for new records" if f == "id" else
                        "Auto-set on creation" if f == "created_at" else
                        "Must be unique (used for matching on import)" if f == config["unique_field"] else ""
            })
        
        if data_source == "dealers_full" and "related_collections" in config:
            for related_name, related_config in config["related_collections"].items():
                meta_data.append({"Sheet": related_name, "Field": "---", "Required": "---", "Notes": f"Related data linked by {related_config['foreign_key']}"})
                for f in related_config["fields"]:
                    meta_data.append({
                        "Sheet": related_name,
                        "Field": f,
                        "Required": "No",
                        "Notes": "Foreign key to dealers" if f == related_config["foreign_key"] else ""
                    })
        
        meta_df = pd.DataFrame(meta_data)
        meta_df.to_excel(writer, sheet_name="Field_Info", index=False)
    
    output.seek(0)
    
    filename = f"{data_source}_export_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
    
    return Response(
        content=output.getvalue(),
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": f"attachment; filename={filename}"}
    )


@api_router.get("/admin/excel/template/{data_source}")
async def get_excel_template(
    data_source: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """Get empty Excel template for data import"""
    import pandas as pd
    from io import BytesIO
    
    if data_source not in EXCEL_DATA_SOURCES:
        raise HTTPException(status_code=400, detail=f"Invalid data source. Available: {list(EXCEL_DATA_SOURCES.keys())}")
    
    config = EXCEL_DATA_SOURCES[data_source]
    
    # Create empty DataFrame with headers
    df = pd.DataFrame(columns=config["fields"])
    
    # Add sample row based on data source
    sample_data = {}
    for field in config["fields"]:
        if field == "id":
            sample_data[field] = "(leave empty for new)"
        elif field == "created_at":
            sample_data[field] = "(auto-filled)"
        elif field == "email":
            sample_data[field] = "example@email.com"
        elif field == "phone":
            sample_data[field] = "9876543210"
        elif field == "first_name":
            sample_data[field] = "John"
        elif field == "last_name":
            sample_data[field] = "Doe"
        elif field == "firm_name":
            sample_data[field] = "Example Firm"
        elif field == "sku_code":
            sample_data[field] = "SKU-001"
        elif field == "name":
            sample_data[field] = "Product Name"
        elif field == "category":
            sample_data[field] = "Inverter"
        elif field == "status":
            sample_data[field] = "active"
        elif field == "items":
            sample_data[field] = '[{"sku_code": "SKU-001", "quantity": 1, "price": 1000}]'
        elif "price" in field or "amount" in field or "mrp" in field:
            sample_data[field] = "0.00"
        elif "date" in field:
            sample_data[field] = "2026-01-01"
        else:
            sample_data[field] = ""
    
    df = pd.concat([df, pd.DataFrame([sample_data])], ignore_index=True)
    
    # Create Excel file
    output = BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        df.to_excel(writer, sheet_name=data_source, index=False)
        
        # Add instructions sheet
        instructions = pd.DataFrame({
            "Instructions": [
                f"1. Fill in the data for {data_source}",
                f"2. Required fields: {', '.join(config['required_fields'])}",
                f"3. Unique field (no duplicates): {config['unique_field']}",
                "4. Leave 'id' empty for new records - it will be auto-generated",
                "5. Leave 'created_at' empty - it will be auto-filled",
                "6. Delete the sample row before importing",
                "7. Save the file and upload it in the Import section"
            ]
        })
        instructions.to_excel(writer, sheet_name="Instructions", index=False)
        
        # Add field info
        meta_df = pd.DataFrame({
            "Field": config["fields"],
            "Required": ["Yes" if f in config["required_fields"] else "No" for f in config["fields"]],
            "Notes": [
                "Auto-generated, leave empty for new records" if f == "id" else
                "Auto-set on creation" if f == "created_at" else
                "Must be unique" if f == config["unique_field"] else
                ""
                for f in config["fields"]
            ]
        })
        meta_df.to_excel(writer, sheet_name="Field_Info", index=False)
    
    output.seek(0)
    
    filename = f"{data_source}_template.xlsx"
    
    return Response(
        content=output.getvalue(),
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": f"attachment; filename={filename}"}
    )


@api_router.post("/admin/excel/import/{data_source}")
async def import_excel_data(
    data_source: str,
    file: UploadFile = File(...),
    mode: str = Form("merge"),  # "merge" or "replace"
    user: dict = Depends(require_roles(["admin"]))
):
    """Import data from Excel file. Mode: 'merge' (add/update) or 'replace' (clear all first)"""
    import pandas as pd
    from io import BytesIO
    
    if data_source not in EXCEL_DATA_SOURCES:
        raise HTTPException(status_code=400, detail=f"Invalid data source. Available: {list(EXCEL_DATA_SOURCES.keys())}")
    
    if not file.filename.endswith(('.xlsx', '.xls')):
        raise HTTPException(status_code=400, detail="Please upload an Excel file (.xlsx or .xls)")
    
    config = EXCEL_DATA_SOURCES[data_source]
    
    try:
        # Read Excel file
        content = await file.read()
        
        # For dealers_full, handle multiple sheets
        if data_source == "dealers_full":
            return await import_dealers_full(content, mode, user, config)
        
        df = pd.read_excel(BytesIO(content), sheet_name=0)
        
        # Remove empty rows
        df = df.dropna(how='all')
        
        # Convert DataFrame to list of dicts
        records = df.to_dict(orient='records')
        
        # Validate required fields
        errors = []
        valid_records = []
        
        for idx, record in enumerate(records):
            row_errors = []
            
            # Skip sample/template rows
            if record.get('id') == "(leave empty for new)" or record.get('created_at') == "(auto-filled)":
                continue
            
            # Check required fields
            for field in config["required_fields"]:
                value = record.get(field)
                if value is None or (isinstance(value, str) and value.strip() == "") or (isinstance(value, float) and pd.isna(value)):
                    row_errors.append(f"Missing required field: {field}")
            
            if row_errors:
                errors.append({"row": idx + 2, "errors": row_errors})  # +2 for header and 0-index
            else:
                # Clean up the record
                clean_record = {}
                for field in config["fields"]:
                    value = record.get(field)
                    
                    # Handle NaN values
                    if isinstance(value, float) and pd.isna(value):
                        value = None
                    # Handle string NaN
                    elif isinstance(value, str) and value.strip() in ["", "nan", "NaN", "(leave empty for new)", "(auto-filled)"]:
                        value = None
                    # Parse JSON strings (for complex fields like items)
                    elif isinstance(value, str) and value.startswith('[') or (isinstance(value, str) and value.startswith('{')):
                        try:
                            value = json.loads(value)
                        except:
                            pass
                    
                    if value is not None:
                        clean_record[field] = value
                
                # Generate ID if not provided
                if not clean_record.get("id"):
                    clean_record["id"] = str(uuid.uuid4())
                
                # Add created_at if not provided
                if not clean_record.get("created_at"):
                    clean_record["created_at"] = datetime.now(timezone.utc).isoformat()
                
                valid_records.append(clean_record)
        
        if errors and len(errors) > 5:
            # Return first 5 errors as sample
            raise HTTPException(
                status_code=400, 
                detail=f"Validation errors in {len(errors)} rows. First 5: {errors[:5]}"
            )
        elif errors:
            raise HTTPException(status_code=400, detail=f"Validation errors: {errors}")
        
        # Perform import
        collection = db[config["collection"]]
        imported_count = 0
        updated_count = 0
        skipped_count = 0
        
        if mode == "replace":
            # Clear existing data (with filter if applicable)
            await collection.delete_many(config["filter"])
            
            # Insert all records
            if valid_records:
                await collection.insert_many(valid_records)
                imported_count = len(valid_records)
        else:
            # Merge mode - update existing or insert new
            unique_field = config["unique_field"]
            
            for record in valid_records:
                unique_value = record.get(unique_field)
                
                if unique_value:
                    # Check if record exists
                    existing = await collection.find_one({unique_field: unique_value})
                    
                    if existing:
                        # Update existing
                        await collection.update_one(
                            {unique_field: unique_value},
                            {"$set": record}
                        )
                        updated_count += 1
                    else:
                        # Insert new
                        await collection.insert_one(record)
                        imported_count += 1
                else:
                    # No unique field, just insert
                    await collection.insert_one(record)
                    imported_count += 1
        
        # Log the import
        await db.audit_logs.insert_one({
            "id": str(uuid.uuid4()),
            "action": "excel_import",
            "data_source": data_source,
            "mode": mode,
            "imported": imported_count,
            "updated": updated_count,
            "skipped": skipped_count,
            "user_id": user["id"],
            "user_email": user.get("email"),
            "created_at": datetime.now(timezone.utc).isoformat()
        })
        
        return {
            "success": True,
            "data_source": data_source,
            "mode": mode,
            "imported": imported_count,
            "updated": updated_count,
            "skipped": skipped_count,
            "total_processed": len(valid_records)
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"Excel import error: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Import failed: {str(e)}")


async def import_dealers_full(content: bytes, mode: str, user: dict, config: dict):
    """Import dealers with related data (orders) from multi-sheet Excel"""
    import pandas as pd
    from io import BytesIO
    
    try:
        # Read all sheets
        excel_file = pd.ExcelFile(BytesIO(content))
        sheet_names = excel_file.sheet_names
        
        results = {
            "dealers": {"imported": 0, "updated": 0, "errors": []},
            "dealer_orders": {"imported": 0, "updated": 0, "errors": []}
        }
        
        # Process dealers sheet first
        dealers_sheet = "dealers" if "dealers" in sheet_names else sheet_names[0]
        if dealers_sheet in sheet_names and dealers_sheet != "Field_Info":
            df = pd.read_excel(excel_file, sheet_name=dealers_sheet)
            df = df.dropna(how='all')
            
            for idx, row in df.iterrows():
                record = row.to_dict()
                
                # Skip template rows
                if record.get('id') == "(leave empty for new)":
                    continue
                
                # Check required fields
                if not record.get('firm_name') or not record.get('phone'):
                    if pd.notna(record.get('firm_name')) or pd.notna(record.get('phone')):
                        results["dealers"]["errors"].append(f"Row {idx+2}: Missing firm_name or phone")
                    continue
                
                # Clean record
                clean_record = {}
                for field in config["fields"]:
                    value = record.get(field)
                    if isinstance(value, float) and pd.isna(value):
                        continue
                    if isinstance(value, str) and value.strip() in ["", "nan", "NaN", "(leave empty for new)", "(auto-filled)"]:
                        continue
                    if value is not None:
                        clean_record[field] = value
                
                # Ensure phone is string
                if 'phone' in clean_record:
                    clean_record['phone'] = str(clean_record['phone']).replace('.0', '').strip()
                
                if not clean_record.get("id"):
                    clean_record["id"] = str(uuid.uuid4())
                if not clean_record.get("user_id"):
                    clean_record["user_id"] = str(uuid.uuid4())
                if not clean_record.get("created_at"):
                    clean_record["created_at"] = datetime.now(timezone.utc).isoformat()
                clean_record["updated_at"] = datetime.now(timezone.utc).isoformat()
                
                # Check if exists by phone
                existing = await db.dealers.find_one({"phone": clean_record["phone"]})
                
                if existing:
                    await db.dealers.update_one(
                        {"phone": clean_record["phone"]},
                        {"$set": clean_record}
                    )
                    results["dealers"]["updated"] += 1
                else:
                    await db.dealers.insert_one(clean_record)
                    results["dealers"]["imported"] += 1
        
        # Process dealer_orders sheet if exists
        if "dealer_orders" in sheet_names:
            df = pd.read_excel(excel_file, sheet_name="dealer_orders")
            df = df.dropna(how='all')
            
            related_config = config.get("related_collections", {}).get("dealer_orders", {})
            fields = related_config.get("fields", [])
            
            for idx, row in df.iterrows():
                record = row.to_dict()
                
                # Skip template rows
                if record.get('id') == "(leave empty for new)":
                    continue
                
                # Check required field - dealer_id
                if not record.get('dealer_id'):
                    if pd.notna(record.get('order_number')):
                        results["dealer_orders"]["errors"].append(f"Row {idx+2}: Missing dealer_id")
                    continue
                
                # Clean record
                clean_record = {}
                for field in fields:
                    value = record.get(field)
                    if isinstance(value, float) and pd.isna(value):
                        continue
                    if isinstance(value, str) and value.strip() in ["", "nan", "NaN"]:
                        continue
                    # Parse JSON fields
                    if isinstance(value, str) and (value.startswith('[') or value.startswith('{')):
                        try:
                            value = json.loads(value)
                        except:
                            pass
                    if value is not None:
                        clean_record[field] = value
                
                if not clean_record.get("id"):
                    clean_record["id"] = str(uuid.uuid4())
                if not clean_record.get("created_at"):
                    clean_record["created_at"] = datetime.now(timezone.utc).isoformat()
                clean_record["updated_at"] = datetime.now(timezone.utc).isoformat()
                
                # Check if order exists by order_number
                order_number = clean_record.get("order_number")
                if order_number:
                    existing = await db.dealer_orders.find_one({"order_number": order_number})
                    
                    if existing:
                        await db.dealer_orders.update_one(
                            {"order_number": order_number},
                            {"$set": clean_record}
                        )
                        results["dealer_orders"]["updated"] += 1
                    else:
                        await db.dealer_orders.insert_one(clean_record)
                        results["dealer_orders"]["imported"] += 1
                else:
                    await db.dealer_orders.insert_one(clean_record)
                    results["dealer_orders"]["imported"] += 1
        
        # Log the import
        await db.audit_logs.insert_one({
            "id": str(uuid.uuid4()),
            "action": "excel_import_dealers_full",
            "mode": mode,
            "results": results,
            "user_id": user["id"],
            "user_email": user.get("email"),
            "created_at": datetime.now(timezone.utc).isoformat()
        })
        
        return {
            "success": True,
            "data_source": "dealers_full",
            "mode": mode,
            "results": results,
            "summary": {
                "dealers_imported": results["dealers"]["imported"],
                "dealers_updated": results["dealers"]["updated"],
                "orders_imported": results["dealer_orders"]["imported"],
                "orders_updated": results["dealer_orders"]["updated"],
                "total_errors": len(results["dealers"]["errors"]) + len(results["dealer_orders"]["errors"])
            }
        }
        
    except Exception as e:
        logger.error(f"Dealers full import error: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Import failed: {str(e)}")


@api_router.get("/admin/excel/sources")
async def get_excel_data_sources(
    user: dict = Depends(require_roles(["admin"]))
):
    """Get list of available data sources for Excel import/export"""
    sources = []
    for key, config in EXCEL_DATA_SOURCES.items():
        # Get count of records
        count = await db[config["collection"]].count_documents(config["filter"])
        sources.append({
            "key": key,
            "name": key.replace("_", " ").title(),
            "collection": config["collection"],
            "record_count": count,
            "fields": config["fields"],
            "required_fields": config["required_fields"],
            "unique_field": config["unique_field"]
        })
    return sources






# ==================== SERIAL NUMBERS DATA MANAGEMENT ====================

@api_router.get("/admin/serial-numbers/export")
async def export_serial_numbers(
    master_sku_id: Optional[str] = None,
    firm_id: Optional[str] = None,
    status: Optional[str] = None,
    user: dict = Depends(require_roles(["admin"]))
):
    """Export serial numbers to Excel format with customer/dispatch data"""
    import io
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Alignment
    
    query = {}
    if master_sku_id:
        query["master_sku_id"] = master_sku_id
    if firm_id:
        query["firm_id"] = firm_id
    if status:
        query["status"] = status
    
    serials = await db.finished_good_serials.find(query, {"_id": 0}).to_list(10000)
    
    dispatch_ids = list(set(s.get("dispatch_id") for s in serials if s.get("dispatch_id")))
    dispatches = await db.dispatches.find(
        {"id": {"$in": dispatch_ids}},
        {"_id": 0, "id": 1, "dispatch_number": 1, "customer_name": 1, "phone": 1, 
         "address": 1, "state": 1, "order_id": 1, "tracking_id": 1, "created_at": 1}
    ).to_list(10000)
    dispatch_map = {d["id"]: d for d in dispatches}
    
    sku_ids = list(set(s.get("master_sku_id") for s in serials if s.get("master_sku_id")))
    skus = await db.master_skus.find({"id": {"$in": sku_ids}}, {"_id": 0, "id": 1, "name": 1, "sku_code": 1}).to_list(1000)
    sku_map = {s["id"]: s for s in skus}
    
    wb = Workbook()
    ws = wb.active
    ws.title = "Serial Numbers"
    
    headers = ["Serial Number", "SKU Code", "SKU Name", "Status", "Firm ID", "Customer Name", "Phone", "Order ID", "Tracking ID", "State", "Address", "Dispatch Number", "Dispatch Date", "Production Date", "Notes"]
    header_fill = PatternFill(start_color="4472C4", end_color="4472C4", fill_type="solid")
    header_font = Font(bold=True, color="FFFFFF")
    
    for col, header in enumerate(headers, 1):
        cell = ws.cell(row=1, column=col, value=header)
        cell.fill = header_fill
        cell.font = header_font
        cell.alignment = Alignment(horizontal="center")
    
    for row_num, serial in enumerate(serials, 2):
        dispatch = dispatch_map.get(serial.get("dispatch_id"), {})
        sku = sku_map.get(serial.get("master_sku_id"), {})
        ws.cell(row=row_num, column=1, value=serial.get("serial_number"))
        ws.cell(row=row_num, column=2, value=sku.get("sku_code"))
        ws.cell(row=row_num, column=3, value=sku.get("name"))
        ws.cell(row=row_num, column=4, value=serial.get("status"))
        ws.cell(row=row_num, column=5, value=serial.get("firm_id"))
        ws.cell(row=row_num, column=6, value=dispatch.get("customer_name") or serial.get("customer_name"))
        ws.cell(row=row_num, column=7, value=dispatch.get("phone") or serial.get("phone"))
        ws.cell(row=row_num, column=8, value=dispatch.get("order_id") or serial.get("order_id"))
        ws.cell(row=row_num, column=9, value=dispatch.get("tracking_id") or serial.get("tracking_id"))
        ws.cell(row=row_num, column=10, value=dispatch.get("state"))
        ws.cell(row=row_num, column=11, value=dispatch.get("address"))
        ws.cell(row=row_num, column=12, value=dispatch.get("dispatch_number"))
        ws.cell(row=row_num, column=13, value=dispatch.get("created_at") or serial.get("dispatch_date"))
        ws.cell(row=row_num, column=14, value=serial.get("production_date"))
        ws.cell(row=row_num, column=15, value=serial.get("notes"))
    
    for col in ws.columns:
        max_length = max(len(str(cell.value or "")) for cell in col)
        ws.column_dimensions[col[0].column_letter].width = min(max_length + 2, 50)
    
    buffer = io.BytesIO()
    wb.save(buffer)
    buffer.seek(0)
    
    from fastapi.responses import StreamingResponse
    return StreamingResponse(buffer, media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": "attachment; filename=serial_numbers_export.xlsx"})


@api_router.post("/admin/serial-numbers/import")
async def import_serial_numbers(file: UploadFile, mode: str = "merge", user: dict = Depends(require_roles(["admin"]))):
    """Import serial numbers from Excel file with customer/dispatch data"""
    import pandas as pd
    import io
    
    now = datetime.now(timezone.utc).isoformat()
    content = await file.read()
    
    try:
        df = pd.read_excel(io.BytesIO(content))
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to read Excel file: {str(e)}")
    
    df.columns = df.columns.str.strip().str.lower().str.replace(' ', '_')
    column_mapping = {'serial_no': 'serial_number', 'serial': 'serial_number', 'dispatch_battery_serial_number': 'serial_number',
        'model': 'sku_code', 'name': 'customer_name', "customer's_full_name": 'customer_name', 
        'order_id/invoice_no': 'order_id', 'tracking_id_by_vasu': 'tracking_id', 'added_time': 'created_at'}
    df.rename(columns=column_mapping, inplace=True)
    
    if 'serial_number' not in df.columns:
        raise HTTPException(status_code=400, detail="Serial Number column is required")
    
    skus = await db.master_skus.find({}, {"_id": 0, "id": 1, "name": 1, "sku_code": 1}).to_list(1000)
    sku_by_code = {s["sku_code"].lower(): s for s in skus if s.get("sku_code")}
    sku_by_name = {s["name"].lower(): s for s in skus if s.get("name")}
    
    firms = await db.firms.find({}, {"_id": 0, "id": 1}).to_list(100)
    default_firm_id = firms[0]["id"] if firms else None
    
    results = {"total_rows": len(df), "imported": 0, "updated": 0, "skipped": 0, "errors": []}
    
    for idx, row in df.iterrows():
        try:
            serial_number = str(row.get('serial_number', '')).strip()
            if not serial_number or serial_number in ['nan', 'NaN', 'None', '']:
                results["skipped"] += 1
                continue
            
            sku_code = str(row.get('sku_code', '')).strip().lower() if pd.notna(row.get('sku_code')) else ''
            master_sku = sku_by_code.get(sku_code) or sku_by_name.get(sku_code)
            if not master_sku and sku_code:
                for name, sku in sku_by_name.items():
                    if sku_code in name or name in sku_code:
                        master_sku = sku
                        break
            
            status = str(row.get('status', '')).strip().lower() if pd.notna(row.get('status')) else ''
            if not status or status == 'nan':
                has_dispatch = pd.notna(row.get('customer_name')) or pd.notna(row.get('order_id'))
                status = 'dispatched' if has_dispatch else 'in_stock'
            
            phone = str(row.get('phone', '')).strip() if pd.notna(row.get('phone')) else ''
            phone = ''.join(filter(str.isdigit, phone))[-10:] if phone else None
            
            existing = await db.finished_good_serials.find_one({"serial_number": serial_number})
            
            serial_doc = {
                "serial_number": serial_number,
                "master_sku_id": master_sku["id"] if master_sku else None,
                "master_sku_name": master_sku["name"] if master_sku else None,
                "sku_code": master_sku["sku_code"] if master_sku else sku_code.upper(),
                "firm_id": default_firm_id,
                "status": status,
                "customer_name": str(row.get('customer_name', '')).strip() if pd.notna(row.get('customer_name')) else None,
                "phone": phone,
                "order_id": str(row.get('order_id', '')).strip() if pd.notna(row.get('order_id')) else None,
                "tracking_id": str(row.get('tracking_id', '')).strip() if pd.notna(row.get('tracking_id')) else None,
                "dispatch_date": str(row.get('dispatch_date', '')) if pd.notna(row.get('dispatch_date')) else None,
                "notes": str(row.get('notes', '')).strip() if pd.notna(row.get('notes')) else None,
                "updated_at": now, "imported_by": user["id"], "import_source": "excel"
            }
            
            if existing:
                if mode in ["merge", "update_only"]:
                    await db.finished_good_serials.update_one({"serial_number": serial_number}, {"$set": serial_doc})
                    results["updated"] += 1
                else:
                    results["skipped"] += 1
            else:
                if mode != "update_only":
                    serial_doc["id"] = str(uuid.uuid4())
                    serial_doc["created_at"] = now
                    await db.finished_good_serials.insert_one(serial_doc)
                    results["imported"] += 1
                else:
                    results["skipped"] += 1
        except Exception as e:
            results["errors"].append(f"Row {idx + 2}: {str(e)}")
            if len(results["errors"]) >= 10:
                break
    
    return {"success": True, "message": f"Import complete: {results['imported']} new, {results['updated']} updated, {results['skipped']} skipped", "results": results}


