@api_router.put("/sales-invoices/{invoice_id}")
async def update_sales_invoice(
    invoice_id: str,
    invoice_data: dict = Body(...),
    user: dict = Depends(require_roles(["admin"]))  # Admin only
):
    """Update an existing sales invoice (admin only)"""
    now = datetime.now(timezone.utc)
    
    # Find existing invoice
    existing = await db.sales_invoices.find_one({"id": invoice_id})
    if not existing:
        raise HTTPException(status_code=404, detail="Invoice not found")
    
    # Build update dict - only update allowed fields
    update_dict = {"updated_at": now.isoformat()}
    
    # Allow updating items with recalculation
    if "items" in invoice_data:
        items = invoice_data["items"]
        for item in items:
            item["total"] = item.get("quantity", 0) * item.get("rate", 0)
            item["taxable_value"] = item["total"] - item.get("discount", 0)
            item["gst_amount"] = item["taxable_value"] * (item.get("gst_rate", 18) / 100)
            item["total_amount"] = item["taxable_value"] + item["gst_amount"]
        update_dict["items"] = items
        
        # Recalculate totals
        subtotal = sum(item.get("total", 0) for item in items)
        total_discount = sum(item.get("discount", 0) for item in items)
        taxable_value = subtotal - total_discount
        total_gst = sum(item.get("gst_amount", 0) for item in items)
        grand_total = taxable_value + total_gst
        
        update_dict["subtotal"] = subtotal
        update_dict["total_discount"] = total_discount
        update_dict["taxable_value"] = taxable_value
        update_dict["total_gst"] = total_gst
        update_dict["grand_total"] = grand_total
    
    # Allow updating payment status
    if "payment_status" in invoice_data:
        update_dict["payment_status"] = invoice_data["payment_status"]
    
    # Allow updating notes
    if "notes" in invoice_data:
        update_dict["notes"] = invoice_data["notes"]
    
    # Allow updating party info
    if "party_id" in invoice_data:
        party = await db.parties.find_one({"id": invoice_data["party_id"], "is_active": True})
        if party:
            update_dict["party_id"] = invoice_data["party_id"]
            update_dict["party_name"] = party.get("name")
            update_dict["party_gstin"] = party.get("gstin")
            update_dict["party_state"] = invoice_data.get("party_state") or party.get("state")
    
    if "party_state" in invoice_data and "party_id" not in invoice_data:
        update_dict["party_state"] = invoice_data["party_state"]
    
    # Calculate CGST/SGST vs IGST based on state
    firm = await db.firms.find_one({"id": existing.get("firm_id")})
    firm_state = firm.get("state", "") if firm else ""
    party_state = update_dict.get("party_state") or existing.get("party_state", "")
    
    if "items" in update_dict:
        total_gst = update_dict.get("total_gst", 0)
        if firm_state and party_state and firm_state.lower() == party_state.lower():
            update_dict["cgst"] = total_gst / 2
            update_dict["sgst"] = total_gst / 2
            update_dict["igst"] = 0
        else:
            update_dict["cgst"] = 0
            update_dict["sgst"] = 0
            update_dict["igst"] = total_gst
    
    # Track who made the edit
    update_dict["edited_by"] = user.get("id")
    update_dict["edited_by_name"] = user.get("name")
    update_dict["edited_at"] = now.isoformat()
    
    await db.sales_invoices.update_one({"id": invoice_id}, {"$set": update_dict})
    
    updated = await db.sales_invoices.find_one({"id": invoice_id}, {"_id": 0})
    return {"message": "Invoice updated", "invoice": updated}


@api_router.post("/sales-invoices/from-dispatch/{dispatch_id}")
async def create_invoice_for_dispatch(
    dispatch_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Create a sales invoice for a specific dispatch.
    Used after fixing a dispatch with missing data.
    """
    # Find the dispatch
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    if not dispatch:
        raise HTTPException(status_code=404, detail="Dispatch not found")
    
    # Check if invoice already exists
    existing_invoice = await db.sales_invoices.find_one({"dispatch_id": dispatch_id})
    if existing_invoice:
        raise HTTPException(status_code=400, detail="Dispatch already has invoice")
    
    # Validate required fields
    missing_fields = []
    if not dispatch.get("state"):
        missing_fields.append("state")
    if not dispatch.get("firm_id"):
        missing_fields.append("firm_id")
    
    # Check SKU and pricing
    dispatch_has_pricing = (
        dispatch.get("invoice_value") or 
        dispatch.get("taxable_value") or 
        dispatch.get("selling_price")
    )
    
    master_sku = None
    if dispatch.get("master_sku_id"):
        master_sku = await db.master_skus.find_one({"id": dispatch.get("master_sku_id")}, {"_id": 0})
    elif dispatch.get("sku"):
        master_sku = await db.master_skus.find_one({"sku_code": dispatch.get("sku")}, {"_id": 0})
    
    if not master_sku:
        missing_fields.append("valid_sku")
    elif not dispatch_has_pricing:
        if not master_sku.get("selling_price") and not master_sku.get("mrp") and not master_sku.get("cost_price"):
            missing_fields.append("sku_price")
    
    if missing_fields:
        raise HTTPException(
            status_code=400, 
            detail=f"Dispatch still has missing data: {', '.join(missing_fields)}"
        )
    
    # Create the invoice
    invoice = await create_sales_invoice_from_dispatch(dispatch, db)
    
    if not invoice:
        raise HTTPException(status_code=500, detail="Failed to create invoice - check dispatch data")
    
    return {
        "message": "Invoice created successfully",
        "invoice": invoice
    }


@api_router.post("/sales-invoices/{invoice_id}/recalculate")
async def recalculate_sales_invoice(
    invoice_id: str,
    user: dict = Depends(require_roles(["admin"]))
):
    """
    Recalculate a sales invoice that has zero values.
    Pulls fresh data from the dispatch and SKU.
    Admin only.
    """
    invoice = await db.sales_invoices.find_one({"id": invoice_id})
    if not invoice:
        raise HTTPException(status_code=404, detail="Invoice not found")
    
    dispatch_id = invoice.get("dispatch_id")
    if not dispatch_id:
        raise HTTPException(status_code=400, detail="Invoice not linked to a dispatch - cannot recalculate")
    
    # Get fresh dispatch data
    dispatch = await db.dispatches.find_one({"id": dispatch_id}, {"_id": 0})
    if not dispatch:
        raise HTTPException(status_code=404, detail="Linked dispatch not found")
    
    # Get SKU details
    master_sku = None
    if dispatch.get("master_sku_id"):
        master_sku = await db.master_skus.find_one({"id": dispatch.get("master_sku_id")}, {"_id": 0})
    elif dispatch.get("sku"):
        master_sku = await db.master_skus.find_one({"sku_code": dispatch.get("sku")}, {"_id": 0})
    
    if not master_sku:
        raise HTTPException(status_code=400, detail="SKU not found - cannot recalculate")
    
    # Determine pricing - PRIORITIZE dispatch's invoice_value/taxable_value
    quantity = dispatch.get("quantity", 1) or 1
    gst_rate = dispatch.get("gst_rate") or master_sku.get("gst_rate", 18) or 18
    hsn_code = master_sku.get("hsn_code", "")
    
    dispatch_invoice_value = dispatch.get("invoice_value") or 0
    dispatch_taxable_value = dispatch.get("taxable_value") or 0
    dispatch_selling_price = dispatch.get("selling_price") or 0
    
    if dispatch_taxable_value > 0:
        taxable_value = dispatch_taxable_value
    elif dispatch_invoice_value > 0:
        taxable_value = dispatch_invoice_value / (1 + gst_rate / 100)
    elif dispatch_selling_price > 0:
        taxable_value = dispatch_selling_price * quantity
    else:
        unit_price = master_sku.get("selling_price") or master_sku.get("mrp") or master_sku.get("cost_price", 0) or 0
        taxable_value = unit_price * quantity
    
    if taxable_value == 0:
        raise HTTPException(
            status_code=400, 
            detail="No pricing found. Set invoice_value on dispatch or selling_price/mrp/cost_price on SKU."
        )
    
    # Calculate GST
    gst_amount = taxable_value * (gst_rate / 100)
    grand_total = taxable_value + gst_amount
    
    # Determine CGST/SGST vs IGST based on state
    firm = await db.firms.find_one({"id": dispatch.get("firm_id")}, {"_id": 0})
    firm_state = firm.get("state", "") if firm else ""
    party_state = dispatch.get("state", "")
    
    is_intra_state = firm_state and party_state and firm_state.lower() == party_state.lower()
    
    # Update the invoice
    update_data = {
        "items": [{
            "master_sku_id": master_sku["id"],
            "sku_name": master_sku.get("name"),
            "sku_code": master_sku.get("sku_code"),
            "hsn_code": hsn_code,
            "quantity": quantity,
            "rate": round(taxable_value / quantity, 2),
            "gst_rate": gst_rate,
            "discount": 0,
            "total": taxable_value,
            "taxable_value": taxable_value,
            "gst_amount": gst_amount,
            "total_amount": grand_total
        }],
        "subtotal": taxable_value,
        "total_discount": 0,
        "taxable_value": taxable_value,
        "total_gst": gst_amount,
        "cgst": gst_amount / 2 if is_intra_state else 0,
        "sgst": gst_amount / 2 if is_intra_state else 0,
        "igst": 0 if is_intra_state else gst_amount,
        "grand_total": grand_total,
        "party_state": party_state,
        "updated_at": datetime.now(timezone.utc).isoformat(),
        "recalculated_by": user.get("id"),
        "recalculated_at": datetime.now(timezone.utc).isoformat()
    }
    
    await db.sales_invoices.update_one({"id": invoice_id}, {"$set": update_data})
    
    updated_invoice = await db.sales_invoices.find_one({"id": invoice_id}, {"_id": 0})
    
    return {
        "message": f"Invoice recalculated. New total: ₹{grand_total:,.2f}",
        "invoice": updated_invoice
    }


@api_router.post("/sales-invoices/backfill")
async def backfill_sales_invoices(
    user: dict = Depends(require_roles(["admin"]))
):
    """
    Backfill sales invoices for all dispatches that don't have one.
    This generates invoices for historical dispatches.
    Returns details of any dispatches with missing data.
    """
    # Find all dispatches without sales invoices
    all_dispatches = await db.dispatches.find({}, {"_id": 0}).to_list(50000)
    
    created = 0
    skipped = 0
    errors = []
    missing_data = []  # Dispatches with incomplete data
    
    for dispatch in all_dispatches:
        try:
            # Check if invoice already exists
            existing = await db.sales_invoices.find_one({"dispatch_id": dispatch.get("id")})
            if existing:
                skipped += 1
                continue
            
            # Check for missing required data
            missing_fields = []
            if not dispatch.get("firm_id"):
                missing_fields.append("firm_id")
            if not dispatch.get("master_sku_id") and not dispatch.get("sku"):
                missing_fields.append("sku/master_sku_id")
            if not dispatch.get("customer_name"):
                missing_fields.append("customer_name")
            if not dispatch.get("state"):
                missing_fields.append("state")
            
            # Check if SKU has valid pricing - ONLY if dispatch doesn't already have pricing
            dispatch_has_pricing = (
                dispatch.get("invoice_value") or 
                dispatch.get("taxable_value") or 
                dispatch.get("selling_price")
            )
            
            master_sku = None
            if dispatch.get("master_sku_id"):
                master_sku = await db.master_skus.find_one({"id": dispatch.get("master_sku_id")}, {"_id": 0})
            if not master_sku and dispatch.get("sku"):
                master_sku = await db.master_skus.find_one({"sku_code": dispatch.get("sku")}, {"_id": 0})
            
            if not master_sku:
                missing_fields.append("valid_sku")
            elif not dispatch_has_pricing:
                # Only check SKU price if dispatch doesn't have its own pricing
                if not master_sku.get("selling_price") and not master_sku.get("mrp") and not master_sku.get("cost_price"):
                    missing_fields.append("sku_price")
            
            if missing_fields:
                missing_data.append({
                    "dispatch_id": dispatch.get("id"),
                    "dispatch_number": dispatch.get("dispatch_number"),
                    "customer_name": dispatch.get("customer_name", "Unknown"),
                    "sku": dispatch.get("sku", "Unknown"),
                    "missing_fields": missing_fields
                })
                skipped += 1
                continue
            
            # Try to create invoice
            invoice = await create_sales_invoice_from_dispatch(dispatch, db)
            if invoice:
                created += 1
            else:
                skipped += 1
        except Exception as e:
            errors.append({"dispatch_id": dispatch.get("id"), "dispatch_number": dispatch.get("dispatch_number"), "error": str(e)})
    
    return {
        "message": "Backfill complete",
        "created": created,
        "skipped": skipped,
        "errors_count": len(errors),
        "missing_data_count": len(missing_data),
        "missing_data": missing_data[:50],  # Return first 50 with missing data
        "errors": errors[:20]  # Return first 20 errors
    }


@api_router.get("/dispatches-without-invoice")
async def get_dispatches_without_invoice(
    firm_id: Optional[str] = None,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get dispatches that don't have a sales invoice yet, with SKU details and missing field info"""
    query = {
        "status": "dispatched",
        "$or": [
            {"sales_invoice_id": {"$exists": False}},
            {"sales_invoice_id": None}
        ]
    }
    if firm_id:
        query["firm_id"] = firm_id
    
    dispatches = await db.dispatches.find(query, {"_id": 0}).sort("created_at", -1).to_list(200)
    
    # Also get dispatches without sales invoice in sales_invoices collection
    all_dispatch_ids = [d.get("id") for d in dispatches]
    existing_invoices = await db.sales_invoices.find(
        {"dispatch_id": {"$in": all_dispatch_ids}},
        {"dispatch_id": 1}
    ).to_list(10000)
    existing_dispatch_ids = {inv["dispatch_id"] for inv in existing_invoices}
    
    # Filter out dispatches that already have invoices
    dispatches = [d for d in dispatches if d.get("id") not in existing_dispatch_ids]
    
    # Enrich dispatches with master SKU info and identify missing fields
    for dispatch in dispatches:
        missing_fields = []
        
        # Check state
        if not dispatch.get("state"):
            missing_fields.append("state")
        
        # Check customer name
        if not dispatch.get("customer_name"):
            missing_fields.append("customer_name")
        
        # Check firm
        if not dispatch.get("firm_id"):
            missing_fields.append("firm_id")
        
        # Get SKU info
        sku = None
        if dispatch.get("master_sku_id"):
            sku = await db.master_skus.find_one({"id": dispatch["master_sku_id"]}, {"_id": 0})
        elif dispatch.get("sku"):
            # Try to find SKU by code
            sku = await db.master_skus.find_one({
                "$or": [
                    {"sku_code": {"$regex": f"^{dispatch['sku']}$", "$options": "i"}},
                    {"name": {"$regex": dispatch['sku'], "$options": "i"}}
                ]
            }, {"_id": 0})
            if sku:
                dispatch["master_sku_id"] = sku.get("id")
        
        # Check if dispatch already has pricing (from invoice_value, taxable_value, or selling_price)
        dispatch_has_pricing = (
            dispatch.get("invoice_value") or 
            dispatch.get("taxable_value") or 
            dispatch.get("selling_price")
        )
        
        if sku:
            dispatch["hsn_code"] = sku.get("hsn_code")
            dispatch["gst_rate"] = sku.get("gst_rate", 18)
            dispatch["sku_name"] = sku.get("name")
            # Use dispatch's existing price if available, otherwise fall back to SKU
            if not dispatch_has_pricing:
                dispatch["selling_price"] = sku.get("selling_price") or sku.get("mrp") or sku.get("cost_price") or 0
            
            # Check if SKU has valid pricing - ONLY if dispatch doesn't have its own pricing
            if not dispatch_has_pricing:
                if not sku.get("selling_price") and not sku.get("mrp") and not sku.get("cost_price"):
                    missing_fields.append("sku_price")
        else:
            missing_fields.append("valid_sku")
        
        # Default quantity to 1 if not set
        if not dispatch.get("quantity"):
            dispatch["quantity"] = 1
        
        # Add missing fields info
        dispatch["missing_fields"] = missing_fields
        dispatch["can_generate_invoice"] = len(missing_fields) == 0
    
    return dispatches


# ==================== PARTY LEDGER ENDPOINTS ====================

@api_router.get("/party-ledger/{party_id}")
async def get_party_ledger(
    party_id: str,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    limit: int = 200,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get ledger entries for a party"""
    party = await db.parties.find_one({"id": party_id}, {"_id": 0})
    if not party:
        raise HTTPException(status_code=404, detail="Party not found")
    
    query = {"party_id": party_id}
    if from_date:
        query["created_at"] = {"$gte": from_date}
    if to_date:
        query.setdefault("created_at", {})["$lte"] = to_date
    
    entries = await db.party_ledger.find(query, {"_id": 0}).sort("created_at", 1).to_list(limit)
    
    # Get current balance
    last_entry = entries[-1] if entries else None
    current_balance = last_entry.get("running_balance", party.get("opening_balance", 0)) if last_entry else party.get("opening_balance", 0)
    
    return {
        "party": party,
        "entries": entries,
        "current_balance": current_balance,
        "total_debit": sum(e.get("debit", 0) for e in entries),
        "total_credit": sum(e.get("credit", 0) for e in entries)
    }


