        # Get incentives
        month_str = f"{year}-{str(month).zfill(2)}"
        incentives = await db.incentives.find({
            "agent_id": user_id,
            "month": month_str,
            "status": {"$in": ["approved", "paid"]}
        }).to_list(100)
        
        total_incentives = sum(inc.get("incentive_amount", 0) for inc in incentives)
        
