@api_router.get("/smartflo/my-calls")
async def get_my_smartflo_calls(
    limit: int = 50,
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    user: dict = Depends(get_current_user)
):
    """Get calls for the current logged-in agent"""
    # Find smartflo agent by user email
    smartflo_agent = await db.smartflo_agents.find_one(
        {"email": user.get("email")},
        {"_id": 0}
    )
    
    if not smartflo_agent:
        # Try matching by phone in user profile
        user_profile = await db.users.find_one({"id": user["id"]}, {"_id": 0, "phone": 1, "first_name": 1})
        if user_profile and user_profile.get("phone"):
            clean_phone = user_profile["phone"].replace("+91", "").replace(" ", "").strip()
            if len(clean_phone) > 10:
                clean_phone = clean_phone[-10:]
            smartflo_agent = await db.smartflo_agents.find_one(
                {"phone": {"$regex": clean_phone}},
                {"_id": 0}
            )
        
        # Also try matching by first name
        if not smartflo_agent and user_profile and user_profile.get("first_name"):
            smartflo_agent = await db.smartflo_agents.find_one(
                {"name": {"$regex": f"^{user_profile['first_name']}", "$options": "i"}},
                {"_id": 0}
            )
    
    # If still no mapping, try to find calls directly by user's first name
    user_first_name = user.get("first_name", "")
    if not smartflo_agent and user_first_name:
        # Create a virtual agent mapping for name-based search
        smartflo_agent = {"name": user_first_name, "phone": ""}
    
    if not smartflo_agent:
        return {"calls": [], "total": 0, "message": "No Smartflo agent mapping found for your account"}
    
    # Build query for this agent's calls - check all possible agent name/number fields
    agent_phone = smartflo_agent.get("phone", "")
    agent_name = smartflo_agent.get("name", "")
    clean_phone = agent_phone[-10:] if len(agent_phone) > 10 else agent_phone
    
    query = {
        "$or": [
            {"agent_number": {"$regex": clean_phone}},
            {"agent_name": agent_name},
            {"answered_agent_name": agent_name},
            {"raw_data.answered_agent_name": agent_name},
            {"raw_data.agent_name": agent_name},
            {"raw_data.missed_agent": agent_name}
        ]
    }
    
    if date_from:
        query["received_at"] = {"$gte": date_from}
    if date_to:
        if "received_at" in query:
            query["received_at"]["$lte"] = date_to
        else:
            query["received_at"] = {"$lte": date_to}
    
    calls = await db.smartflo_calls.find(
        query,
        {"_id": 0}
    ).sort("received_at", -1).limit(limit).to_list(limit)
    
    # Calculate stats
    answered = len([c for c in calls if c.get("raw_data", {}).get("event_type") == "answered" or c.get("raw_data", {}).get("duration")])
    missed = len([c for c in calls if c.get("raw_data", {}).get("event_type") == "missed"])
    
    return {
        "calls": calls,
        "total": len(calls),
        "agent": smartflo_agent,
        "stats": {
            "answered": answered,
            "missed": missed,
            "total": len(calls)
        }
    }


@api_router.get("/smartflo/dashboard")
async def get_smartflo_dashboard(
    date_from: Optional[str] = None,
    date_to: Optional[str] = None,
    department: Optional[str] = None,
    user: dict = Depends(require_roles(["admin", "supervisor"]))
):
    """Get dashboard data for Smartflo calls - admin/supervisor view"""
    query = {}
    
    if date_from:
        query["received_at"] = {"$gte": date_from}
    if date_to:
        if "received_at" in query:
            query["received_at"]["$lte"] = date_to
        else:
            query["received_at"] = {"$lte": date_to}
    if department:
        query["dept_name"] = {"$regex": department, "$options": "i"}
    
    # Get all calls
    calls = await db.smartflo_calls.find(query, {"_id": 0}).sort("received_at", -1).to_list(1000)
    
    # Get agents
    agents = await db.smartflo_agents.find({}, {"_id": 0}).to_list(100)
    agent_map = {a["phone"][-10:]: a for a in agents}
    
    # Calculate per-agent stats - now checking multiple name fields
    agent_stats = {}
    for call in calls:
        # Get agent identifier from multiple sources
        raw = call.get("raw_data") or {}
        agent_name = (
            call.get("agent_name") or 
            call.get("answered_agent_name") or 
            raw.get("answered_agent_name") or 
            raw.get("agent_name") or 
            raw.get("missed_agent")
        )
        
        # Handle case where agent_name might be a list
        if isinstance(agent_name, list):
            agent_name = agent_name[0] if agent_name else None
        
        agent_num = call.get("agent_number", "")
        
        # Use agent name as key if available, otherwise use number
        agent_key = agent_name or (agent_num[-10:] if agent_num and len(agent_num) > 10 else agent_num) or None
        
        if agent_key and isinstance(agent_key, str) and agent_key != "Unknown":
            if agent_key not in agent_stats:
                agent_info = {}
                if agent_num:
                    clean_num = agent_num[-10:] if len(agent_num) > 10 else agent_num
                    agent_info = agent_map.get(clean_num, {})
                
                agent_stats[agent_key] = {
                    "name": agent_name or agent_info.get("name", agent_key),
                    "phone": agent_num,
                    "department": agent_info.get("department", call.get("dept_name", "Unknown")),
                    "answered": 0,
                    "missed": 0,
                    "total_duration": 0,
                    "calls": []
                }
            
            event_type = raw.get("event_type", "")
            duration = raw.get("duration") or call.get("duration") or 0
            
            # Determine if answered: either event_type is 'answered' or duration > 0
            try:
                duration_num = int(float(duration)) if duration else 0
            except (ValueError, TypeError):
                duration_num = 0
            
            is_answered = event_type == "answered" or duration_num > 0
            
            if is_answered:
                agent_stats[agent_key]["answered"] += 1
                agent_stats[agent_key]["total_duration"] += duration_num
            else:
                # If not answered and not explicitly a dial/outbound, count as missed
                agent_stats[agent_key]["missed"] += 1
    
    # Department-wise stats
    dept_stats = {
        "Cx Exp": {"name": "Customer Support", "answered": 0, "missed": 0, "total": 0},
        "Sales Dep": {"name": "Sales", "answered": 0, "missed": 0, "total": 0}
    }
    
    for call in calls:
        dept = call.get("dept_name") or ""
        raw = call.get("raw_data") or {}
        event_type = raw.get("event_type", "")
        duration = raw.get("duration") or call.get("duration") or 0
        
        try:
            duration_num = int(float(duration)) if duration else 0
        except (ValueError, TypeError):
            duration_num = 0
        
        is_answered = event_type == "answered" or duration_num > 0
        
        for dept_key in dept_stats:
            if dept_key.lower() in dept.lower():
                dept_stats[dept_key]["total"] += 1
                if is_answered:
                    dept_stats[dept_key]["answered"] += 1
                else:
                    dept_stats[dept_key]["missed"] += 1
    
    # Overall stats
    total_answered = sum(a["answered"] for a in agent_stats.values())
    total_missed = sum(a["missed"] for a in agent_stats.values())
    total_duration = sum(a["total_duration"] for a in agent_stats.values())
    
    # Process recent calls to fill in agent info from raw_data
    processed_calls = []
    for call in calls[:50]:
        processed_call = dict(call)
        raw = call.get("raw_data", {})
        
        # Fill agent_name from various sources (ensure it's a string)
        agent_name = processed_call.get("agent_name")
        if not agent_name or agent_name == "None" or not isinstance(agent_name, str):
            agent_name = (
                raw.get("answered_agent_name") or 
                raw.get("missed_agent") or 
                call.get("answered_agent_name") or
                call.get("missed_agent")
            )
            if agent_name and isinstance(agent_name, str):
                processed_call["agent_name"] = agent_name
            else:
                processed_call["agent_name"] = None
        
        # Fill dept_name from call_flow or raw_data (ensure it's a string)
        dept_name = processed_call.get("dept_name")
        if not dept_name or dept_name == "None" or not isinstance(dept_name, str):
            call_flow = raw.get("call_flow", [])
            if isinstance(call_flow, list):
                for step in call_flow:
                    if isinstance(step, dict) and step.get("dept_name"):
                        dept_val = step.get("dept_name")
                        if isinstance(dept_val, str):
                            processed_call["dept_name"] = dept_val
                            break
        
        # Remove call_flow from the response to avoid serialization issues
        if "call_flow" in processed_call:
            del processed_call["call_flow"]
        if "raw_data" in processed_call and "call_flow" in processed_call.get("raw_data", {}):
            processed_call["raw_data"] = {k: v for k, v in processed_call["raw_data"].items() if k != "call_flow"}
        
        processed_calls.append(processed_call)
    
    return {
        "summary": {
            "total_calls": len(calls),
            "answered": total_answered,
            "missed": total_missed,
            "avg_duration": round(total_duration / total_answered, 1) if total_answered > 0 else 0
        },
        "agent_stats": list(agent_stats.values()),
        "department_stats": dept_stats,
        "recent_calls": processed_calls[:20]
    }


@api_router.post("/smartflo/click-to-call")
async def initiate_click_to_call(
    customer_phone: str,
    agent_name: Optional[str] = None,
    ticket_id: Optional[str] = None,
    user: dict = Depends(get_current_user)
):
    """Initiate a click-to-call from CRM to customer"""
    import httpx
    
    now = datetime.now(timezone.utc)
    api_key = None
    selected_agent = None
    
    # First, try to find the agent from database by user email (linked CRM user)
    smartflo_agent = await db.smartflo_agents.find_one(
        {"$or": [
            {"email": user.get("email")},
            {"crm_user_id": user.get("id")}
        ]},
        {"_id": 0}
    )
    
    if smartflo_agent:
        selected_agent = smartflo_agent.get("name")
        api_key = smartflo_agent.get("api_key")
    
    # If not found in database, try the hardcoded keys as fallback
    if not api_key and agent_name and agent_name in SMARTFLO_AGENT_KEYS:
        api_key = SMARTFLO_AGENT_KEYS[agent_name]
        selected_agent = agent_name
    
    # If still no API key, try to match by first name in hardcoded keys
    if not api_key and smartflo_agent:
        agent_first_name = smartflo_agent.get("name", "").split()[0] if smartflo_agent.get("name") else None
        if agent_first_name and agent_first_name in SMARTFLO_AGENT_KEYS:
            api_key = SMARTFLO_AGENT_KEYS[agent_first_name]
    
    if not smartflo_agent and not agent_name:
        raise HTTPException(status_code=400, detail="No Smartflo agent mapping found for your account. Contact admin to set up your agent mapping.")
    
    if not api_key:
        raise HTTPException(status_code=400, detail=f"No API key found for agent: {selected_agent}. Please ensure the API key is configured in the Smartflo Agent Mapping.")
    
    # Clean customer phone
    clean_phone = customer_phone.replace("+91", "").replace(" ", "").replace("-", "").strip()
    if len(clean_phone) == 10:
        clean_phone = "91" + clean_phone
    elif not clean_phone.startswith("91"):
        clean_phone = "91" + clean_phone
    
    # Call Smartflo Click-to-Call Support API
    # This API requires: customer_number, api_key (in body), async, caller_id
    # The api_key determines which agent will receive the call
    try:
        # Get agent's caller_id (DID number) - default to company's main DID
        caller_id = smartflo_agent.get("caller_id") if smartflo_agent else None
        if not caller_id:
            caller_id = "918064523982"  # Default company DID
        
        async with httpx.AsyncClient() as client:
            request_body = {
                "customer_number": clean_phone[-10:],  # Customer number (10 digits)
                "api_key": api_key,  # API key determines destination agent
                "async": 1,  # Async mode
                "caller_id": caller_id  # DID number shown to customer
            }
            
            logger.info(f"Click-to-call request: {request_body} for agent {selected_agent}")
            
            response = await client.post(
                f"{SMARTFLO_BASE_URL}/v1/click_to_call_support",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                    "accept": "application/json"
                },
                json=request_body,
                timeout=30.0
            )
            
            result = response.json()
            
            # Log the outbound call attempt
            call_log = {
                "id": str(uuid.uuid4()),
                "source": "smartflo_outbound",
                "call_type": "click_to_call",
                "agent_name": selected_agent,
                "customer_phone": clean_phone,
                "ticket_id": ticket_id,
                "initiated_by": user["id"],
                "initiated_by_name": f"{user['first_name']} {user['last_name']}",
                "api_response": result,
                "status": "initiated" if response.status_code == 200 else "failed",
                "created_at": now.isoformat()
            }
            await db.smartflo_outbound_calls.insert_one(call_log)
            
            if response.status_code == 200 and result.get("success", True):
                return {
                    "status": "success",
                    "message": f"Call initiated to {customer_phone} via {selected_agent}",
                    "call_id": call_log["id"],
                    "api_response": result
                }
            elif response.status_code == 401:
                # Invalid or expired API key
                error_msg = result.get("message", "Authentication failed")
                raise HTTPException(
                    status_code=401,
                    detail=f"Smartflo API authentication failed: {error_msg}. Please check if the API key is valid and not expired."
                )
            else:
                raise HTTPException(
                    status_code=response.status_code,
                    detail=f"Smartflo API error: {result}"
                )
                
    except httpx.TimeoutException:
        raise HTTPException(status_code=504, detail="Smartflo API timeout")
    except Exception as e:
        logger.error(f"Click-to-call error: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))


@api_router.get("/smartflo/call-history/{phone}")
async def get_call_history_for_phone(
    phone: str,
    user: dict = Depends(require_roles(["admin", "support_agent", "supervisor"]))
):
    """Get call history for a specific phone number"""
    # Clean phone
    clean_phone = phone.replace("+91", "").replace(" ", "").replace("-", "").strip()
    if len(clean_phone) > 10:
        clean_phone = clean_phone[-10:]
    
    calls = await db.smartflo_calls.find(
        {"caller_phone": {"$regex": clean_phone}},
        {"_id": 0}
    ).sort("received_at", -1).limit(50).to_list(50)
    
    # Also get outbound calls
    outbound = await db.smartflo_outbound_calls.find(
        {"customer_phone": {"$regex": clean_phone}},
        {"_id": 0}
    ).sort("created_at", -1).limit(50).to_list(50)
    
    return {
        "inbound_calls": calls,
        "outbound_calls": outbound,
        "total_inbound": len(calls),
        "total_outbound": len(outbound)
    }


