@api_router.get("/smartflo/agent-performance")
async def get_smartflo_agent_performance(
    days: int = 30,
    user: dict = Depends(require_roles(["admin", "supervisor"]))
):
    """Get detailed agent performance metrics for admin dashboard"""
    from datetime import timedelta
    
    cutoff_date = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
    
    # Get all calls within the period
    calls = await db.smartflo_calls.find({
        "received_at": {"$gte": cutoff_date}
    }).to_list(10000)
    
    # Get all agents
    agents = await db.smartflo_agents.find({}).to_list(100)
    agent_map = {a.get("name"): a for a in agents}
    
    # Calculate metrics per agent
    agent_metrics = {}
    
    for call in calls:
        # Get agent name from multiple possible fields
        raw = call.get("raw_data") or {}
        agent_name = (
            call.get("agent_name") or 
            call.get("answered_agent_name") or 
            raw.get("answered_agent_name") or
            raw.get("agent_name") or
            raw.get("missed_agent")
        )
        
        # Handle case where agent_name might be a list
        if isinstance(agent_name, list):
            agent_name = agent_name[0] if agent_name else None
        
        if not agent_name or not isinstance(agent_name, str):
            continue
            
        if agent_name not in agent_metrics:
            agent_metrics[agent_name] = {
                "name": agent_name,
                "department": call.get("dept_name", "Unknown"),
                "total_calls": 0,
                "answered": 0,
                "missed": 0,
                "total_duration": 0,
                "outcomes": {},
                "quality_scores": [],
                "customer_satisfaction": {"high": 0, "medium": 0, "low": 0},
                "red_flags_count": 0,
                "unresolved_count": 0
            }
        
        metrics = agent_metrics[agent_name]
        metrics["total_calls"] += 1
        
        # Call status - check multiple fields to determine if answered
        raw_data = call.get("raw_data", {})
        event_type = raw_data.get("event_type", "")
        duration = raw_data.get("duration", 0) or call.get("duration", 0) or 0
        status = call.get("status", "")
        
        is_answered = (
            event_type == "answered" or 
            status == "Answered" or 
            (duration and int(duration) > 0)
        )
        
        if is_answered:
            metrics["answered"] += 1
            metrics["total_duration"] += int(duration) if duration else 0
        else:
            metrics["missed"] += 1
        
        # Outcome tracking
        outcome = call.get("outcome")
        if outcome:
            metrics["outcomes"][outcome] = metrics["outcomes"].get(outcome, 0) + 1
        
        # AI Analysis metrics
        ai_analysis = call.get("ai_analysis", {}).get("analysis", {})
        if ai_analysis:
            if ai_analysis.get("call_quality_score"):
                metrics["quality_scores"].append(ai_analysis["call_quality_score"])
            
            satisfaction = ai_analysis.get("customer_satisfaction_likely")
            if satisfaction in ["high", "medium", "low"]:
                metrics["customer_satisfaction"][satisfaction] += 1
            
            if ai_analysis.get("red_flags"):
                metrics["red_flags_count"] += len(ai_analysis["red_flags"])
            
            if ai_analysis.get("issue_resolved") == False:
                metrics["unresolved_count"] += 1
    
    # Calculate summary metrics
    performance_data = []
    for name, metrics in agent_metrics.items():
        total = metrics["total_calls"]
        answered = metrics["answered"]
        missed = metrics["missed"]
        
        # Calculate averages
        avg_duration = metrics["total_duration"] / answered if answered > 0 else 0
        avg_quality = sum(metrics["quality_scores"]) / len(metrics["quality_scores"]) if metrics["quality_scores"] else None
        
        # Performance indicators
        miss_rate = (missed / total * 100) if total > 0 else 0
        resolution_rate = ((total - metrics["unresolved_count"]) / total * 100) if total > 0 else 0
        
        # Customer satisfaction rate (high / (high + medium + low))
        total_satisfaction = sum(metrics["customer_satisfaction"].values())
        satisfaction_rate = (metrics["customer_satisfaction"]["high"] / total_satisfaction * 100) if total_satisfaction > 0 else None
        
        # Performance issues
        issues = []
        if miss_rate > 30:
            issues.append(f"High miss rate: {miss_rate:.0f}% of calls missed")
        if avg_quality and avg_quality < 5:
            issues.append(f"Low call quality: Average score {avg_quality:.1f}/10")
        if metrics["red_flags_count"] > 3:
            issues.append(f"Multiple red flags: {metrics['red_flags_count']} issues flagged")
        if satisfaction_rate is not None and satisfaction_rate < 50:
            issues.append(f"Low customer satisfaction: Only {satisfaction_rate:.0f}% happy")
        if resolution_rate < 70:
            issues.append(f"Low resolution rate: {resolution_rate:.0f}% resolved")
        
        # Overall status
        if len(issues) >= 3:
            status = "needs_attention"
        elif len(issues) >= 1:
            status = "average"
        else:
            status = "good"
        
        performance_data.append({
            "agent_name": name,
            "department": metrics["department"],
            "total_calls": total,
            "answered": answered,
            "missed": missed,
            "miss_rate": round(miss_rate, 1),
            "avg_duration_seconds": round(avg_duration, 0),
            "avg_quality_score": round(avg_quality, 1) if avg_quality else None,
            "satisfaction_rate": round(satisfaction_rate, 1) if satisfaction_rate is not None else None,
            "resolution_rate": round(resolution_rate, 1),
            "red_flags_count": metrics["red_flags_count"],
            "unresolved_count": metrics["unresolved_count"],
            "outcomes": metrics["outcomes"],
            "issues": issues,
            "status": status
        })
    
    # Sort by status (needs_attention first) then by total calls
    performance_data.sort(key=lambda x: (0 if x["status"] == "needs_attention" else 1 if x["status"] == "average" else 2, -x["total_calls"]))
    
    return {
        "period_days": days,
        "total_agents": len(performance_data),
        "agents_needing_attention": len([a for a in performance_data if a["status"] == "needs_attention"]),
        "agents": performance_data
    }


@api_router.put("/smartflo/calls/{call_id}/outcome")
async def update_call_outcome(
    call_id: str,
    outcome: str = Query(...),
    notes: Optional[str] = None,
    user: dict = Depends(get_current_user)
):
    """Update call outcome and notes"""
    from bson import ObjectId
    
    # Try to find call by multiple ID formats
    call = None
    
    # First try by our generated 'id' field
    call = await db.smartflo_calls.find_one({"id": call_id})
    
    # Then try by Smartflo UUID
    if not call:
        call = await db.smartflo_calls.find_one({"uuid": call_id})
    
    # Finally try by MongoDB ObjectId
    if not call:
        try:
            obj_id = ObjectId(call_id)
            call = await db.smartflo_calls.find_one({"_id": obj_id})
        except:
            pass
    
    if not call:
        raise HTTPException(status_code=404, detail="Call not found")
    
    # Validate outcome
    valid_outcomes = [o["value"] for o in CALL_OUTCOMES]
    if outcome not in valid_outcomes:
        raise HTTPException(status_code=400, detail="Invalid outcome")
    
    update_data = {
        "outcome": outcome,
        "outcome_updated_at": datetime.now(timezone.utc).isoformat(),
        "outcome_updated_by": user.get("email")
    }
    
    if notes:
        update_data["outcome_notes"] = notes
    
    await db.smartflo_calls.update_one({"_id": call["_id"]}, {"$set": update_data})
    
    return {"message": "Outcome updated successfully"}


# =============================================================================
# AI Call Recording Analysis
# =============================================================================

@api_router.post("/smartflo/calls/{call_id}/analyze")
async def analyze_call_recording(
    call_id: str,
    user: dict = Depends(require_roles(["admin", "supervisor"]))
):
    """Transcribe and analyze call recording using AI"""
    from bson import ObjectId
    import httpx
    import tempfile
    import os as os_module
    
    logger.info(f"Analyzing call with ID: {call_id}")
    
    # Try to find call by multiple ID formats
    call = None
    
    # First try by our generated 'id' field
    call = await db.smartflo_calls.find_one({"id": call_id})
    logger.info(f"Found by id: {call is not None}")
    
    # Then try by Smartflo UUID
    if not call:
        call = await db.smartflo_calls.find_one({"uuid": call_id})
        logger.info(f"Found by uuid: {call is not None}")
    
    # Finally try by MongoDB ObjectId
    if not call:
        try:
            obj_id = ObjectId(call_id)
            call = await db.smartflo_calls.find_one({"_id": obj_id})
            logger.info(f"Found by ObjectId: {call is not None}")
        except:
            pass
    
    if not call:
        # Debug: list all calls
        all_calls = await db.smartflo_calls.find({}).to_list(10)
        logger.info(f"Total calls in DB: {len(all_calls)}")
        for c in all_calls:
            logger.info(f"  - id={c.get('id')}, uuid={c.get('uuid')}")
        raise HTTPException(status_code=404, detail="Call not found")
    
    recording_url = call.get("raw_data", {}).get("recording_url") or call.get("recording_url")
    if not recording_url:
        raise HTTPException(status_code=400, detail="No recording available for this call")
    
    # Check if already analyzed
    if call.get("ai_analysis"):
        return {"message": "Call already analyzed", "analysis": call.get("ai_analysis")}
    
    try:
        # Download recording
        async with httpx.AsyncClient() as client:
            response = await client.get(recording_url, timeout=60)
            if response.status_code != 200:
                raise HTTPException(status_code=400, detail="Failed to download recording")
            audio_content = response.content
        
        # Save to temp file
        with tempfile.NamedTemporaryFile(suffix=".mp3", delete=False) as tmp_file:
            tmp_file.write(audio_content)
            tmp_path = tmp_file.name
        
        try:
            # Transcribe using Whisper
            from emergentintegrations.llm.openai import OpenAISpeechToText
            from dotenv import load_dotenv
            load_dotenv()
            
            api_key = os_module.environ.get("EMERGENT_LLM_KEY")
            if not api_key:
                raise HTTPException(status_code=500, detail="AI integration not configured")
            
            stt = OpenAISpeechToText(api_key=api_key)
            
            with open(tmp_path, "rb") as audio_file:
                transcription = await stt.transcribe(
                    file=audio_file,
                    model="whisper-1",
                    response_format="text",
                    language="hi",  # Hindi
                    prompt="This is a customer service call in Hindi. Transcribe accurately including any English words."
                )
            
            transcript_text = transcription if isinstance(transcription, str) else transcription.text
            
            # Now summarize using GPT
            from emergentintegrations.llm.chat import LlmChat, UserMessage
            
            chat = LlmChat(
                api_key=api_key,
                session_id=f"call_analysis_{call_id}",
                system_message="""You are a brutally honest call quality analyst for a CRM system. 
                You analyze customer service calls and provide direct, no-sugar-coating feedback.
                The calls are typically in Hindi or a mix of Hindi and English (Hinglish).
                Your job is to tell the truth about what happened, what went wrong, and how the agent can improve.
                Do NOT use vague or diplomatic language. Be specific and direct.
                
                IMPORTANT: Also extract the customer's name if they mention it during the call (e.g., "Mera naam Rajesh hai" means "My name is Rajesh").
                
                IMPORTANT: The transcript will be in Hindi, but ALL your analysis, summary, feedback, and recommendations MUST be written in ENGLISH. Only the transcript stays in Hindi."""
            ).with_model("openai", "gpt-5.2")
            
            analysis_prompt = f"""Analyze this customer service call transcript and provide a BRUTALLY HONEST JSON response.
Do NOT sugarcoat anything. Be direct about problems and mistakes.

IMPORTANT: Write ALL analysis in ENGLISH. The transcript is in Hindi, but your analysis must be in English only.
IMPORTANT: Extract the CUSTOMER'S NAME if they mention it during the call.

Required JSON structure:
{{
    "customer_name_detected": "Customer's name if mentioned in call, or null if not mentioned",
    "customer_name_confidence": "high/medium/low - how confident are you about the name",
    "summary": "Brief 2-3 sentence summary in ENGLISH of what ACTUALLY happened on the call - be direct",
    "customer_intent": "What the customer really wanted - in ENGLISH",
    "what_went_well": ["List of things the agent did correctly in ENGLISH - only if any"],
    "what_went_wrong": ["List of SPECIFIC mistakes or problems in ENGLISH - be blunt. Include missed opportunities, wrong information given, poor handling, etc."],
    "agent_tone_assessment": "Honest assessment in ENGLISH of agent's tone - was it professional, rude, dismissive, helpful, impatient, etc.",
    "customer_tone_assessment": "How did the customer sound in ENGLISH - frustrated, angry, confused, satisfied, etc.",
    "improvement_advice": ["SPECIFIC actionable advice in ENGLISH for the agent on how to handle this better next time"],
    "key_points": ["List of key discussion points in ENGLISH"],
    "action_items": ["Any follow-up actions needed in ENGLISH"],
    "customer_satisfaction_likely": "high/medium/low - your honest estimate based on the call",
    "issue_resolved": true/false,
    "suggested_outcome": "One of: sale_completed, quote_sent, callback_scheduled, not_interested, issue_resolved, ticket_created, escalated, information_provided, wrong_number, no_answer, follow_up_required",
    "call_quality_score": 1-10,
    "red_flags": ["Any serious issues in ENGLISH like rude behavior, misinformation, compliance issues, etc."]
}}

Transcript (Hindi):
{transcript_text}

Remember: 
1. Be DIRECT and HONEST - no diplomatic language
2. Write ALL analysis in ENGLISH - only the original transcript is in Hindi
3. If the agent was bad, say so clearly
4. Respond ONLY with valid JSON, no additional text."""
            
            analysis_response = await chat.send_message(UserMessage(text=analysis_prompt))
            
            # Parse the JSON response
            import json
            try:
                # Clean up response if needed
                analysis_text = analysis_response.strip()
                if analysis_text.startswith("```json"):
                    analysis_text = analysis_text[7:]
                if analysis_text.startswith("```"):
                    analysis_text = analysis_text[3:]
                if analysis_text.endswith("```"):
                    analysis_text = analysis_text[:-3]
                
                analysis_json = json.loads(analysis_text.strip())
            except json.JSONDecodeError:
                analysis_json = {
                    "summary": analysis_response[:500],
                    "raw_response": True
                }
            
            # Store analysis
            ai_analysis = {
                "transcript": transcript_text,
                "analysis": analysis_json,
                "analyzed_at": datetime.now(timezone.utc).isoformat(),
                "analyzed_by": user.get("email")
            }
            
            # Also extract detected customer name
            update_data = {"ai_analysis": ai_analysis}
            detected_name = analysis_json.get("customer_name_detected")
            if detected_name and analysis_json.get("customer_name_confidence") in ["high", "medium"]:
                update_data["ai_detected_customer_name"] = detected_name
            
            await db.smartflo_calls.update_one(
                {"_id": call["_id"]},
                {"$set": update_data}
            )
            
            return {"message": "Call analyzed successfully", "analysis": ai_analysis}
            
        finally:
            # Cleanup temp file
            if os_module.path.exists(tmp_path):
                os_module.remove(tmp_path)
                
    except httpx.HTTPError as e:
        raise HTTPException(status_code=400, detail=f"Failed to download recording: {str(e)}")
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Analysis failed: {str(e)}")


@api_router.post("/smartflo/calls/auto-analyze-webhook")
async def auto_analyze_call_webhook(request: Request):
    """Webhook endpoint for automatic call analysis when recording becomes available
    This can be triggered by Smartflo or by a scheduled job"""
    data = await request.json()
    
    call_uuid = data.get("uuid")
    if not call_uuid:
        return {"status": "ignored", "reason": "No UUID provided"}
    
    # Find the call
    call = await db.smartflo_calls.find_one({"uuid": call_uuid})
    if not call:
        return {"status": "ignored", "reason": "Call not found"}
    
    # Skip if already analyzed
    if call.get("ai_analysis"):
        return {"status": "skipped", "reason": "Already analyzed"}
    
    # Skip if no recording
    recording_url = call.get("raw_data", {}).get("recording_url") or call.get("recording_url")
    if not recording_url:
        return {"status": "skipped", "reason": "No recording available"}
    
    # Queue for background analysis (in production, use Celery or similar)
    # For now, we'll mark it for analysis
    await db.smartflo_calls.update_one(
        {"_id": call["_id"]},
        {"$set": {"needs_analysis": True, "analysis_queued_at": datetime.now(timezone.utc).isoformat()}}
    )
    
    return {"status": "queued", "message": "Call queued for analysis"}


@api_router.post("/smartflo/calls/batch-analyze")
async def batch_analyze_calls(
    user: dict = Depends(require_roles(["admin", "supervisor"]))
):
    """Batch analyze all calls that have recordings but no analysis.
    Only analyzes answered calls with duration > 30 seconds.
    Called by cron job every 30 minutes."""
    import httpx
    import tempfile
    import os as os_module
    
    # Find calls that need analysis
    thirty_seconds = 30
    calls_to_analyze = await db.smartflo_calls.find({
        "ai_analysis": {"$exists": False},
        "$and": [
            {"$or": [
                {"raw_data.recording_url": {"$exists": True, "$ne": None}},
                {"recording_url": {"$exists": True, "$ne": None}}
            ]},
            {"$or": [
                {"raw_data.duration": {"$gt": thirty_seconds}},
                {"duration": {"$gt": thirty_seconds}}
            ]}
        ]
    }).sort("received_at", -1).limit(10).to_list(10)  # Process max 10 per batch
    
    if not calls_to_analyze:
        return {"status": "complete", "message": "No calls to analyze", "analyzed": 0}
    
    analyzed_count = 0
    errors = []
    
    api_key = os.environ.get("EMERGENT_LLM_KEY")
    if not api_key:
        return {"status": "error", "message": "AI integration not configured"}
    
    for call in calls_to_analyze:
        try:
            call_id = call.get("id") or str(call.get("_id"))
            recording_url = call.get("raw_data", {}).get("recording_url") or call.get("recording_url")
            
            if not recording_url:
                continue
            
            # Download recording
            async with httpx.AsyncClient() as client:
                response = await client.get(recording_url, timeout=60)
                if response.status_code != 200:
                    errors.append(f"Call {call_id}: Failed to download recording")
                    continue
                audio_content = response.content
            
            # Save to temp file
            with tempfile.NamedTemporaryFile(suffix=".mp3", delete=False) as tmp_file:
                tmp_file.write(audio_content)
                tmp_path = tmp_file.name
            
            try:
                # Transcribe using Whisper
                from emergentintegrations.llm.openai import OpenAISpeechToText
                
                stt = OpenAISpeechToText(api_key=api_key)
                
                with open(tmp_path, "rb") as audio_file:
                    transcription = await stt.transcribe(
                        file=audio_file,
                        model="whisper-1",
                        response_format="text",
                        language="hi",
                        prompt="This is a customer service call in Hindi. Transcribe accurately including any English words."
                    )
                
                transcript_text = transcription if isinstance(transcription, str) else transcription.text
                
                # Now analyze using GPT - including customer name extraction
                from emergentintegrations.llm.chat import LlmChat, UserMessage
                
                chat = LlmChat(
                    api_key=api_key,
                    session_id=f"batch_analysis_{call_id}",
                    system_message="""You are a brutally honest call quality analyst for a CRM system. 
                    You analyze customer service calls and provide direct, no-sugar-coating feedback.
                    The calls are typically in Hindi or a mix of Hindi and English (Hinglish).
                    
                    IMPORTANT: Also extract the customer's name if they mention it during the call.
                    
                    IMPORTANT: The transcript will be in Hindi, but ALL your analysis MUST be in ENGLISH."""
                ).with_model("openai", "gpt-5.2")
                
                analysis_prompt = f"""Analyze this customer service call transcript and provide a BRUTALLY HONEST JSON response.

IMPORTANT: 
1. Write ALL analysis in ENGLISH
2. Extract the CUSTOMER'S NAME if they mention it (e.g., "Mera naam Rajesh hai" means "My name is Rajesh")
3. Be direct about problems and mistakes

Required JSON structure:
{{
    "customer_name_detected": "Customer's name if mentioned in call, or null if not mentioned",
    "customer_name_confidence": "high/medium/low - how confident are you about the name",
    "summary": "Brief 2-3 sentence summary in ENGLISH",
    "customer_intent": "What the customer really wanted",
    "what_went_well": ["Things agent did correctly"],
    "what_went_wrong": ["SPECIFIC mistakes - be blunt"],
    "agent_tone_assessment": "Honest assessment of agent's tone",
    "customer_tone_assessment": "How did the customer sound",
    "improvement_advice": ["SPECIFIC actionable advice for the agent"],
    "key_points": ["Key discussion points"],
    "action_items": ["Follow-up actions needed"],
    "customer_satisfaction_likely": "high/medium/low",
    "issue_resolved": true/false,
    "suggested_outcome": "sale_completed/quote_sent/callback_scheduled/not_interested/issue_resolved/ticket_created/escalated/information_provided/wrong_number/no_answer/follow_up_required",
    "call_quality_score": 1-10,
    "red_flags": ["Serious issues if any"]
}}

Transcript (Hindi):
{transcript_text}

Respond ONLY with valid JSON."""
                
                analysis_response = await chat.send_message(UserMessage(text=analysis_prompt))
                
                # Parse JSON
                import json
                try:
                    analysis_text = analysis_response.strip()
                    if analysis_text.startswith("```json"):
                        analysis_text = analysis_text[7:]
                    if analysis_text.startswith("```"):
                        analysis_text = analysis_text[3:]
                    if analysis_text.endswith("```"):
                        analysis_text = analysis_text[:-3]
                    
                    analysis_json = json.loads(analysis_text.strip())
                except json.JSONDecodeError:
                    analysis_json = {"summary": analysis_response[:500], "raw_response": True}
                
                # Store analysis
                ai_analysis = {
                    "transcript": transcript_text,
                    "analysis": analysis_json,
                    "analyzed_at": datetime.now(timezone.utc).isoformat(),
                    "analyzed_by": "auto_batch"
                }
                
                # Update call with analysis and detected customer name
                update_data = {"ai_analysis": ai_analysis}
                detected_name = analysis_json.get("customer_name_detected")
                if detected_name and analysis_json.get("customer_name_confidence") in ["high", "medium"]:
                    update_data["ai_detected_customer_name"] = detected_name
                
                await db.smartflo_calls.update_one(
                    {"_id": call["_id"]},
                    {"$set": update_data}
                )
                
                analyzed_count += 1
                
            finally:
                if os_module.path.exists(tmp_path):
                    os_module.remove(tmp_path)
                    
        except Exception as e:
            errors.append(f"Call {call.get('id', 'unknown')}: {str(e)}")
    
    return {
        "status": "complete",
        "analyzed": analyzed_count,
        "errors": errors,
        "message": f"Analyzed {analyzed_count} calls"
    }


@api_router.get("/smartflo/calls/{call_id}/customer-suggestion")
async def get_customer_name_suggestion(
    call_id: str,
    user: dict = Depends(get_current_user)
):
    """Get AI-detected customer name suggestion for a call"""
    call = await db.smartflo_calls.find_one({"$or": [{"id": call_id}, {"uuid": call_id}]})
    if not call:
        raise HTTPException(status_code=404, detail="Call not found")
    
    detected_name = call.get("ai_detected_customer_name")
    ai_analysis = call.get("ai_analysis", {})
    analysis = ai_analysis.get("analysis", {})
    
    return {
        "detected_name": detected_name or analysis.get("customer_name_detected"),
        "confidence": analysis.get("customer_name_confidence"),
        "caller_phone": call.get("caller_id_number") or call.get("caller_phone"),
        "matched_customer_id": call.get("matched_customer_id"),
        "matched_customer_name": call.get("matched_customer_name")
    }


@api_router.post("/smartflo/calls/{call_id}/link-customer")
async def link_call_to_customer(
    call_id: str,
    customer_id: Optional[str] = None,
    customer_name: Optional[str] = None,
    create_new: bool = False,
    user: dict = Depends(get_current_user)
):
    """Link a call to an existing customer or create a new customer record"""
    call = await db.smartflo_calls.find_one({"$or": [{"id": call_id}, {"uuid": call_id}]})
    if not call:
        raise HTTPException(status_code=404, detail="Call not found")
    
    caller_phone = call.get("caller_id_number") or call.get("caller_phone")
    if not caller_phone:
        raise HTTPException(status_code=400, detail="Call has no phone number")
    
    # Clean phone number
    clean_phone = caller_phone.replace("+91", "").replace("-", "").replace(" ", "").strip()
    if len(clean_phone) > 10:
        clean_phone = clean_phone[-10:]
    
    if customer_id:
        # Link to existing customer
        customer = await db.customers.find_one({"id": customer_id})
        if not customer:
            raise HTTPException(status_code=404, detail="Customer not found")
        
        await db.smartflo_calls.update_one(
            {"_id": call["_id"]},
            {"$set": {
                "matched_customer_id": customer_id,
                "matched_customer_name": customer.get("name"),
                "linked_by": user.get("email"),
                "linked_at": datetime.now(timezone.utc).isoformat()
            }}
        )
        
        return {"message": "Call linked to customer", "customer_name": customer.get("name")}
    
    elif create_new and customer_name:
        # Create new customer record
        import uuid as uuid_lib
        
        new_customer = {
            "id": str(uuid_lib.uuid4()),
            "name": customer_name,
            "phone": clean_phone,
            "source": "call_center",
            "created_at": datetime.now(timezone.utc).isoformat(),
            "created_by": user.get("email"),
            "customer_type": "B2C"
        }
        
        await db.customers.insert_one(new_customer)
        
        # Link call to new customer
        await db.smartflo_calls.update_one(
            {"_id": call["_id"]},
            {"$set": {
                "matched_customer_id": new_customer["id"],
                "matched_customer_name": customer_name,
                "linked_by": user.get("email"),
                "linked_at": datetime.now(timezone.utc).isoformat()
            }}
        )
        
        # Update other calls from same number
        await db.smartflo_calls.update_many(
            {
                "$or": [
                    {"caller_id_number": {"$regex": clean_phone}},
                    {"caller_phone": {"$regex": clean_phone}}
                ],
                "matched_customer_id": {"$exists": False}
            },
            {"$set": {
                "matched_customer_id": new_customer["id"],
                "matched_customer_name": customer_name
            }}
        )
        
        return {"message": "Customer created and linked", "customer_id": new_customer["id"], "customer_name": customer_name}
    
    else:
        raise HTTPException(status_code=400, detail="Either customer_id or (create_new + customer_name) required")


@api_router.get("/smartflo/customer-call-history/{phone}")
async def get_customer_call_history(
    phone: str,
    user: dict = Depends(get_current_user)
):
    """Get call history for a phone number"""
    clean_phone = phone.replace("+91", "").replace("-", "").replace(" ", "").strip()
    if len(clean_phone) > 10:
        clean_phone = clean_phone[-10:]
    
    calls = await db.smartflo_calls.find(
        {
            "$or": [
                {"caller_id_number": {"$regex": clean_phone}},
                {"caller_phone": {"$regex": clean_phone}}
            ]
        },
        {"_id": 0, "id": 1, "received_at": 1, "agent_name": 1, "raw_data.duration": 1, "outcome": 1, "matched_customer_name": 1}
    ).sort("received_at", -1).limit(50).to_list(50)
    
    # Find linked customer
    customer = await db.customers.find_one(
        {"phone": {"$regex": clean_phone}},
        {"_id": 0, "id": 1, "name": 1, "phone": 1, "customer_type": 1}
    )
    
    return {
        "phone": phone,
        "customer": customer,
        "total_calls": len(calls),
        "calls": calls
    }


# ============== OPERATIONS ASSISTANT BOT ==============

async def bot_search_order(query: str):
    """Search for order by ID, phone, or customer name across all tables"""
    results = []
    query = query.strip()
    
    # Search in pending_fulfillment
    pf_query = {
        "$or": [
            {"order_id": {"$regex": query, "$options": "i"}},
            {"tracking_id": {"$regex": query, "$options": "i"}},
            {"customer_name": {"$regex": query, "$options": "i"}},
            {"customer_phone": {"$regex": query, "$options": "i"}},
            {"phone": {"$regex": query, "$options": "i"}}
        ]
    }
    pf_orders = await db.pending_fulfillment.find(pf_query, {"_id": 0}).sort("created_at", -1).limit(10).to_list(10)
    for order in pf_orders:
        order["_source"] = "pending_fulfillment"
        order["_source_display"] = "Pending Fulfillment" if order.get("status") == "awaiting_stock" else "Ready to Dispatch"
        results.append(order)
    
    # Search in dispatches
    dispatch_query = {
        "$or": [
            {"order_id": {"$regex": query, "$options": "i"}},
            {"tracking_id": {"$regex": query, "$options": "i"}},
            {"customer_name": {"$regex": query, "$options": "i"}},
            {"phone": {"$regex": query, "$options": "i"}},
            {"marketplace_order_id": {"$regex": query, "$options": "i"}}
        ]
    }
    dispatches = await db.dispatches.find(dispatch_query, {"_id": 0}).sort("created_at", -1).limit(10).to_list(10)
    for order in dispatches:
        order["_source"] = "dispatches"
        order["_source_display"] = "Dispatched"
        results.append(order)
    
    # Search in amazon_orders
    amazon_query = {
        "$or": [
            {"amazon_order_id": {"$regex": query, "$options": "i"}},
            {"order_id": {"$regex": query, "$options": "i"}},
            {"buyer_name": {"$regex": query, "$options": "i"}},
            {"buyer_phone": {"$regex": query, "$options": "i"}}
        ],
        "crm_status": {"$nin": ["dispatched", "cancelled"]}
    }
    amazon_orders = await db.amazon_orders.find(amazon_query, {"_id": 0}).sort("purchase_date", -1).limit(10).to_list(10)
    for order in amazon_orders:
        order["_source"] = "amazon_orders"
        order["_source_display"] = "Amazon Order (New)"
        order["customer_name"] = order.get("buyer_name")
        order["customer_phone"] = order.get("buyer_phone")
        order["order_id"] = order.get("amazon_order_id")
        results.append(order)
    
    return results


async def bot_get_order_fields(order: dict):
    """Analyze order and determine known vs missing fields"""
    known_fields = {}
    missing_fields = []
    
    # Determine order source/type
    order_source = order.get("order_source") or order.get("source") or ""
    is_easyship = order_source.lower() in ["easyship", "easy_ship", "amazon_easy_ship"]
    fulfillment_channel = order.get("fulfillment_channel", "").upper()
    is_amazon_fba = fulfillment_channel == "AFN"  # Amazon Fulfilled Network
    
    # Order ID
    order_id = order.get("order_id") or order.get("amazon_order_id") or order.get("marketplace_order_id")
    if order_id:
        known_fields["order_id"] = order_id
    else:
        missing_fields.append("order_id")
    
    # Customer name - always required
    customer_name = order.get("customer_name") or order.get("buyer_name")
    if customer_name:
        known_fields["customer_name"] = customer_name
    else:
        missing_fields.append("customer_name")
    
    # Phone - NOT required for EasyShip/FBA orders
    phone = order.get("customer_phone") or order.get("phone") or order.get("buyer_phone")
    if phone:
        known_fields["phone"] = phone
    elif not is_easyship and not is_amazon_fba:
        # Only mark as missing if not EasyShip/FBA
        missing_fields.append("phone")
    else:
        known_fields["phone"] = "(Not required for EasyShip)"
    
    # Address - NOT required for EasyShip/FBA (Amazon handles shipping)
    address = order.get("address") or order.get("shipping_address")
    if address:
        known_fields["address"] = address
    elif not is_easyship and not is_amazon_fba:
        missing_fields.append("address")
    else:
        known_fields["address"] = "(Handled by Amazon)"
    
    # State
    state = order.get("state") or order.get("shipping_state")
    if state:
        known_fields["state"] = state
    elif not is_easyship and not is_amazon_fba:
        missing_fields.append("state")
    else:
        known_fields["state"] = "(Handled by Amazon)"
    
    # Pincode
    pincode = order.get("pincode") or order.get("shipping_pincode") or order.get("postal_code")
    if pincode:
        known_fields["pincode"] = pincode
    elif not is_easyship and not is_amazon_fba:
        missing_fields.append("pincode")
    else:
        known_fields["pincode"] = "(Handled by Amazon)"
    
    # Tracking ID
    tracking_id = order.get("tracking_id") or order.get("tracking_number")
    if tracking_id:
        known_fields["tracking_id"] = tracking_id
    else:
        missing_fields.append("tracking_id")
    
    # Invoice
    if order.get("invoice_url") or order.get("invoice_file"):
        known_fields["invoice"] = "Uploaded"
    else:
        missing_fields.append("invoice")
    
    # Shipping label
    if order.get("label_url") or order.get("shipping_label"):
        known_fields["shipping_label"] = "Uploaded"
    else:
        missing_fields.append("shipping_label")
    
    # Product info
    if order.get("items"):
        items_display = ", ".join([f"{i.get('master_sku_name') or i.get('title', 'Item')} x{i.get('quantity', 1)}" for i in order.get("items", [])])
        known_fields["product"] = items_display
    elif order.get("master_sku_name"):
        known_fields["product"] = f"{order.get('master_sku_name')} x{order.get('quantity', 1)}"
    
    if order.get("order_total") or order.get("amount"):
        known_fields["amount"] = order.get("order_total") or order.get("amount")
    
    return {
        "known": known_fields, 
        "missing": missing_fields, 
        "source": order.get("_source", ""), 
        "status": order.get("status", "unknown"),
        "is_easyship": is_easyship,
        "is_amazon_fba": is_amazon_fba
    }


async def bot_get_customer_history(phone: str):
    """Get customer's previous orders and address"""
    clean_phone = phone.replace("+91", "").replace("-", "").replace(" ", "").strip()
    if len(clean_phone) > 10:
        clean_phone = clean_phone[-10:]
    
    previous_orders = await db.dispatches.find(
        {"phone": {"$regex": clean_phone}},
        {"_id": 0, "customer_name": 1, "address": 1, "city": 1, "state": 1, "pincode": 1, "created_at": 1}
    ).sort("created_at", -1).limit(5).to_list(5)
    
    pf_orders = await db.pending_fulfillment.find(
        {"$or": [{"customer_phone": {"$regex": clean_phone}}, {"phone": {"$regex": clean_phone}}]},
        {"_id": 0, "customer_name": 1, "address": 1, "city": 1, "state": 1, "pincode": 1, "created_at": 1}
    ).sort("created_at", -1).limit(5).to_list(5)
    
    all_orders = previous_orders + pf_orders
    
    if all_orders:
        latest = all_orders[0]
        return {
            "is_repeat_customer": True,
            "total_orders": len(all_orders),
            "last_address": {
                "address": latest.get("address"),
                "city": latest.get("city"),
                "state": latest.get("state"),
                "pincode": latest.get("pincode")
            },
            "customer_name": latest.get("customer_name")
        }
    return {"is_repeat_customer": False}


@api_router.get("/bot/daily-briefing")
async def bot_daily_briefing(user: dict = Depends(require_roles(["admin", "accountant"]))):
    """Get daily operations briefing for accountant"""
    now = datetime.now(timezone.utc)
    today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)
    yesterday_start = today_start - timedelta(days=1)
    three_days_ago = (now - timedelta(days=3)).isoformat()
    five_days_ago = (now - timedelta(days=5)).isoformat()
    
    dispatched_yesterday = await db.dispatches.count_documents({
        "created_at": {"$gte": yesterday_start.isoformat(), "$lt": today_start.isoformat()}
    })
    dispatched_today = await db.dispatches.count_documents({
        "created_at": {"$gte": today_start.isoformat()}
    })
    
    stuck_ready = await db.pending_fulfillment.find({
        "status": "ready_to_dispatch",
        "created_at": {"$lt": three_days_ago}
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "created_at": 1}).to_list(100)
    
    stuck_awaiting = await db.pending_fulfillment.find({
        "status": "awaiting_stock",
        "created_at": {"$lt": five_days_ago}
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "master_sku_name": 1, "created_at": 1}).to_list(100)
    
    missing_invoices = await db.pending_fulfillment.find({
        "status": {"$in": ["ready_to_dispatch", "awaiting_stock"]},
        "$or": [{"invoice_url": {"$exists": False}}, {"invoice_url": None}, {"invoice_url": ""}]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1}).to_list(100)
    
    missing_tracking = await db.pending_fulfillment.find({
        "status": {"$in": ["ready_to_dispatch", "awaiting_stock"]},
        "$or": [{"tracking_id": {"$exists": False}}, {"tracking_id": None}, {"tracking_id": ""}]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1}).to_list(100)
    
    new_amazon = await db.amazon_orders.count_documents({
        "crm_status": {"$nin": ["dispatched", "cancelled", "in_pending_fulfillment"]}
    })
    
    production_suggestions = []
    low_stock_items = await db.pending_fulfillment.aggregate([
        {"$match": {"status": "awaiting_stock"}},
        {"$group": {"_id": "$master_sku_id", "count": {"$sum": 1}, "sku_name": {"$first": "$master_sku_name"}}},
        {"$sort": {"count": -1}},
        {"$limit": 10}
    ]).to_list(10)
    
    for item in low_stock_items:
        if item.get("_id"):
            production_suggestions.append({
                "master_sku_id": item["_id"],
                "master_sku_name": item.get("sku_name", "Unknown"),
                "pending_orders": item["count"]
            })
    
    return {
        "date": now.isoformat(),
        "yesterday": {"dispatched": dispatched_yesterday},
        "today": {"dispatched": dispatched_today},
        "urgent": {
            "stuck_ready_to_dispatch": len(stuck_ready),
            "stuck_ready_list": stuck_ready[:5],
            "missing_invoices": len(missing_invoices),
            "missing_invoices_list": missing_invoices[:5],
            "missing_tracking": len(missing_tracking)
        },
        "attention": {
            "stuck_awaiting_stock": len(stuck_awaiting),
            "stuck_awaiting_list": stuck_awaiting[:5],
            "new_amazon_orders": new_amazon,
            "production_suggestions": production_suggestions[:5]
        }
    }


@api_router.get("/bot/queue-health")
async def bot_queue_health(user: dict = Depends(require_roles(["admin", "accountant"]))):
    """Get health status of all queues"""
    now = datetime.now(timezone.utc)
    three_days_ago = (now - timedelta(days=3)).isoformat()
    
    pf_total = await db.pending_fulfillment.count_documents({"status": {"$nin": ["dispatched", "cancelled"]}})
    pf_awaiting = await db.pending_fulfillment.count_documents({"status": "awaiting_stock"})
    pf_ready = await db.pending_fulfillment.count_documents({"status": "ready_to_dispatch"})
    pf_stuck = await db.pending_fulfillment.count_documents({
        "status": "ready_to_dispatch",
        "created_at": {"$lt": three_days_ago}
    })
    
    missing_invoice = await db.pending_fulfillment.count_documents({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"invoice_url": {"$exists": False}}, {"invoice_url": None}, {"invoice_url": ""}]
    })
    missing_tracking = await db.pending_fulfillment.count_documents({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"tracking_id": {"$exists": False}}, {"tracking_id": None}, {"tracking_id": ""}]
    })
    missing_label = await db.pending_fulfillment.count_documents({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"label_url": {"$exists": False}}, {"label_url": None}, {"label_url": ""}]
    })
    
    amazon_new = await db.amazon_orders.count_documents({
        "crm_status": {"$nin": ["dispatched", "cancelled", "in_pending_fulfillment"]}
    })
    amazon_today = await db.amazon_orders.count_documents({
        "synced_at": {"$gte": now.replace(hour=0, minute=0, second=0).isoformat()}
    })
    dispatched_today = await db.dispatches.count_documents({
        "created_at": {"$gte": now.replace(hour=0, minute=0, second=0).isoformat()}
    })
    
    return {
        "pending_fulfillment": {"total": pf_total, "awaiting_stock": pf_awaiting, "ready_to_dispatch": pf_ready, "stuck_over_3_days": pf_stuck},
        "missing_data": {"invoices": missing_invoice, "tracking_ids": missing_tracking, "shipping_labels": missing_label},
        "amazon_orders": {"new_unprocessed": amazon_new, "synced_today": amazon_today},
        "dispatched": {"today": dispatched_today}
    }


@api_router.get("/bot/stuck-orders")
async def bot_stuck_orders(days: int = 3, user: dict = Depends(require_roles(["admin", "accountant"]))):
    """Get orders stuck for more than specified days"""
    cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
    
    stuck_ready = await db.pending_fulfillment.find({
        "status": "ready_to_dispatch",
        "created_at": {"$lt": cutoff}
    }, {"_id": 0}).sort("created_at", 1).to_list(50)
    
    for order in stuck_ready:
        fields = await bot_get_order_fields(order)
        order["missing_fields"] = fields["missing"]
        order["days_stuck"] = (datetime.now(timezone.utc) - datetime.fromisoformat(order["created_at"].replace("Z", "+00:00"))).days
    
    stuck_awaiting = await db.pending_fulfillment.find({
        "status": "awaiting_stock",
        "created_at": {"$lt": cutoff}
    }, {"_id": 0}).sort("created_at", 1).to_list(50)
    
    for order in stuck_awaiting:
        order["days_stuck"] = (datetime.now(timezone.utc) - datetime.fromisoformat(order["created_at"].replace("Z", "+00:00"))).days
    
    return {"ready_to_dispatch": stuck_ready, "awaiting_stock": stuck_awaiting, "total_stuck": len(stuck_ready) + len(stuck_awaiting)}


@api_router.get("/bot/missing-data")
async def bot_missing_data(user: dict = Depends(require_roles(["admin", "accountant"]))):
    """Get all orders with missing data"""
    
    missing_invoices = await db.pending_fulfillment.find({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"invoice_url": {"$exists": False}}, {"invoice_url": None}, {"invoice_url": ""}]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "customer_phone": 1, "created_at": 1, "status": 1}).to_list(100)
    
    missing_tracking = await db.pending_fulfillment.find({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"tracking_id": {"$exists": False}}, {"tracking_id": None}, {"tracking_id": ""}]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "customer_phone": 1, "created_at": 1, "status": 1}).to_list(100)
    
    missing_labels = await db.pending_fulfillment.find({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"label_url": {"$exists": False}}, {"label_url": None}, {"label_url": ""}]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "customer_phone": 1, "created_at": 1, "status": 1}).to_list(100)
    
    missing_phones = await db.pending_fulfillment.find({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$and": [
            {"$or": [{"customer_phone": {"$exists": False}}, {"customer_phone": None}, {"customer_phone": ""}]},
            {"$or": [{"phone": {"$exists": False}}, {"phone": None}, {"phone": ""}]}
        ]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "created_at": 1, "status": 1}).to_list(100)
    
    missing_addresses = await db.pending_fulfillment.find({
        "status": {"$nin": ["dispatched", "cancelled"]},
        "$or": [{"address": {"$exists": False}}, {"address": None}, {"address": ""}]
    }, {"_id": 0, "id": 1, "order_id": 1, "customer_name": 1, "customer_phone": 1, "created_at": 1, "status": 1}).to_list(100)
    
    return {
        "invoices": {"count": len(missing_invoices), "orders": missing_invoices},
        "tracking_ids": {"count": len(missing_tracking), "orders": missing_tracking},
        "shipping_labels": {"count": len(missing_labels), "orders": missing_labels},
        "phone_numbers": {"count": len(missing_phones), "orders": missing_phones},
        "addresses": {"count": len(missing_addresses), "orders": missing_addresses},
        "total_issues": len(missing_invoices) + len(missing_tracking) + len(missing_labels) + len(missing_phones) + len(missing_addresses)
    }


@api_router.get("/bot/production-suggestions")
async def bot_production_suggestions(user: dict = Depends(require_roles(["admin", "accountant"]))):
    """Get production suggestions based on pending orders and stock levels"""
    
    awaiting_items = await db.pending_fulfillment.aggregate([
        {"$match": {"status": "awaiting_stock"}},
        {"$group": {
            "_id": "$master_sku_id",
            "pending_orders": {"$sum": 1},
            "total_quantity": {"$sum": "$quantity"},
            "sku_name": {"$first": "$master_sku_name"},
            "sku_code": {"$first": "$sku_code"},
            "oldest_order": {"$min": "$created_at"},
            "customer_names": {"$push": "$customer_name"}
        }},
        {"$sort": {"pending_orders": -1}}
    ]).to_list(20)
    
    suggestions = []
    for item in awaiting_items:
        if not item.get("_id"):
            continue
        
        stock_entry = await db.inventory_ledger.find_one(
            {"item_id": item["_id"], "item_type": "master_sku"},
            sort=[("created_at", -1)]
        )
        current_stock = stock_entry.get("running_balance", 0) if stock_entry else 0
        
        if item.get("oldest_order"):
            oldest = datetime.fromisoformat(item["oldest_order"].replace("Z", "+00:00"))
            days_waiting = (datetime.now(timezone.utc) - oldest).days
        else:
            days_waiting = 0
        
        severity = "critical" if current_stock == 0 and item["pending_orders"] > 0 else "warning" if current_stock < item["total_quantity"] else "info"
        
        suggestions.append({
            "master_sku_id": item["_id"],
            "master_sku_name": item.get("sku_name", "Unknown"),
            "sku_code": item.get("sku_code"),
            "current_stock": current_stock,
            "pending_orders": item["pending_orders"],
            "total_quantity_needed": item["total_quantity"],
            "days_waiting": days_waiting,
            "customers_waiting": item.get("customer_names", [])[:5],
            "severity": severity,
            "recommended_production": max(item["total_quantity"] - current_stock, 0) + 5
        })
    
    return {"suggestions": suggestions, "critical_count": len([s for s in suggestions if s["severity"] == "critical"]), "warning_count": len([s for s in suggestions if s["severity"] == "warning"])}


@api_router.post("/bot/search")
async def bot_search(
    query: str = Form(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Search for orders by ID, phone, or name"""
    results = await bot_search_order(query)
    
    enriched = []
    for order in results:
        fields = await bot_get_order_fields(order)
        order["known_fields"] = fields["known"]
        order["missing_fields"] = fields["missing"]
        enriched.append(order)
    
    return {"results": enriched, "count": len(enriched)}


@api_router.post("/bot/update-field")
async def bot_update_field(
    order_id: str = Form(...),
    field: str = Form(...),
    value: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Update a specific field on an order"""
    
    order = await db.pending_fulfillment.find_one({"id": order_id})
    if not order:
        raise HTTPException(status_code=404, detail="Order not found")
    
    update_data = {"updated_at": datetime.now(timezone.utc).isoformat()}
    
    field_map = {
        "phone": "customer_phone",
        "customer_name": "customer_name",
        "address": "address",
        "city": "city",
        "state": "state",
        "pincode": "pincode",
        "tracking_id": "tracking_id"
    }
    db_field = field_map.get(field, field)
    update_data[db_field] = value
    
    if field == "phone":
        update_data["phone"] = value
    
    await db.pending_fulfillment.update_one({"id": order_id}, {"$set": update_data})
    
    updated_order = await db.pending_fulfillment.find_one({"id": order_id}, {"_id": 0})
    fields = await bot_get_order_fields(updated_order)
    
    return {"message": f"{field} updated successfully", "remaining_fields": fields["missing"], "is_complete": len(fields["missing"]) == 0}


@api_router.post("/bot/upload-file")
async def bot_upload_file(
    order_id: str = Form(...),
    field: str = Form(...),
    file: UploadFile = File(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Upload a file (invoice, shipping label, or eway bill) for an order.
    If order doesn't exist in pending_fulfillment yet (Amazon order pre-processing),
    creates a temporary entry to store the files.
    
    Files are uploaded to NAS storage via File API for persistence and dispatcher access."""
    
    now = datetime.now(timezone.utc)
    
    # Search by multiple fields: id, order_id, or amazon_order_id
    order = await db.pending_fulfillment.find_one({
        "$or": [
            {"id": order_id},
            {"order_id": order_id},
            {"amazon_order_id": order_id}
        ]
    })
    
    # If no entry exists, create a temporary one to store the uploaded files
    if not order:
        # Check if this is an Amazon order
        amazon_order = await db.amazon_orders.find_one({
            "$or": [
                {"amazon_order_id": order_id},
                {"order_id": order_id}
            ]
        }, {"_id": 0})
        
        if amazon_order:
            # Create temporary pending_fulfillment entry
            temp_id = str(uuid.uuid4())
            order = {
                "id": temp_id,
                "order_id": order_id,
                "amazon_order_id": order_id,
                "status": "collecting_info",
                "created_at": now.isoformat(),
                "updated_at": now.isoformat()
            }
            await db.pending_fulfillment.insert_one(order)
        else:
            raise HTTPException(status_code=404, detail="Order not found")
    
    # Use the actual database id for updates
    db_id = order.get("id")
    
    file_content = await file.read()
    
    # Determine folder based on field type
    folder_map = {
        "invoice": "Dispatches",
        "shipping_label": "Dispatches",
        "eway_bill_copy": "Dispatches"
    }
    folder = folder_map.get(field, "Dispatches")
    
    # Generate filename prefix for clarity
    safe_order_id = order_id.replace("-", "")[:12] if order_id else "unknown"
    filename_prefix = f"{safe_order_id}_{field}"
    
    try:
        # Upload to NAS storage via File API
        relative_path, storage_type = await storage_upload(
            file_content,
            folder,
            file.filename,
            filename_prefix
        )
        file_url = f"/api/files/{relative_path}"
        logger.info(f"Bot file uploaded to NAS: {relative_path} ({storage_type})")
    except Exception as e:
        logger.error(f"NAS upload failed, falling back to local: {str(e)}")
        # Fallback to local storage if NAS fails
        file_ext = file.filename.split(".")[-1] if "." in file.filename else "pdf"
        file_name = f"{db_id}_{field}_{uuid.uuid4().hex[:8]}.{file_ext}"
        file_path = f"/app/uploads/bot/{file_name}"
        os.makedirs("/app/uploads/bot", exist_ok=True)
        with open(file_path, "wb") as f:
            f.write(file_content)
        file_url = file_path
    
    # Map field to database column
    field_map = {
        "invoice": "invoice_url", 
        "shipping_label": "label_url",
        "eway_bill_copy": "eway_bill_url"
    }
    db_field = field_map.get(field, field)
    
    await db.pending_fulfillment.update_one(
        {"id": db_id},
        {"$set": {db_field: file_url, "updated_at": now.isoformat()}}
    )
    
    updated_order = await db.pending_fulfillment.find_one({"id": db_id}, {"_id": 0})
    fields = await bot_get_order_fields(updated_order)
    
    return {"message": f"{field} uploaded successfully", "file_url": file_url, "remaining_fields": fields["missing"], "is_complete": len(fields["missing"]) == 0}


class PendingFulfillmentUpdate(BaseModel):
    tracking_id: Optional[str] = None
    customer_name: Optional[str] = None
    customer_phone: Optional[str] = None
    address: Optional[str] = None
    city: Optional[str] = None
    state: Optional[str] = None
    pincode: Optional[str] = None
    serial_number: Optional[str] = None  # Bug 6 fix: Allow serial number update


@api_router.post("/pending-fulfillment/{order_id}/update")
async def update_pending_fulfillment(
    order_id: str,
    data: PendingFulfillmentUpdate,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Update pending fulfillment fields (tracking_id, customer details)"""
    
    # Search by multiple fields
    order = await db.pending_fulfillment.find_one({
        "$or": [
            {"id": order_id},
            {"order_id": order_id},
            {"amazon_order_id": order_id}
        ]
    })
    if not order:
        raise HTTPException(status_code=404, detail="Order not found")
    
    db_id = order.get("id")
    
    # Build update dict with only non-None values
    update_data = {k: v for k, v in data.dict().items() if v is not None}
    if not update_data:
        raise HTTPException(status_code=400, detail="No fields to update")
    
    # DUPLICATE VALIDATION: Check tracking_id before saving
    if data.tracking_id:
        tracking_dup = await check_tracking_id_duplicate(data.tracking_id, db_id)
        if tracking_dup["exists"]:
            raise HTTPException(status_code=400, detail=tracking_dup["message"])
    
    update_data["updated_at"] = datetime.now(timezone.utc).isoformat()
    
    await db.pending_fulfillment.update_one(
        {"id": db_id},
        {"$set": update_data}
    )
    
    return {"message": "Updated successfully", "updated_fields": list(update_data.keys())}


class MoveToPendingFulfillmentRequest(BaseModel):
    amazon_order_id: str
    customer_name: Optional[str] = None
    customer_phone: str
    address: str
    city: str
    state: str
    pincode: str


@api_router.post("/bot/move-to-pending-fulfillment")
async def bot_move_to_pending_fulfillment(
    data: MoveToPendingFulfillmentRequest,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Move an Amazon order to Pending Fulfillment queue after collecting all details.
    If already imported (pending_fulfillment exists), update the customer details instead."""
    
    now = datetime.now(timezone.utc)
    
    # First check if already in pending_fulfillment (already imported via import-amazon-to-crm)
    existing_pf = await db.pending_fulfillment.find_one({
        "$or": [
            {"amazon_order_id": data.amazon_order_id},
            {"order_id": data.amazon_order_id},
            {"id": data.amazon_order_id}  # Also check by pending_fulfillment id
        ]
    })
    
    if existing_pf:
        # Just update the customer details in existing pending_fulfillment
        update_data = {
            "customer_name": data.customer_name or existing_pf.get("customer_name"),
            "customer_phone": data.customer_phone,
            "phone": data.customer_phone,
            "address": data.address,
            "city": data.city,
            "state": data.state,
            "pincode": data.pincode,
            "updated_at": now.isoformat()
        }
        
        # Copy tracking_id and files from temp entry if they exist
        temp_order = await db.pending_fulfillment.find_one({"order_id": data.amazon_order_id})
        if temp_order and temp_order.get("id") != existing_pf.get("id"):
            if temp_order.get("invoice_url"):
                update_data["invoice_url"] = temp_order.get("invoice_url")
            if temp_order.get("label_url"):
                update_data["label_url"] = temp_order.get("label_url")
            if temp_order.get("tracking_id"):
                update_data["tracking_id"] = temp_order.get("tracking_id")
        
        await db.pending_fulfillment.update_one(
            {"id": existing_pf.get("id")},
            {"$set": update_data}
        )
        
        # Get stock info
        master_sku_id = existing_pf.get("master_sku_id")
        stock_info = await get_stock_info_for_pending_fulfillment(master_sku_id, existing_pf)
        
        return {
            "message": "Customer details updated",
            "pending_fulfillment_id": existing_pf.get("id"),
            "order_id": existing_pf.get("order_id") or data.amazon_order_id,
            "stock_info": stock_info
        }
    
    # Find the Amazon order (for new imports)
    amazon_order = await db.amazon_orders.find_one(
        {"$or": [
            {"amazon_order_id": data.amazon_order_id},
            {"order_id": data.amazon_order_id}
        ]},
        {"_id": 0}
    )
    if not amazon_order:
        raise HTTPException(status_code=404, detail="Amazon order not found")
    
    pf_id = str(uuid.uuid4())
    
    # Get customer name from multiple sources
    customer_name = (
        data.customer_name or 
        amazon_order.get("buyer_name") or 
        amazon_order.get("customer_name") or
        amazon_order.get("shipping_address", {}).get("name") or
        amazon_order.get("recipient_name") or
        "Unknown Customer"
    )
    
    # Get master SKU info for stock check
    master_sku_id = None
    master_sku = None
    product_name = None
    sku_code = None
    is_manufactured = False
    current_stock = 0
    
    # Get from mapped items or check SKU mapping
    items = amazon_order.get("items", [])
    if items:
        item = items[0]
        if item.get("master_sku_id"):
            master_sku_id = item["master_sku_id"]
        elif item.get("amazon_sku") or item.get("seller_sku"):
            # Try to find mapping - first with firm_id, then without (for cross-firm SKUs)
            amazon_sku = item.get("amazon_sku") or item.get("seller_sku")
            order_firm_id = amazon_order.get("firm_id")
            
            # First try with firm-specific mapping
            mapping = None
            if order_firm_id:
                mapping = await db.amazon_sku_mappings.find_one({
                    "amazon_sku": amazon_sku,
                    "firm_id": order_firm_id
                }, {"_id": 0})
            
            # Fallback to any mapping without firm filter
            if not mapping:
                mapping = await db.amazon_sku_mappings.find_one({"amazon_sku": amazon_sku}, {"_id": 0})
            
            if mapping:
                master_sku_id = mapping.get("master_sku_id")
        
        if master_sku_id:
            master_sku = await db.master_skus.find_one({"id": master_sku_id}, {"_id": 0})
            if master_sku:
                product_name = master_sku.get("name")
                sku_code = master_sku.get("sku_code")
                is_manufactured = master_sku.get("is_manufactured", False) or master_sku.get("product_type") == "manufactured"
        
        # If still no SKU info, use amazon item info
        if not product_name:
            product_name = item.get("title") or item.get("product_name") or item.get("name")
            sku_code = item.get("amazon_sku") or item.get("seller_sku") or item.get("asin")
    
    # BUG FIX: Use firm from Amazon order, not just first active firm
    firm_id = amazon_order.get("firm_id")
    firm = None
    if firm_id:
        firm = await db.firms.find_one({"id": firm_id, "is_active": True}, {"_id": 0})
    
    # Fallback to default firm only if Amazon order has no firm
    if not firm:
        firm = await db.firms.find_one({"is_active": True}, {"_id": 0})
        firm_id = firm.get("id") if firm else None
    
    # Check current stock
    if master_sku_id and firm_id:
        if is_manufactured:
            # For manufactured items, check finished_good_serials
            stock_count = await db.finished_good_serials.count_documents({
                "master_sku_id": master_sku_id,
                "firm_id": firm_id,
                "status": "in_stock"
            })
            current_stock = stock_count
        else:
            # For traded items, check inventory_ledger running balance
            last_entry = await db.inventory_ledger.find_one(
                {"item_id": master_sku_id, "firm_id": firm_id},
                sort=[("created_at", -1)]
            )
            current_stock = last_entry.get("running_balance", 0) if last_entry else 0
    
    quantity_needed = amazon_order.get("quantity", 1) or sum(i.get("quantity", 1) for i in items)
    in_stock = current_stock >= quantity_needed
    
    # Determine status based on stock
    status = "ready_to_dispatch" if in_stock else "awaiting_stock"
    
    # Create or update pending_fulfillment entry
    pf_data = {
        "id": pf_id,
        "type": "amazon_order",
        "order_id": data.amazon_order_id,
        "amazon_order_id": data.amazon_order_id,
        "order_source": "amazon",
        "customer_name": customer_name,
        "customer_phone": data.customer_phone,
        "phone": data.customer_phone,
        "address": data.address,
        "city": data.city,
        "state": data.state,
        "pincode": data.pincode,
        "master_sku_id": master_sku_id,
        "master_sku_name": product_name,
        "sku_code": sku_code,
        "quantity": quantity_needed,
        "items": items,
        "order_total": amazon_order.get("order_total"),
        "tracking_id": amazon_order.get("tracking_id") or amazon_order.get("tracking_number"),
        "firm_id": firm_id,
        "firm_name": firm.get("name") if firm else None,
        "is_manufactured_item": is_manufactured,
        "fulfillment_channel": amazon_order.get("fulfillment_channel"),
        "is_easy_ship": amazon_order.get("is_easy_ship", False),
        "status": status,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    
    # Copy uploaded files and tracking if they exist in temporary location
    temp_order = await db.pending_fulfillment.find_one({"order_id": data.amazon_order_id})
    if temp_order:
        pf_data["invoice_url"] = temp_order.get("invoice_url")
        pf_data["label_url"] = temp_order.get("label_url")
        # CRITICAL: Also copy tracking_id that was entered earlier
        if temp_order.get("tracking_id"):
            pf_data["tracking_id"] = temp_order.get("tracking_id")
    
    if existing_pf:
        await db.pending_fulfillment.update_one(
            {"id": pf_id},
            {"$set": pf_data}
        )
    else:
        await db.pending_fulfillment.insert_one(pf_data)
    
    # Update amazon_orders with crm_status
    await db.amazon_orders.update_one(
        {"amazon_order_id": data.amazon_order_id},
        {"$set": {"crm_status": "pending", "updated_at": now.isoformat()}}
    )
    
    return {
        "message": "Order moved to Pending Fulfillment",
        "order_id": data.amazon_order_id,
        "pending_fulfillment_id": pf_id,
        "status": status,
        "stock_info": {
            "master_sku_id": master_sku_id,
            "product_name": product_name,
            "sku_code": sku_code,
            "is_manufactured": is_manufactured,
            "current_stock": current_stock,
            "quantity_needed": quantity_needed,
            "in_stock": in_stock
        }
    }


@api_router.post("/bot/dispatch")
async def bot_dispatch_order(
    order_id: str = Form(...),
    serial_numbers: Optional[str] = Form(None),
    tracking_id: Optional[str] = Form(None),
    payment_status: Optional[str] = Form(None),
    invoice_number: Optional[str] = Form(None),
    invoice_value: Optional[float] = Form(None),
    eway_bill_number: Optional[str] = Form(None),
    courier: Optional[str] = Form(None),
    bigship_order_id: Optional[str] = Form(None),
    confirmed: bool = Form(False),
    notes: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Prepare an order for dispatch via bot - with compliance validation.
    NOTE: Accountant prepares the order, DISPATCHER marks it as dispatched.
    This creates a dispatch entry with status 'ready_for_dispatch'.
    """
    
    # Search by multiple fields: id, order_id, or amazon_order_id
    entry = await db.pending_fulfillment.find_one(
        {"$or": [
            {"id": order_id},
            {"order_id": order_id},
            {"amazon_order_id": order_id}
        ]}
    )
    if not entry:
        raise HTTPException(status_code=404, detail="Order not found")
    
    if entry.get("status") == "dispatched":
        raise HTTPException(status_code=400, detail="Order already dispatched")
    
    if entry.get("status") == "cancelled":
        raise HTTPException(status_code=400, detail="Cannot dispatch cancelled order")
    
    # CRITICAL: Check if dispatch entry already exists to prevent duplicates
    existing_dispatch = await db.dispatches.find_one({
        "$or": [
            {"pending_fulfillment_id": entry.get("id")},
            {"pending_fulfillment_id": order_id},
            {"order_id": entry.get("order_id")},
            {"marketplace_order_id": entry.get("amazon_order_id")}
        ],
        "status": {"$ne": "cancelled"}  # Allow re-dispatch if previous was cancelled
    }, {"_id": 0, "dispatch_number": 1, "status": 1})
    
    if existing_dispatch:
        return {
            "message": "Dispatch entry already exists",
            "dispatch_number": existing_dispatch.get("dispatch_number"),
            "status": existing_dispatch.get("status"),
            "duplicate": True
        }
    
    # Determine if EasyShip/FBA (relaxed validation)
    order_source = entry.get("order_source") or entry.get("source") or ""
    is_easyship = order_source.lower() in ["easyship", "easy_ship", "amazon_easy_ship"]
    fulfillment_channel = entry.get("fulfillment_channel", "").upper()
    is_amazon_fba = fulfillment_channel == "AFN"
    is_offline_order = order_source.lower() == "offline" or entry.get("type") == "offline_order"
    
    # COMPLIANCE CHECKS
    errors = []
    
    # 1. Tracking ID - required for Amazon MFN, optional for offline/easyship/FBA
    final_tracking = tracking_id or entry.get("tracking_id")
    if not final_tracking and not is_offline_order and not is_easyship and not is_amazon_fba:
        errors.append("Tracking ID is required")
    elif final_tracking:
        # Check for duplicate tracking ID
        tracking_dup = await check_tracking_id_duplicate(final_tracking, entry.get("id"))
        if tracking_dup["exists"]:
            errors.append(tracking_dup["message"])
    
    # 2. Invoice - required for Amazon MFN, NOT required for offline orders (invoice is external)
    if not is_offline_order and not is_easyship and not is_amazon_fba:
        if not entry.get("invoice_url"):
            errors.append("Invoice must be uploaded")
    
    # 3. Shipping label - required for Amazon MFN, NOT required for offline/Bigship orders
    # If bigship_order_id is provided, label can be downloaded from Bigship
    has_bigship_label = bigship_order_id is not None
    if not is_offline_order and not is_easyship and not is_amazon_fba and not has_bigship_label:
        if not entry.get("label_url"):
            errors.append("Shipping label must be uploaded (or generate via Bigship)")
    
    # 4. Invoice number duplicate check (if provided)
    final_invoice_number = invoice_number or entry.get("external_invoice_number") or entry.get("invoice_number")
    if final_invoice_number:
        invoice_dup = await check_invoice_number_duplicate(final_invoice_number, entry.get("id"))
        if invoice_dup["exists"]:
            errors.append(invoice_dup["message"])
    
    # 5. E-Way Bill required if invoice > 50,000
    order_total = invoice_value or entry.get("order_total") or entry.get("grand_total") or entry.get("amount") or 0
    if order_total > 50000:
        final_eway = eway_bill_number or entry.get("eway_bill_number")
        if not final_eway:
            errors.append(f"E-Way Bill Number is required for invoice value ₹{order_total:,.2f} (exceeds ₹50,000)")
        # E-way bill copy only required for non-offline orders
        if not is_offline_order and not entry.get("eway_bill_url"):
            errors.append("E-Way Bill copy must be uploaded for invoice > ₹50,000")
    
    # 6. Must be confirmed
    if not confirmed:
        errors.append("Dispatch must be confirmed by accountant")
    
    if errors:
        # Bug 5 Fix: Add helpful context to error messages
        order_type = "Amazon MFN" if not is_easyship and not is_amazon_fba and not is_offline_order else (
            "EasyShip" if is_easyship else ("Amazon FBA" if is_amazon_fba else "Offline Order")
        )
        error_context = {
            "errors": errors, 
            "message": f"Compliance checks failed for {order_type} order",
            "order_type": order_type,
            "order_id": entry.get("order_id"),
            "help": {
                "tracking_required": not is_offline_order and not is_easyship and not is_amazon_fba,
                "invoice_required": not is_offline_order and not is_easyship and not is_amazon_fba,
                "label_required": not is_offline_order and not is_easyship and not is_amazon_fba,
                "eway_bill_threshold": 50000
            }
        }
        raise HTTPException(status_code=400, detail=error_context)
    
    # Update tracking_id and other fields in pending_fulfillment
    update_data = {"updated_at": datetime.now(timezone.utc).isoformat()}
    if tracking_id:
        update_data["tracking_id"] = tracking_id
    if payment_status:
        update_data["payment_status"] = payment_status
    if invoice_number:
        update_data["invoice_number"] = invoice_number
    if invoice_value:
        update_data["order_total"] = invoice_value
        update_data["amount"] = invoice_value
    if eway_bill_number:
        update_data["eway_bill_number"] = eway_bill_number
    if serial_numbers:
        update_data["serial_number"] = serial_numbers
    if courier:
        update_data["courier"] = courier
        update_data["courier_name"] = courier
    if bigship_order_id:
        update_data["bigship_order_id"] = bigship_order_id
    
    # Mark as ready_to_dispatch in pending_fulfillment
    update_data["status"] = "ready_to_dispatch"
    update_data["prepared_by"] = user["id"]
    update_data["prepared_by_name"] = f"{user['first_name']} {user['last_name']}"
    update_data["prepared_at"] = datetime.now(timezone.utc).isoformat()
    
    # Use the entry's actual id field, not the search parameter
    entry_id = entry.get("id")
    await db.pending_fulfillment.update_one({"id": entry_id}, {"$set": update_data})
    
    # Create dispatch entry with status 'ready_for_dispatch' for dispatcher
    now = datetime.now(timezone.utc)
    dispatch_id = str(uuid.uuid4())
    
    # Generate dispatch number
    today_str = now.strftime("%Y%m%d")
    count = await db.dispatches.count_documents({"created_at": {"$regex": f"^{now.strftime('%Y-%m-%d')}"}})
    dispatch_number = f"DSP-{today_str}-{count + 1:04d}"
    
    # Get firm info
    firm = None
    if entry.get("firm_id"):
        firm = await db.firms.find_one({"id": entry["firm_id"]}, {"_id": 0})
    
    # Get master SKU info
    master_sku = None
    if entry.get("master_sku_id"):
        master_sku = await db.master_skus.find_one({"id": entry["master_sku_id"]}, {"_id": 0})
    
    # Determine dispatch type and order source based on entry type
    dispatch_type = "amazon_order" if entry.get("type") == "amazon_order" else "new_order"
    final_order_source = entry.get("order_source", "amazon" if entry.get("type") == "amazon_order" else "direct")
    
    # CRITICAL: Amazon orders have GST-inclusive pricing
    # We need to reverse-calculate taxable value for proper invoicing
    is_amazon_order = final_order_source.lower() in ["amazon", "flipkart", "marketplace"]
    gst_rate = master_sku.get("gst_rate", 18) if master_sku else 18
    
    # invoice_value is the total (GST inclusive for marketplace orders)
    final_invoice_value = order_total
    
    if is_amazon_order and final_invoice_value > 0:
        # Amazon price is GST-inclusive, calculate taxable value
        taxable_value = round(final_invoice_value / (1 + gst_rate / 100), 2)
        gst_amount = round(final_invoice_value - taxable_value, 2)
    else:
        # Direct orders - taxable value equals order total (GST added separately)
        taxable_value = final_invoice_value
        gst_amount = round(taxable_value * (gst_rate / 100), 2)
    
    # FIX: Extract serial numbers from items array for offline orders
    all_serial_numbers = []
    item_serials_list = []
    items = entry.get("items") or []
    
    for item in items:
        item_serials = item.get("serial_numbers") or []
        if item_serials:
            all_serial_numbers.extend(item_serials)
            item_serials_list.append({
                "master_sku_id": item.get("master_sku_id"),
                "product_name": item.get("product_name"),
                "serial_numbers": item_serials
            })
    
    # Use serials from items if no direct serial_numbers provided
    final_serial_numbers = serial_numbers or entry.get("serial_number") or (all_serial_numbers[0] if len(all_serial_numbers) == 1 else None)
    
    dispatch_doc = {
        "id": dispatch_id,
        "dispatch_number": dispatch_number,
        "dispatch_type": "offline_order" if is_offline_order else ("amazon_order" if entry.get("type") == "amazon_order" else "new_order"),
        "order_source": final_order_source,
        "is_easyship": is_easyship,
        "is_amazon_fba": is_amazon_fba,
        "is_offline_order": is_offline_order,
        "is_marketplace_order": is_amazon_order,
        "price_is_gst_inclusive": is_amazon_order,  # Flag for invoice generation
        "firm_id": entry.get("firm_id"),
        "firm_name": firm.get("name") if firm else None,
        "master_sku_id": entry.get("master_sku_id"),
        "master_sku_name": entry.get("master_sku_name") or (master_sku.get("name") if master_sku else None),
        "sku": entry.get("sku_code") or (master_sku.get("sku_code") if master_sku else None),
        "sku_code": entry.get("sku_code") or (master_sku.get("sku_code") if master_sku else None),
        "gst_rate": gst_rate,
        "quantity": entry.get("quantity", 1),
        "serial_number": final_serial_numbers,
        # Multi-item serial tracking for offline orders
        "item_serials": item_serials_list if item_serials_list else None,
        "all_serial_numbers": all_serial_numbers if all_serial_numbers else None,
        # Items array for multi-item offline orders
        "items": items if items else None,
        "order_id": entry.get("order_id"),
        "external_invoice_number": entry.get("external_invoice_number") or entry.get("invoice_number"),
        "marketplace_order_id": entry.get("amazon_order_id") or entry.get("order_id"),
        "customer_name": entry.get("customer_name"),
        "customer_id": entry.get("customer_id"),
        "customer_gst": entry.get("customer_gst"),
        "phone": entry.get("customer_phone") or entry.get("phone"),
        "address": entry.get("address"),
        "city": entry.get("city"),
        "state": entry.get("state"),
        "pincode": entry.get("pincode"),
        "delivery_method": entry.get("delivery_method"),
        "payment_status": entry.get("payment_status"),
        "amount_paid": entry.get("amount_paid"),
        "balance_due": entry.get("balance_due"),
        "tracking_id": final_tracking,
        "courier": courier or entry.get("carrier_name") or entry.get("carrier_code") or entry.get("courier"),
        "bigship_order_id": bigship_order_id or entry.get("bigship_order_id"),
        # Copy uploaded documents from pending_fulfillment
        "invoice_url": entry.get("invoice_url"),
        "invoice_number": final_invoice_number or entry.get("invoice_number"),
        "label_url": entry.get("label_url"),
        "label_file": entry.get("label_url"),  # For dispatcher compatibility
        "eway_bill_number": eway_bill_number or entry.get("eway_bill_number"),
        "eway_bill_url": entry.get("eway_bill_url"),
        # PRICING - properly separated for GST calculation
        "invoice_value": final_invoice_value,  # Total (GST inclusive for marketplace)
        "taxable_value": taxable_value,  # Amount before GST
        "gst_amount": gst_amount,  # GST portion
        "subtotal": entry.get("subtotal"),
        "total_gst": entry.get("total_gst"),
        "grand_total": entry.get("grand_total") or entry.get("order_total"),
        "pending_fulfillment_id": order_id,
        "status": "ready_for_dispatch",  # Dispatcher will mark as 'dispatched'
        "notes": notes,
        "prepared_by": user["id"],
        "prepared_by_name": f"{user['first_name']} {user['last_name']}",
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat()
    }
    
    await db.dispatches.insert_one(dispatch_doc)
    
    # Update pending_fulfillment status to 'in_dispatch_queue'
    await db.pending_fulfillment.update_one(
        {"id": entry.get("id")},
        {"$set": {
            "status": "in_dispatch_queue",
            "dispatch_id": dispatch_id,
            "dispatch_number": dispatch_number,
            "updated_at": now.isoformat()
        }}
    )
    
    # Update amazon_orders status if this is an Amazon order
    if entry.get("type") == "amazon_order" and entry.get("amazon_order_id"):
        await db.amazon_orders.update_one(
            {"amazon_order_id": entry.get("amazon_order_id")},
            {"$set": {
                "crm_status": "ready_for_dispatch",
                "dispatch_id": dispatch_id,
                "dispatch_number": dispatch_number,
                "updated_at": now.isoformat()
            }}
        )
    
    # Create audit log
    await db.audit_logs.insert_one({
        "id": str(uuid.uuid4()),
        "action": "order_prepared_for_dispatch",
        "entity_type": "pending_fulfillment",
        "entity_id": order_id,
        "entity_name": entry.get("order_id"),
        "performed_by": user["id"],
        "performed_by_name": f"{user['first_name']} {user['last_name']}",
        "details": {
            "dispatch_id": dispatch_id, 
            "dispatch_number": dispatch_number,
            "tracking_id": final_tracking, 
            "serial_number": serial_numbers,
            "note": "Prepared by accountant via Operations Bot"
        },
        "timestamp": now.isoformat()
    })
    
    return {
        "message": "Order prepared for dispatch! Dispatcher will complete the physical dispatch.",
        "dispatch_id": dispatch_id, 
        "dispatch_number": dispatch_number,
        "status": "ready_for_dispatch",
        "next_step": "Order is now in Dispatcher Queue. Dispatcher will print labels and mark as dispatched."
    }


@api_router.get("/bot/prepare-dispatch/{order_id}")
async def bot_prepare_dispatch(
    order_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get all details needed for dispatch confirmation - comprehensive compliance check"""
    
    # Search by multiple fields: id, order_id, or amazon_order_id
    entry = await db.pending_fulfillment.find_one(
        {"$or": [
            {"id": order_id},
            {"order_id": order_id},
            {"amazon_order_id": order_id}
        ]},
        {"_id": 0}
    )
    if not entry:
        raise HTTPException(status_code=404, detail="Order not found")
    
    # Determine order type - EasyShip orders don't need phone/address
    order_source = entry.get("order_source") or entry.get("source") or ""
    is_easyship = order_source.lower() in ["easyship", "easy_ship", "amazon_easy_ship"]
    fulfillment_channel = entry.get("fulfillment_channel", "").upper()
    is_amazon_fba = fulfillment_channel == "AFN"
    
    # Get product/SKU details
    master_sku = None
    if entry.get("master_sku_id"):
        master_sku = await db.master_skus.find_one({"id": entry["master_sku_id"]}, {"_id": 0})
    
    # If no master_sku yet, try to find via SKU mapping from Amazon order
    if not master_sku and (entry.get("amazon_order_id") or entry.get("marketplace_order_id")):
        amazon_order_id = entry.get("amazon_order_id") or entry.get("marketplace_order_id")
        temp_amazon = await db.amazon_orders.find_one(
            {"$or": [{"amazon_order_id": amazon_order_id}, {"order_id": amazon_order_id}]},
            {"_id": 0, "sku": 1, "firm_id": 1}
        )
        if temp_amazon and temp_amazon.get("sku"):
            # Look up SKU mapping
            sku_mapping = await db.sku_mappings.find_one({
                "amazon_sku": temp_amazon["sku"],
                "$or": [{"firm_id": temp_amazon.get("firm_id")}, {"firm_id": {"$exists": False}}]
            })
            if sku_mapping and sku_mapping.get("master_sku_id"):
                master_sku = await db.master_skus.find_one({"id": sku_mapping["master_sku_id"]}, {"_id": 0})
                # Also try by ObjectId
                if not master_sku:
                    from bson import ObjectId
                    try:
                        master_sku = await db.master_skus.find_one({"_id": ObjectId(sku_mapping["master_sku_id"])}, {"_id": 0})
                    except:
                        pass
    
    # Get pricing from Amazon order if available
    amazon_price = None
    amazon_order = None
    if entry.get("amazon_order_id") or entry.get("marketplace_order_id"):
        amazon_order_id = entry.get("amazon_order_id") or entry.get("marketplace_order_id")
        amazon_order = await db.amazon_orders.find_one(
            {"$or": [{"amazon_order_id": amazon_order_id}, {"order_id": amazon_order_id}]},
            {"_id": 0}
        )
        if amazon_order:
            amazon_price = amazon_order.get("order_total") or amazon_order.get("item_price")
            # Also check EasyShip from Amazon order
            if amazon_order.get("is_easy_ship") or amazon_order.get("fulfillment_channel") == "EasyShip":
                is_easyship = True
    
    # Get available serial numbers for this SKU
    available_serials = []
    if entry.get("master_sku_id") and entry.get("firm_id"):
        available_serials = await db.finished_good_serials.find(
            {
                "master_sku_id": entry["master_sku_id"],
                "firm_id": entry["firm_id"],
                "status": "in_stock"
            },
            {"_id": 0, "id": 1, "serial_number": 1, "manufacturing_date": 1, "batch_number": 1}
        ).sort("manufacturing_date", 1).to_list(50)
    
    # Check if this is a manufactured item (has serials) or regular SKU
    is_manufactured = master_sku.get("type") == "manufactured" if master_sku else False
    
    # Get regular SKU stock for non-manufactured items
    sku_stock = None
    if master_sku and not is_manufactured and entry.get("firm_id"):
        sku_stock = await db.skus.find_one(
            {
                "sku_code": master_sku.get("sku_code"),
                "firm_id": entry["firm_id"],
                "active": True
            },
            {"_id": 0, "stock_quantity": 1}
        )
    
    # Calculate GST (assuming 18% default, can be fetched from product)
    gst_rate = master_sku.get("gst_rate", 18) if master_sku else 18
    total_with_gst = amazon_price or entry.get("order_total") or entry.get("amount") or 0
    quantity = entry.get("quantity", 1)
    
    # Determine if price is GST-inclusive (marketplace orders)
    is_marketplace = order_source.lower() in ["amazon", "flipkart", "marketplace"]
    
    # Calculate prices
    if total_with_gst > 0:
        if is_marketplace:
            # Amazon/Flipkart: Price is GST-inclusive
            price_without_gst = round(total_with_gst / (1 + gst_rate/100), 2)
            gst_amount = round(total_with_gst - price_without_gst, 2)
            total_value = total_with_gst  # Already includes GST
        else:
            # Direct order: Price is taxable, GST added separately
            price_without_gst = total_with_gst
            gst_amount = round(total_with_gst * (gst_rate/100), 2)
            total_value = total_with_gst + gst_amount
    else:
        price_without_gst = 0
        gst_amount = 0
        total_value = 0
    
    # Check compliance requirements
    compliance = {
        "tracking_id_required": True,
        "tracking_id_provided": bool(entry.get("tracking_id")),
        "invoice_required": True,
        "invoice_uploaded": bool(entry.get("invoice_url")),
        "label_required": True,
        "label_uploaded": bool(entry.get("label_url")),
        "eway_bill_required": total_value > 50000,
        "eway_bill_provided": bool(entry.get("eway_bill_number")),
        "eway_bill_uploaded": bool(entry.get("eway_bill_url")),
        "serial_required": entry.get("is_manufactured", False) or bool(available_serials),
        "serial_provided": bool(entry.get("serial_number"))
    }
    
    # Determine what's missing
    missing = []
    if not compliance["tracking_id_provided"]:
        missing.append("tracking_id")
    if not compliance["invoice_uploaded"]:
        missing.append("invoice")
    if not compliance["label_uploaded"]:
        missing.append("shipping_label")
    if compliance["eway_bill_required"] and not compliance["eway_bill_provided"]:
        missing.append("eway_bill_number")
    if compliance["eway_bill_required"] and not compliance["eway_bill_uploaded"]:
        missing.append("eway_bill_copy")
    if compliance["serial_required"] and not compliance["serial_provided"]:
        missing.append("serial_number")
    
    return {
        "order": {
            "id": entry.get("id"),
            "order_id": entry.get("order_id"),
            "status": entry.get("status"),
            "payment_status": entry.get("payment_status", "unpaid"),
            "order_source": order_source,
            "is_easyship": is_easyship,
            "is_amazon_fba": is_amazon_fba
        },
        "customer": {
            "name": entry.get("customer_name"),
            "first_name": entry.get("customer_first_name"),
            "last_name": entry.get("customer_last_name"),
            "phone": entry.get("customer_phone") or entry.get("phone") or ("(Not required for EasyShip)" if is_easyship else None),
            "address": entry.get("address") or entry.get("address_line1") or ("(Handled by Amazon)" if is_easyship else None),
            "city": entry.get("city"),
            "state": entry.get("state"),
            "pincode": entry.get("pincode")
        },
        "product": {
            "name": entry.get("master_sku_name") or (master_sku.get("name") if master_sku else None),
            "sku_code": entry.get("sku_code") or (master_sku.get("sku_code") if master_sku else None),
            "hsn_code": master_sku.get("hsn_code") if master_sku else None,
            "quantity": quantity,
            "is_manufactured": entry.get("is_manufactured", False)
        },
        "pricing": {
            "source": "amazon" if amazon_price else "order",
            "is_gst_inclusive": is_marketplace,  # Flag to indicate if price includes GST
            "taxable_value": price_without_gst,  # Amount before GST
            "gst_rate": gst_rate,
            "gst_amount": gst_amount,
            "quantity": quantity,
            "total_value": total_value  # Final amount (taxable + GST)
        },
        "logistics": {
            "tracking_id": entry.get("tracking_id"),
            "courier": entry.get("courier") or entry.get("shipping_method")
        },
        "documents": {
            "invoice_number": entry.get("invoice_number"),
            "invoice_uploaded": bool(entry.get("invoice_url")),
            "label_uploaded": bool(entry.get("label_url")),
            "eway_bill_number": entry.get("eway_bill_number"),
            "eway_bill_uploaded": bool(entry.get("eway_bill_url"))
        },
        "serial_numbers": {
            "selected": entry.get("serial_number"),
            "available": available_serials
        },
        "stock": {
            "available": len(available_serials) if is_manufactured else (sku_stock.get("stock_quantity", 0) if sku_stock else 0),
            "is_available": len(available_serials) > 0 if is_manufactured else (sku_stock.get("stock_quantity", 0) > 0 if sku_stock else False)
        },
        "item_count": len(entry.get("items", [])) or 1,  # Number of items in the order
        "is_multi_item": len(entry.get("items", [])) > 1,  # Flag for multi-item orders
        "master_sku": {
            "id": master_sku.get("id") if master_sku else None,
            "name": master_sku.get("name") if master_sku else None,
            "sku_code": master_sku.get("sku_code") if master_sku else None,
            "weight_kg": master_sku.get("weight_kg") if master_sku else None,  # Weight in kg
            "length_cm": master_sku.get("length_cm") if master_sku else None,  # Length in cm
            "breadth_cm": master_sku.get("breadth_cm") if master_sku else None,  # Breadth in cm
            "height_cm": master_sku.get("height_cm") if master_sku else None  # Height in cm
        } if master_sku else None,
        "compliance": compliance,
        "missing_fields": missing,
        "ready_to_dispatch": len(missing) == 0
    }


@api_router.get("/bot/available-serials/{order_id}")
async def bot_available_serials(
    order_id: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get available serial numbers for an order's product"""
    
    entry = await db.pending_fulfillment.find_one({"id": order_id}, {"_id": 0})
    if not entry:
        raise HTTPException(status_code=404, detail="Order not found")
    
    if not entry.get("master_sku_id"):
        return {"serials": [], "message": "No product SKU linked to this order"}
    
    firm_id = entry.get("firm_id") or "default"
    
    serials = await db.finished_good_serials.find(
        {
            "master_sku_id": entry["master_sku_id"],
            "firm_id": firm_id,
            "status": "in_stock"
        },
        {"_id": 0, "id": 1, "serial_number": 1, "manufacturing_date": 1, "batch_number": 1, "warranty_start": 1}
    ).sort("manufacturing_date", 1).to_list(100)
    
    return {
        "serials": serials,
        "count": len(serials),
        "product_name": entry.get("master_sku_name"),
        "quantity_needed": entry.get("quantity", 1)
    }


@api_router.post("/bot/select-serial")
async def bot_select_serial(
    order_id: str = Form(...),
    serial_number: str = Form(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Select a serial number for dispatch"""
    
    entry = await db.pending_fulfillment.find_one({"id": order_id})
    if not entry:
        raise HTTPException(status_code=404, detail="Order not found")
    
    # Verify serial exists and is in stock
    serial = await db.finished_good_serials.find_one({
        "serial_number": serial_number,
        "status": "in_stock"
    })
    
    if not serial:
        raise HTTPException(status_code=400, detail=f"Serial number {serial_number} not found or not in stock")
    
    # Update order with selected serial
    await db.pending_fulfillment.update_one(
        {"id": order_id},
        {"$set": {
            "serial_number": serial_number,
            "serial_id": serial.get("id"),
            "updated_at": datetime.now(timezone.utc).isoformat()
        }}
    )
    
    return {"message": f"Serial number {serial_number} selected", "serial": serial_number}


@api_router.get("/bot/customer-history/{phone}")
async def bot_customer_history(phone: str, user: dict = Depends(require_roles(["admin", "accountant"]))):
    """Get customer's previous orders and suggest address"""
    history = await bot_get_customer_history(phone)
    return history


@api_router.get("/bot/comprehensive-order/{order_id}")
async def bot_comprehensive_order_analysis(order_id: str, user: dict = Depends(require_roles(["admin", "accountant"]))):
    """
    Get comprehensive analysis of an order including all related data:
    - Customer details
    - Tracking ID
    - Serial numbers
    - SKU mapping
    - Pricing & GST
    - Sales invoice status
    - Dispatch entry
    - Payment reconciliation
    """
    analysis = {
        "order_id": order_id,
        "found": False,
        "source": None,
        "checks": {
            "customer_details": {"status": "missing", "data": {}},
            "tracking_id": {"status": "missing", "data": None},
            "serial_numbers": {"status": "not_applicable", "data": []},
            "sku_mapping": {"status": "missing", "data": {}},
            "pricing_gst": {"status": "missing", "data": {}},
            "sales_invoice": {"status": "missing", "data": None},
            "dispatch_entry": {"status": "missing", "data": None},
            "payment_reconciliation": {"status": "missing", "data": None}
        },
        "raw_order": None,
        "summary": {"complete": 0, "missing": 0, "issues": []}
    }
    
    # Search for order in all collections
    order = None
    source = None
    
    # Check pending_fulfillment
    pf_order = await db.pending_fulfillment.find_one({
        "$or": [
            {"order_id": {"$regex": f"^{order_id}$", "$options": "i"}},
            {"tracking_id": {"$regex": f"^{order_id}$", "$options": "i"}},
            {"id": order_id}
        ]
    }, {"_id": 0})
    if pf_order:
        order = pf_order
        source = "pending_fulfillment"
    
    # Check dispatches
    if not order:
        dispatch = await db.dispatches.find_one({
            "$or": [
                {"order_id": {"$regex": f"^{order_id}$", "$options": "i"}},
                {"tracking_id": {"$regex": f"^{order_id}$", "$options": "i"}},
                {"dispatch_number": {"$regex": f"^{order_id}$", "$options": "i"}},
                {"marketplace_order_id": {"$regex": f"^{order_id}$", "$options": "i"}}
            ]
        }, {"_id": 0})
        if dispatch:
            order = dispatch
            source = "dispatches"
    
    # Check amazon_orders
    if not order:
        amazon = await db.amazon_orders.find_one({
            "$or": [
                {"amazon_order_id": {"$regex": f"^{order_id}$", "$options": "i"}},
                {"order_id": {"$regex": f"^{order_id}$", "$options": "i"}}
            ]
        }, {"_id": 0})
        if amazon:
            order = amazon
            source = "amazon_orders"
    
    if not order:
        return analysis
    
    analysis["found"] = True
    analysis["source"] = source
    analysis["raw_order"] = order
    
    # 1. Customer Details Check
    customer_name = order.get("customer_name") or order.get("buyer_name")
    phone = order.get("customer_phone") or order.get("phone") or order.get("buyer_phone")
    address = order.get("address") or order.get("shipping_address")
    state = order.get("state") or order.get("shipping_state")
    pincode = order.get("pincode") or order.get("shipping_pincode") or order.get("postal_code")
    city = order.get("city") or order.get("shipping_city")
    
    customer_data = {
        "name": customer_name,
        "phone": phone,
        "address": address,
        "city": city,
        "state": state,
        "pincode": pincode
    }
    
    customer_complete = all([customer_name, phone, address, state, pincode])
    analysis["checks"]["customer_details"] = {
        "status": "complete" if customer_complete else "incomplete",
        "data": customer_data,
        "missing": [k for k, v in customer_data.items() if not v]
    }
    
    # 2. Tracking ID Check
    tracking_id = order.get("tracking_id") or order.get("tracking_number")
    analysis["checks"]["tracking_id"] = {
        "status": "complete" if tracking_id else "missing",
        "data": tracking_id
    }
    
    # 3. Serial Numbers Check
    items = order.get("items", [])
    has_manufactured = False
    serials_assigned = []
    
    for item in items:
        master_sku_id = item.get("master_sku_id")
        if master_sku_id:
            sku = await db.master_skus.find_one({"id": master_sku_id}, {"_id": 0})
            if sku and sku.get("product_type") == "manufactured":
                has_manufactured = True
    
    # Also check single-item orders
    if order.get("master_sku_id"):
        sku = await db.master_skus.find_one({"id": order.get("master_sku_id")}, {"_id": 0})
        if sku and sku.get("product_type") == "manufactured":
            has_manufactured = True
    
    # Check if serials are assigned
    if order.get("item_serials"):
        serials_assigned = order.get("item_serials", [])
    elif order.get("serial_number"):
        serials_assigned = [order.get("serial_number")]
    
    if has_manufactured:
        analysis["checks"]["serial_numbers"] = {
            "status": "complete" if serials_assigned else "missing",
            "data": serials_assigned,
            "required": True
        }
    else:
        analysis["checks"]["serial_numbers"] = {
            "status": "not_applicable",
            "data": [],
            "required": False
        }
    
    # 4. SKU Mapping Check
    sku_data = []
    if items:
        for item in items:
            master_sku_id = item.get("master_sku_id")
            if master_sku_id:
                sku = await db.master_skus.find_one({"id": master_sku_id}, {"_id": 0})
                if sku:
                    sku_data.append({
                        "name": sku.get("name"),
                        "sku_code": sku.get("sku_code"),
                        "hsn_code": sku.get("hsn_code"),
                        "gst_rate": sku.get("gst_rate"),
                        "mapped": True
                    })
                else:
                    sku_data.append({"master_sku_id": master_sku_id, "mapped": False})
            else:
                sku_data.append({"title": item.get("title"), "mapped": False})
    elif order.get("master_sku_id"):
        sku = await db.master_skus.find_one({"id": order.get("master_sku_id")}, {"_id": 0})
        if sku:
            sku_data.append({
                "name": sku.get("name"),
                "sku_code": sku.get("sku_code"),
                "hsn_code": sku.get("hsn_code"),
                "gst_rate": sku.get("gst_rate"),
                "mapped": True
            })
    
    all_mapped = all(s.get("mapped") for s in sku_data) if sku_data else False
    analysis["checks"]["sku_mapping"] = {
        "status": "complete" if all_mapped else "incomplete" if sku_data else "missing",
        "data": sku_data
    }
    
    # 5. Pricing & GST Check
    invoice_value = order.get("invoice_value") or order.get("order_total") or order.get("amount")
    taxable_value = order.get("taxable_value")
    gst_amount = order.get("gst_amount") or order.get("total_gst")
    
    pricing_data = {
        "invoice_value": invoice_value,
        "taxable_value": taxable_value,
        "gst_amount": gst_amount,
        "payment_status": order.get("payment_status", "unknown")
    }
    
    analysis["checks"]["pricing_gst"] = {
        "status": "complete" if invoice_value else "missing",
        "data": pricing_data
    }
    
    # 6. Sales Invoice Check
    lookup_id = order.get("order_id") or order.get("amazon_order_id") or order_id
    sales_invoice = await db.sales_invoices.find_one({
        "$or": [
            {"order_id": lookup_id},
            {"dispatch_id": order.get("id")},
            {"reference_number": {"$regex": lookup_id, "$options": "i"}}
        ]
    }, {"_id": 0})
    
    analysis["checks"]["sales_invoice"] = {
        "status": "complete" if sales_invoice else "missing",
        "data": {
            "invoice_number": sales_invoice.get("invoice_number") if sales_invoice else None,
            "date": sales_invoice.get("invoice_date") if sales_invoice else None,
            "grand_total": sales_invoice.get("grand_total") if sales_invoice else None
        } if sales_invoice else None
    }
    
    # 7. Dispatch Entry Check
    dispatch_entry = None
    if source == "dispatches":
        dispatch_entry = order
    else:
        dispatch_entry = await db.dispatches.find_one({
            "$or": [
                {"order_id": lookup_id},
                {"marketplace_order_id": lookup_id},
                {"pending_fulfillment_id": order.get("id")}
            ]
        }, {"_id": 0})
    
    analysis["checks"]["dispatch_entry"] = {
        "status": "complete" if dispatch_entry else "missing",
        "data": {
            "dispatch_number": dispatch_entry.get("dispatch_number") if dispatch_entry else None,
            "dispatch_date": dispatch_entry.get("dispatch_date") if dispatch_entry else None,
            "status": dispatch_entry.get("status") if dispatch_entry else None
        } if dispatch_entry else None
    }
    
    # 8. Payment Reconciliation Check
    # Check in ecommerce reconciliation if it's a marketplace order
    order_source = order.get("order_source") or order.get("source")
    recon_data = None
    
    if order_source in ["amazon", "flipkart", "Amazon", "Flipkart"]:
        recon_tx = await db.payout_transactions.find_one({
            "$or": [
                {"order_id": lookup_id},
                {"external_order_id": lookup_id}
            ]
        }, {"_id": 0})
        
        if recon_tx:
            recon_data = {
                "matched": recon_tx.get("matched", False),
                "transaction_type": recon_tx.get("type"),
                "amount": recon_tx.get("amount"),
                "statement_id": recon_tx.get("statement_id")
            }
    
    # Check if marked as paid
    payment_status = order.get("payment_status") or (dispatch_entry.get("payment_status") if dispatch_entry else None)
    
    analysis["checks"]["payment_reconciliation"] = {
        "status": "complete" if (recon_data and recon_data.get("matched")) or payment_status == "paid" else "pending" if recon_data else "not_reconciled",
        "data": recon_data or {"payment_status": payment_status},
        "marketplace_order": order_source in ["amazon", "flipkart", "Amazon", "Flipkart"]
    }
    
    # Generate Summary
    complete_count = sum(1 for c in analysis["checks"].values() if c["status"] == "complete" or c["status"] == "not_applicable")
    missing_count = sum(1 for c in analysis["checks"].values() if c["status"] in ["missing", "incomplete", "not_reconciled"])
    
    issues = []
    if analysis["checks"]["customer_details"]["status"] != "complete":
        issues.append(f"Missing customer details: {', '.join(analysis['checks']['customer_details'].get('missing', []))}")
    if analysis["checks"]["tracking_id"]["status"] == "missing":
        issues.append("Tracking ID not set")
    if analysis["checks"]["serial_numbers"]["status"] == "missing":
        issues.append("Serial number required but not assigned")
    if analysis["checks"]["sku_mapping"]["status"] != "complete":
        issues.append("SKU not fully mapped")
    if analysis["checks"]["pricing_gst"]["status"] == "missing":
        issues.append("Pricing/invoice value missing")
    if analysis["checks"]["sales_invoice"]["status"] == "missing":
        issues.append("Sales invoice not created")
    if analysis["checks"]["dispatch_entry"]["status"] == "missing":
        issues.append("Not dispatched yet")
    if analysis["checks"]["payment_reconciliation"]["status"] == "not_reconciled":
        issues.append("Payment not reconciled")
    
    analysis["summary"] = {
        "complete": complete_count,
        "total": len(analysis["checks"]),
        "issues": issues,
        "overall_status": "complete" if not issues else "has_issues"
    }
    
    return analysis


@api_router.get("/bot/orders-missing-invoices")
async def bot_get_orders_missing_invoices(
    limit: int = 20,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get orders that are missing invoice uploads - for 'fix invoices' command"""
    
    # Find pending fulfillment entries missing invoice_url
    missing_invoices = await db.pending_fulfillment.find({
        "status": {"$in": ["pending_dispatch", "ready_to_dispatch"]},
        "$or": [
            {"invoice_url": {"$exists": False}},
            {"invoice_url": None},
            {"invoice_url": ""}
        ]
    }, {"_id": 0}).sort("created_at", -1).limit(limit).to_list(limit)
    
    results = []
    for order in missing_invoices:
        results.append({
            "id": order.get("id"),
            "order_id": order.get("order_id"),
            "tracking_id": order.get("tracking_id"),
            "customer_name": order.get("customer_name"),
            "customer_phone": order.get("customer_phone") or order.get("phone"),
            "status": order.get("status"),
            "created_at": order.get("created_at"),
            "has_tracking": bool(order.get("tracking_id")),
            "has_label": bool(order.get("label_url"))
        })
    
    return {
        "count": len(results),
        "orders": results,
        "message": f"Found {len(results)} orders missing invoices"
    }


@api_router.post("/bot/chat")
async def bot_intelligent_chat(
    message: str = Form(...),
    session_id: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Intelligent chat endpoint that understands natural language queries.
    Parses intents like:
    - "find order 1234" / "show me order 1234" / "can you find order ID 1234"
    - "fix invoices" / "show missing invoices"
    - "status" / "how's everything"
    """
    message_lower = message.lower().strip()
    
    # Intent detection patterns
    import re
    
    # Skip command-like words early
    command_words = ["status", "stuck", "missing", "help", "production", "invoices", "me", "order", "orders", "the", "a", "an"]
    
    # Pattern: Fix invoices / missing invoices - CHECK FIRST before order search
    if any(p in message_lower for p in ["fix invoice", "missing invoice", "orders without invoice", "need invoice"]):
        return {
            "intent": "fix_invoices",
            "action": "list_missing_invoices",
            "message": "Fetching orders missing invoices..."
        }
    
    # Pattern: Stuck orders - CHECK EARLY
    if any(p in message_lower for p in ["stuck", "delayed", "pending too long", "old orders"]):
        return {
            "intent": "stuck_orders",
            "action": "list_stuck",
            "message": "Checking for stuck orders..."
        }
    
    # Pattern: Status / Summary / Briefing  
    if any(p in message_lower for p in ["status", "summary", "briefing", "how's everything", "what's going on", "overview"]):
        return {
            "intent": "status",
            "action": "daily_briefing",
            "message": "Fetching operations status..."
        }
    
    # Pattern: Find/show/get/check order [ID] - more specific patterns
    order_patterns = [
        # "show me order 123" or "find order 123"
        r"(?:show\s+me|find|get|check|pull|look\s*up|search)\s+(?:order\s+)?(?:id\s+)?[#]?([A-Za-z0-9][A-Za-z0-9\-_]+)",
        # "order 123" or "order id 123"
        r"^order\s+(?:id\s+)?[#]?([A-Za-z0-9][A-Za-z0-9\-_]+)$",
        # "can you find order 123"
        r"can\s+you\s+(?:find|show|get|check)\s+(?:order\s+)?(?:id\s+)?[#]?([A-Za-z0-9][A-Za-z0-9\-_]+)",
        # Just a long alphanumeric string that looks like an order ID (e.g., 171-3496729-7741914)
        r"^([0-9]{3}-[0-9]{7}-[0-9]{7})$",
        r"^([A-Z]{2,3}-[0-9]+)$"
    ]
    
    for pattern in order_patterns:
        match = re.search(pattern, message_lower)
        if match:
            order_id = match.group(1).strip()
            # Skip if it's just a command word
            if order_id.lower() in command_words:
                continue
            # Skip very short IDs (likely partial words)
            if len(order_id) < 3:
                continue
            return {
                "intent": "find_order",
                "order_id": order_id,
                "action": "comprehensive_analysis",
                "message": f"Looking up order {order_id}..."
            }
    
    # Pattern: Missing data
    if any(p in message_lower for p in ["missing data", "incomplete", "data gap"]):
        return {
            "intent": "missing_data",
            "action": "list_missing",
            "message": "Checking for data gaps..."
        }
    
    # Pattern: Production
    if any(p in message_lower for p in ["production", "stock", "inventory", "what to make"]):
        return {
            "intent": "production",
            "action": "production_suggestions",
            "message": "Analyzing stock levels..."
        }
    
    # Pattern: Help
    if any(p in message_lower for p in ["help", "what can you do", "commands", "how to use"]):
        return {
            "intent": "help",
            "action": "show_help",
            "message": "Here's what I can do..."
        }
    
    # Default: Try to search
    return {
        "intent": "search",
        "query": message,
        "action": "search_order",
        "message": f"Searching for '{message}'..."
    }


@api_router.get("/bot/universal-search/{query}")
async def bot_universal_search(
    query: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """
    Universal search across ALL CRM data:
    - Order IDs (amazon_orders, pending_fulfillment, dispatches)
    - Tracking IDs (dispatches, incoming_queue, returns)
    - Phone numbers (customers, orders)
    - Serial numbers (finished_good_serials)
    """
    results = {
        "query": query,
        "found_in": [],
        "primary_result": None,
        "all_results": {}
    }
    
    query_clean = query.strip()
    
    # 1. Search Amazon Orders
    amazon_order = await db.amazon_orders.find_one({
        "$or": [
            {"amazon_order_id": {"$regex": f"^{query_clean}$", "$options": "i"}},
            {"order_id": {"$regex": f"^{query_clean}$", "$options": "i"}}
        ]
    }, {"_id": 0})
    
    if amazon_order:
        results["found_in"].append("amazon_orders")
        
        # Check if actually exists in pending_fulfillment (not just crm_status flag)
        pf_exists = await db.pending_fulfillment.find_one({
            "$or": [
                {"amazon_order_id": amazon_order.get("amazon_order_id")},
                {"order_id": amazon_order.get("amazon_order_id")}
            ]
        })
        in_crm = pf_exists is not None
        
        results["all_results"]["amazon_order"] = {
            "type": "amazon_order",
            "data": amazon_order,
            "in_crm": in_crm,
            "status": amazon_order.get("crm_status") or amazon_order.get("order_status"),
            "actions": []
        }
        # Determine available actions - if NOT in CRM, allow import or mark as dispatched
        if not in_crm:
            results["all_results"]["amazon_order"]["actions"] = ["import_to_crm", "mark_already_dispatched"]
        elif pf_exists and pf_exists.get("status") not in ["dispatched", "cancelled"]:
            results["all_results"]["amazon_order"]["actions"] = ["prepare_dispatch", "view_details"]
        else:
            results["all_results"]["amazon_order"]["actions"] = ["view_details"]
    
    # 2. Search Pending Fulfillment (use contains match for order_id to handle partial searches)
    pf_order = await db.pending_fulfillment.find_one({
        "$or": [
            {"order_id": {"$regex": query_clean, "$options": "i"}},
            {"tracking_id": {"$regex": query_clean, "$options": "i"}},
            {"id": query_clean},
            {"amazon_order_id": {"$regex": query_clean, "$options": "i"}}
        ]
    }, {"_id": 0})
    
    if pf_order:
        results["found_in"].append("pending_fulfillment")
        results["all_results"]["pending_fulfillment"] = {
            "type": "pending_fulfillment",
            "data": pf_order,
            "status": pf_order.get("status"),
            "actions": ["prepare_dispatch", "update_details"] if pf_order.get("status") != "dispatched" else ["view_details"]
        }
    
    # 3. Search Dispatches (use contains match for order_id)
    dispatch = await db.dispatches.find_one({
        "$or": [
            {"order_id": {"$regex": query_clean, "$options": "i"}},
            {"tracking_id": {"$regex": query_clean, "$options": "i"}},
            {"dispatch_number": {"$regex": query_clean, "$options": "i"}},
            {"marketplace_order_id": {"$regex": query_clean, "$options": "i"}}
        ]
    }, {"_id": 0})
    
    if dispatch:
        results["found_in"].append("dispatches")
        results["all_results"]["dispatch"] = {
            "type": "dispatch",
            "data": dispatch,
            "status": dispatch.get("status"),
            "actions": ["view_details"]
        }
    
    # 4. Search Incoming Queue (Returns/RTO)
    incoming = await db.incoming_queue.find_one({
        "$or": [
            {"tracking_id": {"$regex": f"^{query_clean}$", "$options": "i"}},
            {"awb_number": {"$regex": f"^{query_clean}$", "$options": "i"}},
            {"order_id": {"$regex": f"^{query_clean}$", "$options": "i"}}
        ]
    }, {"_id": 0})
    
    if incoming:
        results["found_in"].append("incoming_queue")
        results["all_results"]["incoming"] = {
            "type": "incoming_return",
            "data": incoming,
            "status": incoming.get("status"),
            "actions": ["add_to_inventory", "send_to_repair", "send_to_repair_yard", "mark_dead_stock"]
        }
    
    # 5. Search Serial Numbers
    serial = await db.finished_good_serials.find_one({
        "serial_number": {"$regex": f"^{query_clean}$", "$options": "i"}
    }, {"_id": 0})
    
    if serial:
        results["found_in"].append("serial_numbers")
        # Get additional info about this serial
        serial_dispatch = await db.dispatches.find_one({"serial_number": serial.get("serial_number")}, {"_id": 0})
        serial_warranty = await db.warranties.find_one({"serial_number": serial.get("serial_number")}, {"_id": 0})
        
        results["all_results"]["serial"] = {
            "type": "serial_number",
            "data": serial,
            "dispatch_info": serial_dispatch,
            "warranty_info": serial_warranty,
            "status": serial.get("status"),
            "actions": ["update_serial_info", "view_history"]
        }
    
    # 6. Search by Phone Number
    if query_clean.isdigit() and len(query_clean) >= 10:
        # Search customers/orders by phone
        customer_orders = await db.pending_fulfillment.find({
            "$or": [
                {"customer_phone": {"$regex": query_clean}},
                {"phone": {"$regex": query_clean}}
            ]
        }, {"_id": 0}).limit(10).to_list(10)
        
        dispatched_orders = await db.dispatches.find({
            "phone": {"$regex": query_clean}
        }, {"_id": 0}).limit(10).to_list(10)
        
        if customer_orders or dispatched_orders:
            results["found_in"].append("customer_phone")
            results["all_results"]["customer"] = {
                "type": "customer_phone",
                "pending_orders": customer_orders,
                "dispatched_orders": dispatched_orders,
                "total_orders": len(customer_orders) + len(dispatched_orders),
                "actions": ["view_customer_history"]
            }
    
    # 7. Search Tickets (Repairs)
    ticket = await db.tickets.find_one({
        "$or": [
            {"ticket_number": {"$regex": f"^{query_clean}$", "$options": "i"}},
            {"tracking_id": {"$regex": f"^{query_clean}$", "$options": "i"}},
            {"return_tracking": {"$regex": f"^{query_clean}$", "$options": "i"}},
            {"board_serial_number": {"$regex": f"^{query_clean}$", "$options": "i"}}
        ]
    }, {"_id": 0})
    
    if ticket:
        results["found_in"].append("tickets")
        results["all_results"]["ticket"] = {
            "type": "repair_ticket",
            "data": ticket,
            "status": ticket.get("status"),
            "actions": ["view_ticket", "update_status"]
        }
    
    # Determine primary result
    if len(results["found_in"]) > 0:
        # Priority: serial > incoming > pending_fulfillment > amazon_order > dispatch > ticket > customer
        priority_order = ["serial_numbers", "incoming_queue", "pending_fulfillment", "amazon_orders", "dispatches", "tickets", "customer_phone"]
        for source in priority_order:
            if source in results["found_in"]:
                key_map = {
                    "serial_numbers": "serial",
                    "incoming_queue": "incoming",
                    "pending_fulfillment": "pending_fulfillment",
                    "amazon_orders": "amazon_order",
                    "dispatches": "dispatch",
                    "tickets": "ticket",
                    "customer_phone": "customer"
                }
                results["primary_result"] = results["all_results"].get(key_map[source])
                break
    
    return results


@api_router.post("/bot/import-amazon-to-crm")
async def bot_import_amazon_to_crm(
    amazon_order_id: str = Form(...),
    master_sku_id: Optional[str] = Form(None),
    customer_first_name: Optional[str] = Form(None),
    customer_last_name: Optional[str] = Form(None),
    customer_address: Optional[str] = Form(None),
    customer_phone: Optional[str] = Form(None),
    invoice_url: Optional[str] = Form(None),
    tracking_id: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Import Amazon order to CRM (creates pending_fulfillment entry)"""
    
    amazon_order = await db.amazon_orders.find_one({"amazon_order_id": amazon_order_id}, {"_id": 0})
    if not amazon_order:
        raise HTTPException(status_code=404, detail="Amazon order not found")
    
    # Check if already imported
    existing = await db.pending_fulfillment.find_one({"amazon_order_id": amazon_order_id})
    if existing:
        raise HTTPException(status_code=400, detail="Order already imported to CRM")
    
    now = datetime.now(timezone.utc)
    pf_id = str(uuid.uuid4())
    
    # Try to match SKU if not provided
    if not master_sku_id and amazon_order.get("items"):
        for item in amazon_order.get("items", []):
            asin = item.get("asin")
            if asin:
                sku_match = await db.master_skus.find_one({"amazon_asin": asin}, {"_id": 0})
                if sku_match:
                    master_sku_id = sku_match.get("id")
                    break
    
    master_sku = None
    if master_sku_id:
        master_sku = await db.master_skus.find_one({"id": master_sku_id}, {"_id": 0})
    
    # Get product info from Amazon items as fallback
    amazon_items = amazon_order.get("items", [])
    first_item = amazon_items[0] if amazon_items else {}
    product_title = first_item.get("title") or first_item.get("name") or "Unknown Product"
    amazon_sku = first_item.get("amazon_sku") or first_item.get("sku") or first_item.get("asin")
    
    # Get firm ID (default)
    firm = await db.firms.find_one({}, {"_id": 0, "id": 1, "name": 1})
    
    # Build customer name - prefer provided name, fall back to Amazon data
    final_customer_name = None
    if customer_first_name and customer_last_name:
        final_customer_name = f"{customer_first_name} {customer_last_name}"
    elif customer_first_name:
        final_customer_name = customer_first_name
    else:
        final_customer_name = amazon_order.get("buyer_name") or amazon_order.get("customer_name")
    
    # Build address - prefer provided, fall back to Amazon data
    final_address = customer_address or amazon_order.get("shipping_address") or amazon_order.get("address") or amazon_order.get("address_line1")
    
    # Build phone - prefer provided, fall back to Amazon data
    final_phone = customer_phone or amazon_order.get("buyer_phone") or amazon_order.get("phone")
    
    pf_entry = {
        "id": pf_id,
        "type": "amazon_order",
        "order_id": amazon_order.get("amazon_order_id"),
        "amazon_order_id": amazon_order.get("amazon_order_id"),
        "order_source": "amazon",
        "customer_name": final_customer_name,
        "customer_first_name": customer_first_name,
        "customer_last_name": customer_last_name,
        "customer_phone": final_phone,
        "phone": final_phone,
        "address": final_address,
        "address_line1": final_address,
        "city": amazon_order.get("shipping_city") or amazon_order.get("city"),
        "state": amazon_order.get("shipping_state") or amazon_order.get("state"),
        "pincode": amazon_order.get("shipping_pincode") or amazon_order.get("postal_code") or amazon_order.get("pincode"),
        "master_sku_id": master_sku_id,
        "master_sku_name": master_sku.get("name") if master_sku else product_title,
        "sku_code": master_sku.get("sku_code") if master_sku else amazon_sku,
        "amazon_sku": amazon_sku,
        "product_title": product_title,
        "quantity": amazon_order.get("quantity", 1),
        "order_total": amazon_order.get("order_total") or amazon_order.get("item_price"),
        "amount": amazon_order.get("order_total") or amazon_order.get("item_price"),
        "firm_id": amazon_order.get("firm_id") or (firm.get("id") if firm else None),
        "firm_name": amazon_order.get("firm_name") or (firm.get("name") if firm else None),
        "fulfillment_channel": amazon_order.get("fulfillment_channel"),
        "is_easyship": amazon_order.get("is_easy_ship", False),
        "tracking_id": tracking_id or amazon_order.get("tracking_id"),
        "carrier_name": amazon_order.get("carrier_name"),
        "invoice_url": invoice_url,
        "invoice_uploaded": bool(invoice_url),
        "items": amazon_order.get("items", []),
        "status": "pending_dispatch",
        "payment_status": "paid" if amazon_order.get("payment_method") else "unpaid",
        "imported_by": user["id"],
        "imported_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    
    await db.pending_fulfillment.insert_one(pf_entry)
    
    # Update amazon_orders with customer details if provided
    update_data = {
        "crm_status": "pending",
        "pending_fulfillment_id": pf_id,
        "imported_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    if customer_first_name:
        update_data["customer_first_name"] = customer_first_name
    if customer_last_name:
        update_data["customer_last_name"] = customer_last_name
    if final_customer_name:
        update_data["buyer_name"] = final_customer_name
    if customer_address:
        update_data["address_line1"] = customer_address
    if customer_phone:
        update_data["phone"] = customer_phone
    
    await db.amazon_orders.update_one(
        {"amazon_order_id": amazon_order_id},
        {"$set": update_data}
    )
    
    return {
        "message": "Amazon order imported to CRM successfully",
        "pending_fulfillment_id": pf_id,
        "order_id": amazon_order_id,
        "status": "pending_dispatch",
        "next_actions": ["upload_invoice", "upload_label", "prepare_dispatch"]
    }


@api_router.post("/bot/mark-amazon-dispatched")
async def bot_mark_amazon_dispatched(
    amazon_order_id: str = Form(...),
    tracking_id: Optional[str] = Form(None),
    courier: Optional[str] = Form(None),
    dispatch_date: Optional[str] = Form(None),
    serial_number: Optional[str] = Form(None),
    master_sku_id: Optional[str] = Form(None),
    invoice_value: Optional[float] = Form(None),
    notes: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Mark Amazon order as already dispatched (for historical reconciliation)"""
    
    amazon_order = await db.amazon_orders.find_one({"amazon_order_id": amazon_order_id}, {"_id": 0})
    if not amazon_order:
        raise HTTPException(status_code=404, detail="Amazon order not found")
    
    now = datetime.now(timezone.utc)
    dispatch_id = str(uuid.uuid4())
    
    # Generate dispatch number
    today_str = now.strftime("%Y%m%d")
    count = await db.dispatches.count_documents({"created_at": {"$regex": f"^{now.strftime('%Y-%m-%d')}"}})
    dispatch_number = f"MG-D-{today_str}{count + 1:05d}"
    
    # Get master SKU
    master_sku = None
    if master_sku_id:
        master_sku = await db.master_skus.find_one({"id": master_sku_id}, {"_id": 0})
    
    # Get firm
    firm = await db.firms.find_one({}, {"_id": 0, "id": 1, "name": 1})
    
    # CRITICAL: Amazon price is GST-inclusive - calculate taxable value
    final_invoice_value = invoice_value or amazon_order.get("order_total") or 0
    gst_rate = master_sku.get("gst_rate", 18) if master_sku else 18
    
    # Reverse-calculate taxable value from GST-inclusive price
    taxable_value = round(final_invoice_value / (1 + gst_rate / 100), 2) if final_invoice_value > 0 else 0
    gst_amount = round(final_invoice_value - taxable_value, 2) if final_invoice_value > 0 else 0
    
    # Create dispatch entry directly (already shipped)
    dispatch_doc = {
        "id": dispatch_id,
        "dispatch_number": dispatch_number,
        "dispatch_type": "amazon_order",
        "order_source": "amazon",
        "is_marketplace_order": True,
        "price_is_gst_inclusive": True,  # Flag for invoice generation
        "firm_id": firm.get("id") if firm else None,
        "firm_name": firm.get("name") if firm else None,
        "master_sku_id": master_sku_id,
        "master_sku_name": master_sku.get("name") if master_sku else None,
        "sku_code": master_sku.get("sku_code") if master_sku else None,
        "gst_rate": gst_rate,
        "quantity": amazon_order.get("quantity", 1),
        "serial_number": serial_number,
        "order_id": amazon_order.get("amazon_order_id"),
        "marketplace_order_id": amazon_order.get("amazon_order_id"),
        "customer_name": amazon_order.get("buyer_name") or amazon_order.get("customer_name"),
        "phone": amazon_order.get("buyer_phone") or amazon_order.get("phone"),
        "address": amazon_order.get("shipping_address") or amazon_order.get("address"),
        "city": amazon_order.get("shipping_city") or amazon_order.get("city"),
        "state": amazon_order.get("shipping_state") or amazon_order.get("state"),
        "pincode": amazon_order.get("shipping_pincode") or amazon_order.get("postal_code"),
        "tracking_id": tracking_id or amazon_order.get("tracking_id"),
        "courier": courier or amazon_order.get("carrier_name"),
        # PRICING - properly separated for GST calculation
        "invoice_value": final_invoice_value,  # Total (GST inclusive)
        "taxable_value": taxable_value,  # Amount before GST
        "gst_amount": gst_amount,  # GST portion
        "status": "dispatched",
        "scanned_out_at": dispatch_date or now.isoformat(),
        "notes": notes or "Imported as already dispatched via Operations Bot",
        "is_historical_import": True,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat()
    }
    
    await db.dispatches.insert_one(dispatch_doc)
    
    # Update amazon_orders status
    await db.amazon_orders.update_one(
        {"amazon_order_id": amazon_order_id},
        {"$set": {
            "crm_status": "dispatched",
            "dispatch_id": dispatch_id,
            "dispatch_number": dispatch_number,
            "dispatched_at": dispatch_date or now.isoformat(),
            "updated_at": now.isoformat()
        }}
    )
    
    # Update serial number if provided
    if serial_number:
        await db.finished_good_serials.update_one(
            {"serial_number": serial_number},
            {"$set": {
                "status": "sold",
                "dispatch_id": dispatch_id,
                "dispatch_number": dispatch_number,
                "dispatched_at": now.isoformat(),
                "customer_name": amazon_order.get("buyer_name"),
                "customer_phone": amazon_order.get("buyer_phone"),
                "updated_at": now.isoformat()
            }}
        )
    
    return {
        "message": "Amazon order marked as dispatched",
        "dispatch_id": dispatch_id,
        "dispatch_number": dispatch_number,
        "tracking_id": tracking_id,
        "status": "dispatched"
    }


@api_router.post("/bot/handle-rto")
async def bot_handle_rto(
    tracking_id: str = Form(...),
    action: str = Form(...),  # add_to_inventory, send_to_repair, send_to_repair_yard, mark_dead_stock
    master_sku_id: Optional[str] = Form(None),
    serial_number: Optional[str] = Form(None),
    condition: Optional[str] = Form("good"),  # good, damaged, defective
    notes: Optional[str] = Form(None),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Handle RTO/Return - Add to inventory, send to repair, or mark as dead stock"""
    
    # Find the incoming item or dispatch by tracking ID
    incoming = await db.incoming_queue.find_one({"tracking_id": tracking_id}, {"_id": 0})
    dispatch = await db.dispatches.find_one({"tracking_id": tracking_id}, {"_id": 0})
    
    source_item = incoming or dispatch
    if not source_item:
        raise HTTPException(status_code=404, detail=f"No record found for tracking ID: {tracking_id}")
    
    now = datetime.now(timezone.utc)
    
    # Get master SKU
    final_master_sku_id = master_sku_id or source_item.get("master_sku_id")
    master_sku = None
    if final_master_sku_id:
        master_sku = await db.master_skus.find_one({"id": final_master_sku_id}, {"_id": 0})
    
    if action == "add_to_inventory":
        # Add back to finished goods inventory
        if not final_master_sku_id:
            raise HTTPException(status_code=400, detail="Master SKU ID required to add to inventory")
        
        # Create inventory ledger entry
        firm = await db.firms.find_one({}, {"_id": 0, "id": 1})
        firm_id = source_item.get("firm_id") or (firm.get("id") if firm else None)
        
        ledger_entry = {
            "id": str(uuid.uuid4()),
            "item_type": "master_sku",
            "item_id": final_master_sku_id,
            "item_name": master_sku.get("name") if master_sku else None,
            "sku_code": master_sku.get("sku_code") if master_sku else None,
            "firm_id": firm_id,
            "transaction_type": "rto_return",
            "quantity_change": 1,
            "reference_type": "rto",
            "reference_id": tracking_id,
            "reference_number": tracking_id,
            "serial_number": serial_number or source_item.get("serial_number"),
            "condition": condition,
            "notes": notes or f"RTO return via tracking {tracking_id}",
            "created_by": user["id"],
            "created_by_name": f"{user['first_name']} {user['last_name']}",
            "created_at": now.isoformat()
        }
        
        # Get current balance
        last_entry = await db.inventory_ledger.find_one(
            {"item_id": final_master_sku_id, "item_type": "master_sku"},
            sort=[("created_at", -1)]
        )
        current_balance = last_entry.get("running_balance", 0) if last_entry else 0
        ledger_entry["running_balance"] = current_balance + 1
        
        await db.inventory_ledger.insert_one(ledger_entry)
        
        # Update serial number status if provided
        if serial_number:
            await db.finished_good_serials.update_one(
                {"serial_number": serial_number},
                {"$set": {
                    "status": "in_stock",
                    "condition": condition,
                    "rto_date": now.isoformat(),
                    "rto_tracking": tracking_id,
                    "updated_at": now.isoformat()
                }}
            )
        
        # Update incoming queue status
        if incoming:
            await db.incoming_queue.update_one(
                {"tracking_id": tracking_id},
                {"$set": {
                    "status": "processed",
                    "processed_action": "added_to_inventory",
                    "processed_at": now.isoformat(),
                    "processed_by": user["id"]
                }}
            )
        
        return {
            "message": "RTO added to inventory successfully",
            "action": "add_to_inventory",
            "master_sku": master_sku.get("name") if master_sku else final_master_sku_id,
            "new_balance": ledger_entry["running_balance"]
        }
    
    elif action == "send_to_repair":
        # Create repair ticket
        ticket_id = str(uuid.uuid4())
        ticket_number = f"TKT-{now.strftime('%Y%m%d')}-{str(uuid.uuid4())[:4].upper()}"
        
        ticket = {
            "id": ticket_id,
            "ticket_number": ticket_number,
            "type": "rto_repair",
            "source": "rto",
            "tracking_id": tracking_id,
            "master_sku_id": final_master_sku_id,
            "master_sku_name": master_sku.get("name") if master_sku else None,
            "serial_number": serial_number or source_item.get("serial_number"),
            "customer_name": source_item.get("customer_name"),
            "customer_phone": source_item.get("phone"),
            "condition": condition,
            "status": "pending_repair",
            "notes": notes,
            "created_by": user["id"],
            "created_by_name": f"{user['first_name']} {user['last_name']}",
            "created_at": now.isoformat()
        }
        
        await db.tickets.insert_one(ticket)
        
        # Update incoming queue
        if incoming:
            await db.incoming_queue.update_one(
                {"tracking_id": tracking_id},
                {"$set": {
                    "status": "sent_to_repair",
                    "ticket_id": ticket_id,
                    "ticket_number": ticket_number,
                    "processed_at": now.isoformat()
                }}
            )
        
        return {
            "message": "Sent to repair technician",
            "action": "send_to_repair",
            "ticket_number": ticket_number,
            "ticket_id": ticket_id
        }
    
    elif action == "send_to_repair_yard":
        # Update status to repair yard
        if incoming:
            await db.incoming_queue.update_one(
                {"tracking_id": tracking_id},
                {"$set": {
                    "status": "repair_yard",
                    "location": "repair_yard",
                    "condition": condition,
                    "processed_at": now.isoformat(),
                    "processed_by": user["id"],
                    "notes": notes
                }}
            )
        
        return {
            "message": "Sent to repair yard",
            "action": "send_to_repair_yard",
            "tracking_id": tracking_id
        }
    
    elif action == "mark_dead_stock":
        # Create dead stock entry
        dead_stock_entry = {
            "id": str(uuid.uuid4()),
            "tracking_id": tracking_id,
            "master_sku_id": final_master_sku_id,
            "master_sku_name": master_sku.get("name") if master_sku else None,
            "serial_number": serial_number or source_item.get("serial_number"),
            "condition": condition,
            "reason": notes or "Marked as dead stock via RTO processing",
            "source": "rto",
            "created_by": user["id"],
            "created_by_name": f"{user['first_name']} {user['last_name']}",
            "created_at": now.isoformat()
        }
        
        await db.dead_stock.insert_one(dead_stock_entry)
        
        # Update incoming queue
        if incoming:
            await db.incoming_queue.update_one(
                {"tracking_id": tracking_id},
                {"$set": {
                    "status": "dead_stock",
                    "processed_action": "marked_dead_stock",
                    "processed_at": now.isoformat()
                }}
            )
        
        # Update serial status
        if serial_number:
            await db.finished_good_serials.update_one(
                {"serial_number": serial_number},
                {"$set": {"status": "dead_stock", "updated_at": now.isoformat()}}
            )
        
        return {
            "message": "Marked as dead stock",
            "action": "mark_dead_stock",
            "tracking_id": tracking_id
        }
    
    else:
        raise HTTPException(status_code=400, detail=f"Invalid action: {action}")


@api_router.get("/bot/serial-info/{serial_number}")
async def bot_serial_info(
    serial_number: str,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get comprehensive information about a serial number"""
    
    serial = await db.finished_good_serials.find_one(
        {"serial_number": {"$regex": f"^{serial_number}$", "$options": "i"}},
        {"_id": 0}
    )
    
    if not serial:
        return {
            "found": False,
            "serial_number": serial_number,
            "message": "Serial number not found in system"
        }
    
    # Get related information
    master_sku = None
    if serial.get("master_sku_id"):
        master_sku = await db.master_skus.find_one({"id": serial["master_sku_id"]}, {"_id": 0})
    
    # Get dispatch info
    dispatch = await db.dispatches.find_one({"serial_number": serial_number}, {"_id": 0})
    
    # Get warranty info
    warranty = await db.warranties.find_one({"serial_number": serial_number}, {"_id": 0})
    
    # Get repair tickets
    tickets = await db.tickets.find(
        {"$or": [{"serial_number": serial_number}, {"board_serial_number": serial_number}]},
        {"_id": 0}
    ).sort("created_at", -1).to_list(10)
    
    # Determine missing fields
    missing_fields = []
    if not serial.get("manufacturing_date"):
        missing_fields.append("manufacturing_date")
    if not serial.get("batch_number"):
        missing_fields.append("batch_number")
    if not serial.get("master_sku_id"):
        missing_fields.append("master_sku_id")
    if serial.get("status") == "sold" and not dispatch:
        missing_fields.append("dispatch_info")
    if serial.get("status") == "sold" and not warranty:
        missing_fields.append("warranty_info")
    
    return {
        "found": True,
        "serial_number": serial_number,
        "serial_data": serial,
        "master_sku": master_sku,
        "dispatch_info": dispatch,
        "warranty_info": warranty,
        "repair_history": tickets,
        "status": serial.get("status"),
        "missing_fields": missing_fields,
        "has_missing_data": len(missing_fields) > 0,
        "actions": ["update_serial_info"] if missing_fields else []
    }


@api_router.post("/bot/update-serial")
async def bot_update_serial(
    serial_number: str = Form(...),
    field: str = Form(...),
    value: str = Form(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Update a field on a serial number record"""
    
    serial = await db.finished_good_serials.find_one({"serial_number": serial_number})
    if not serial:
        raise HTTPException(status_code=404, detail="Serial number not found")
    
    allowed_fields = [
        "manufacturing_date", "batch_number", "master_sku_id", "firm_id",
        "condition", "notes", "customer_name", "customer_phone", "warranty_start", "warranty_end"
    ]
    
    if field not in allowed_fields:
        raise HTTPException(status_code=400, detail=f"Field '{field}' cannot be updated")
    
    update_data = {
        field: value,
        "updated_at": datetime.now(timezone.utc).isoformat(),
        "updated_by": user["id"]
    }
    
    # If updating master_sku_id, also get the name
    if field == "master_sku_id":
        sku = await db.master_skus.find_one({"id": value}, {"_id": 0})
        if sku:
            update_data["master_sku_name"] = sku.get("name")
            update_data["sku_code"] = sku.get("sku_code")
    
    await db.finished_good_serials.update_one(
        {"serial_number": serial_number},
        {"$set": update_data}
    )
    
    return {
        "message": f"Serial {serial_number} updated: {field} = {value}",
        "serial_number": serial_number,
        "field": field,
        "value": value
    }


@api_router.post("/bot/update-order-field")
async def bot_update_order_field_v2(
    order_id: str = Form(...),
    source: str = Form(...),  # amazon_orders, pending_fulfillment, dispatches
    field: str = Form(...),
    value: str = Form(...),
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Update a field on any order type"""
    
    collection_map = {
        "amazon_orders": db.amazon_orders,
        "pending_fulfillment": db.pending_fulfillment,
        "dispatches": db.dispatches
    }
    
    if source not in collection_map:
        raise HTTPException(status_code=400, detail=f"Invalid source: {source}")
    
    collection = collection_map[source]
    
    # Find the order
    id_field = "amazon_order_id" if source == "amazon_orders" else "id"
    order = await collection.find_one({id_field: order_id})
    
    if not order:
        # Try alternate ID fields
        order = await collection.find_one({"order_id": order_id})
    
    if not order:
        raise HTTPException(status_code=404, detail="Order not found")
    
    allowed_fields = [
        "customer_name", "customer_phone", "phone", "address", "city", "state", "pincode",
        "tracking_id", "courier", "master_sku_id", "serial_number", "invoice_value",
        "order_total", "amount", "payment_status", "notes"
    ]
    
    if field not in allowed_fields:
        raise HTTPException(status_code=400, detail=f"Field '{field}' cannot be updated")
    
    update_data = {
        field: value,
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    
    # If updating master_sku_id, also update related fields
    if field == "master_sku_id":
        sku = await db.master_skus.find_one({"id": value}, {"_id": 0})
        if sku:
            update_data["master_sku_name"] = sku.get("name")
            update_data["sku_code"] = sku.get("sku_code")
    
    await collection.update_one({id_field: order_id}, {"$set": update_data})
    
    return {
        "message": f"Order updated: {field} = {value}",
        "order_id": order_id,
        "source": source,
        "field": field,
        "value": value
    }


@api_router.get("/bot/master-skus")
async def bot_get_master_skus(
    search: Optional[str] = None,
    limit: int = 50,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Get list of master SKUs for selection"""
    
    query = {}
    if search:
        query = {
            "$or": [
                {"name": {"$regex": search, "$options": "i"}},
                {"sku_code": {"$regex": search, "$options": "i"}}
            ]
        }
    
    skus = await db.master_skus.find(query, {"_id": 0, "id": 1, "name": 1, "sku_code": 1, "hsn_code": 1, "gst_rate": 1}).limit(limit).to_list(limit)
    
    return {"skus": skus, "count": len(skus)}


@api_router.get("/bot/search-items")
async def bot_search_items(
    item_type: str,
    search: Optional[str] = None,
    limit: int = 50,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Search items by type for purchase/adjustment flow.
    item_type: 'raw_material' (from raw_materials), 'traded_item' (from master_skus non-manufactured)
    """
    
    query = {}
    if search:
        query = {
            "$or": [
                {"name": {"$regex": search, "$options": "i"}},
                {"sku_code": {"$regex": search, "$options": "i"}},
                {"code": {"$regex": search, "$options": "i"}},  # raw_materials use 'code' field
                {"model_name": {"$regex": search, "$options": "i"}}
            ]
        }
    
    items = []
    
    if item_type == "traded_item":
        # Bug 2 Fix: Search master_skus for traded/finished goods (non-manufactured)
        # These are products you BUY from suppliers (not manufacture yourself)
        sku_query = dict(query) if query else {}
        sku_query["$and"] = sku_query.get("$and", [])
        if "$or" in sku_query:
            sku_query["$and"].append({"$or": sku_query.pop("$or")})
        sku_query["$and"].append({
            "$or": [
                {"is_manufactured": {"$ne": True}},
                {"is_manufactured": {"$exists": False}},
                {"product_type": "traded"},
                {"product_type": {"$exists": False}}
            ]
        })
        # Remove empty $and
        if not sku_query["$and"]:
            del sku_query["$and"]
        
        skus = await db.master_skus.find(sku_query, {"_id": 0}).limit(limit).to_list(limit)
        items = [{
            "id": s["id"], 
            "name": s.get("name"), 
            "sku_code": s.get("sku_code"),
            "hsn_code": s.get("hsn_code"),
            "gst_rate": s.get("gst_rate", 18),
            "type": "master_sku"  # Use master_sku as type for inventory ledger
        } for s in skus]
        
        # Also check traded_items collection as fallback
        if len(items) == 0:
            traded = await db.traded_items.find(query, {"_id": 0}).limit(limit).to_list(limit)
            items = [{
                "id": t["id"], 
                "name": t.get("name"), 
                "sku_code": t.get("sku_code"),
                "hsn_code": t.get("hsn_code"),
                "gst_rate": t.get("gst_rate", 18),
                "type": "traded_item"
            } for t in traded]
        
    elif item_type == "raw_material":
        # Search raw_materials collection
        raw = await db.raw_materials.find(query, {"_id": 0}).limit(limit).to_list(limit)
        items = [{
            "id": r["id"], 
            "name": r.get("name"), 
            "sku_code": r.get("code") or r.get("sku_code"),
            "hsn_code": r.get("hsn_code"),
            "gst_rate": r.get("gst_rate", 18),
            "type": "raw_material"
        } for r in raw]
        
    elif item_type == "master_sku":
        # Search all master_skus (for other flows)
        skus = await db.master_skus.find(query, {"_id": 0}).limit(limit).to_list(limit)
        items = [{
            "id": s["id"], 
            "name": s.get("name"), 
            "sku_code": s.get("sku_code"),
            "hsn_code": s.get("hsn_code"),
            "gst_rate": s.get("gst_rate", 18),
            "type": "master_sku"
        } for s in skus]
    
    return {"items": items, "count": len(items)}


