# ===== PURCHASE ENTRY ENDPOINTS =====

@api_router.get("/bot/search-parties")
async def bot_search_parties(
    search: str,
    party_type: Optional[str] = None,  # supplier, customer, or None for all
    limit: int = 20,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Search parties (suppliers/customers) by name, phone, or GST number"""
    
    # Base search query - search by name, phone, or GST
    search_conditions = [
        {"name": {"$regex": search, "$options": "i"}},
        {"phone": {"$regex": search, "$options": "i"}},
        {"gst_number": {"$regex": search, "$options": "i"}},
        {"contact_name": {"$regex": search, "$options": "i"}}
    ]
    
    if party_type == "supplier":
        # Bug 1 Fix: For suppliers, check multiple possible formats
        # party_type='supplier', party_types contains 'supplier', or type='supplier'
        # Also include legacy data where party_type might be null but has supplier-like attributes
        query = {
            "$and": [
                {"$or": search_conditions},
                {"$or": [
                    {"party_type": "supplier"},
                    {"party_types": "supplier"},
                    {"type": "supplier"},
                    # Include parties that might be suppliers (have GST, are companies)
                    {"party_type": {"$exists": False}},
                    {"party_type": None}
                ]}
            ]
        }
    elif party_type == "customer":
        # For customers, include various formats:
        # - party_type=customer, party_types contains 'customer', party_type=dealer (dealers are also customers)
        # - Also include null/missing party_type for legacy data
        query = {
            "$and": [
                {"$or": search_conditions},
                {"$or": [
                    {"party_type": "customer"},
                    {"party_type": "dealer"},  # Dealers are customers
                    {"party_types": "customer"},
                    {"party_type": {"$exists": False}},
                    {"party_type": None}
                ]}
            ]
        }
    else:
        # No party_type filter - search all
        query = {"$or": search_conditions}
    
    parties = await db.parties.find(query, {"_id": 0}).limit(limit).to_list(limit)
    return {"parties": parties, "count": len(parties)}


class CreatePartyRequest(BaseModel):
    name: str
    party_type: str  # supplier or customer
    is_gst_registered: bool = False
    gst_number: Optional[str] = None
    state: Optional[str] = None
    contact_name: Optional[str] = None
    phone: Optional[str] = None
    email: Optional[str] = None
    address: Optional[str] = None
    city: Optional[str] = None
    pincode: Optional[str] = None


@api_router.post("/bot/create-party")
async def bot_create_party(
    data: CreatePartyRequest,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Create a new party (supplier or customer)"""
    
    now = datetime.now(timezone.utc)
    
    # Check if party with same name or GST already exists
    existing = await db.parties.find_one({
        "$or": [
            {"name": {"$regex": f"^{data.name}$", "$options": "i"}},
            {"gst_number": data.gst_number} if data.gst_number else {"name": "___never_match___"}
        ]
    })
    if existing:
        raise HTTPException(status_code=400, detail="Party with same name or GST number already exists")
    
    party_id = str(uuid.uuid4())
    party_doc = {
        "id": party_id,
        "name": data.name,
        "party_type": data.party_type,
        "is_gst_registered": data.is_gst_registered,
        "gst_number": data.gst_number,
        "state": data.state,
        "contact_name": data.contact_name,
        "phone": data.phone,
        "email": data.email,
        "address": data.address,
        "city": data.city,
        "pincode": data.pincode,
        "opening_balance": 0,
        "current_balance": 0,
        "is_active": True,
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat()
    }
    
    await db.parties.insert_one(party_doc)
    
    return {"message": "Party created successfully", "party": {k: v for k, v in party_doc.items() if k != "_id"}}


