@api_router.post("/bot/record-purchase")
async def bot_record_purchase(
    data: RecordPurchaseRequest,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Record a purchase entry and update inventory"""
    
    now = datetime.now(timezone.utc)
    
    # Bug 5 Fix: Check for duplicate invoice number from same supplier
    if data.invoice_number:
        existing_purchase = await db.purchase_register.find_one({
            "supplier_id": data.supplier_id,
            "invoice_number": data.invoice_number
        }, {"_id": 0, "purchase_number": 1})
        if existing_purchase:
            raise HTTPException(
                status_code=400, 
                detail=f"Invoice {data.invoice_number} already recorded for this supplier (Purchase #{existing_purchase.get('purchase_number')})"
            )
    
    # Get firm details
    firm = await db.firms.find_one({"id": data.firm_id}, {"_id": 0})
    if not firm:
        raise HTTPException(status_code=404, detail="Firm not found")
    
    # Get supplier details
    supplier = await db.parties.find_one({"id": data.supplier_id}, {"_id": 0})
    if not supplier:
        raise HTTPException(status_code=404, detail="Supplier not found")
    
    # Generate purchase number
    purchase_number = f"PUR-{now.strftime('%Y%m%d')}-{str(uuid.uuid4())[:4].upper()}"
    purchase_id = str(uuid.uuid4())
    
    # Create purchase register entry
    purchase_doc = {
        "id": purchase_id,
        "purchase_number": purchase_number,
        "firm_id": data.firm_id,
        "firm_name": firm.get("name"),
        "supplier_id": data.supplier_id,
        "supplier_name": supplier.get("name"),
        "supplier_gst": supplier.get("gst_number"),
        "invoice_number": data.invoice_number,
        "invoice_date": data.invoice_date,
        "items": [item.dict() for item in data.items],
        "subtotal": data.subtotal,
        "total_gst": data.total_gst,
        "grand_total": data.grand_total,
        "payment_status": data.payment_status,
        "amount_paid": data.amount_paid,
        "balance_due": data.balance_due,
        "payment_mode": data.payment_mode,
        "payment_reference": data.payment_reference,
        "notes": data.notes,
        "status": "recorded",
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat()
    }
    
    await db.purchase_register.insert_one(purchase_doc)
    
    # Update inventory for each item
    for item in data.items:
        # Get current stock
        current_stock = await get_current_stock(item.item_type, item.item_id, data.firm_id)
        new_balance = current_stock + item.quantity
        
        # Create inventory ledger entry
        ledger_entry = {
            "id": str(uuid.uuid4()),
            "entry_number": generate_ledger_entry_number(),
            "entry_type": "purchase",
            "item_type": item.item_type,
            "item_id": item.item_id,
            "item_name": item.name,
            "item_sku": item.sku_code,
            "firm_id": data.firm_id,
            "firm_name": firm.get("name"),
            "quantity": item.quantity,
            "running_balance": new_balance,
            "reference_type": "purchase",
            "reference_id": purchase_id,
            "reference_number": purchase_number,
            "unit_rate": item.unit_rate,
            "total_value": item.total,
            "notes": f"Purchase from {supplier.get('name')} - Inv: {data.invoice_number}",
            "created_by": user["id"],
            "created_by_name": f"{user['first_name']} {user['last_name']}",
            "created_at": now.isoformat()
        }
        
        await db.inventory_ledger.insert_one(ledger_entry)
    
    # Update party ledger if there's a balance due
    if data.balance_due > 0:
        party_ledger_entry = {
            "id": str(uuid.uuid4()),
            "party_id": data.supplier_id,
            "party_name": supplier.get("name"),
            "entry_type": "purchase",
            "reference_type": "purchase",
            "reference_id": purchase_id,
            "reference_number": purchase_number,
            "debit": data.grand_total,
            "credit": data.amount_paid,
            "balance": data.balance_due,
            "notes": f"Purchase - Inv: {data.invoice_number}",
            "created_by": user["id"],
            "created_at": now.isoformat()
        }
        await db.party_ledger.insert_one(party_ledger_entry)
        
        # Update party current balance
        await db.parties.update_one(
            {"id": data.supplier_id},
            {"$inc": {"current_balance": data.balance_due}}
        )
    
    return {
        "message": "Purchase recorded successfully",
        "purchase_number": purchase_number,
        "purchase_id": purchase_id,
        "supplier": supplier.get("name"),
        "total": data.grand_total,
        "stock_updated": len(data.items)
    }


class SpareDispatchCreate(BaseModel):
    ticket_id: str
    ticket_number: str
    master_sku_id: str
    customer_name: str
    customer_phone: str
    address: Optional[str] = None
    city: Optional[str] = None
    state: Optional[str] = None
    pincode: Optional[str] = None


@api_router.post("/bot/create-spare-dispatch")
async def bot_create_spare_dispatch(
    data: SpareDispatchCreate,
    user: dict = Depends(require_roles(["admin", "accountant"]))
):
    """Create a spare part dispatch entry linked to a ticket.
    This creates a pending_fulfillment entry that goes to the Dispatcher queue."""
    
    now = datetime.now(timezone.utc)
    
    # Get ticket info
    ticket = await db.tickets.find_one({"id": data.ticket_id}, {"_id": 0})
    if not ticket:
        raise HTTPException(status_code=404, detail="Ticket not found")
    
    # Get master SKU info
    master_sku = await db.master_skus.find_one({"id": data.master_sku_id}, {"_id": 0})
    if not master_sku:
        raise HTTPException(status_code=404, detail="Master SKU not found")
    
    # Get default firm
    firm = await db.firms.find_one({"is_active": True}, {"_id": 0})
    
    # Generate order ID for spare dispatch
    date_str = now.strftime("%Y%m%d")
    random_part = ''.join(random.choices(string.digits, k=5))
    order_id = f"SPARE-{date_str}-{random_part}"
    
    pf_id = str(uuid.uuid4())
    
    # Create pending_fulfillment entry
    pf_entry = {
        "id": pf_id,
        "type": "spare_dispatch",
        "order_id": order_id,
        "order_source": "ticket_spare",
        "ticket_id": data.ticket_id,
        "ticket_number": data.ticket_number,
        "status": "pending",  # Will go to dispatcher queue
        "customer_name": data.customer_name,
        "customer_phone": data.customer_phone,
        "address": data.address or ticket.get("address") or ticket.get("customer_address"),
        "city": data.city or ticket.get("city"),
        "state": data.state or ticket.get("state"),
        "pincode": data.pincode or ticket.get("pincode"),
        "master_sku_id": data.master_sku_id,
        "master_sku_name": master_sku.get("name"),
        "sku_code": master_sku.get("sku_code"),
        "quantity": 1,
        "firm_id": firm.get("id") if firm else None,
        "firm_name": firm.get("name") if firm else None,
        "is_manufactured_item": master_sku.get("is_manufactured", False) or master_sku.get("product_type") == "manufactured",
        "notes": f"Spare dispatch for ticket {data.ticket_number}",
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat(),
        "updated_at": now.isoformat()
    }
    
    await db.pending_fulfillment.insert_one(pf_entry)
    
    # Add note to ticket
    note_entry = {
        "id": str(uuid.uuid4()),
        "ticket_id": data.ticket_id,
        "note": f"Spare dispatch created: {master_sku.get('name')} (Order: {order_id})",
        "created_by": user["id"],
        "created_by_name": f"{user['first_name']} {user['last_name']}",
        "created_at": now.isoformat()
    }
    await db.ticket_notes.insert_one(note_entry)
    
    return {
        "message": "Spare dispatch created",
        "order_id": order_id,
        "pending_fulfillment_id": pf_id,
        "product": master_sku.get("name"),
        "customer": data.customer_name
    }


